                    {item.classTitle}
                  </h2>
                  <div className="flex items-center gap-1.5 text-on-surface-variant text-[0.75rem] font-semibold leading-[1rem] font-['Inter']">
                    <span className="material-symbols-outlined text-[16px]">calendar_today</span>
