              </div>

              {item.status === 'PAYMENT_PENDING' && (
                <div className="bg-surface-container-low/50 px-4 py-3 border-t border-outline-variant/30 flex justify-between items-center">
                  <span className="text-[0.75rem] font-semibold leading-[1rem] font-['Inter'] text-amber-600 flex items-center gap-1.5">
