          />
          <div className="absolute inset-0 bg-gradient-to-t from-black/70 via-black/20 to-transparent flex flex-col justify-end p-6 text-left">
            <span className="text-[#d8e2ff] font-bold text-xs tracking-widest uppercase mb-1 font-label">New Season</span>
            <h2 className="text-white font-headline text-2xl font-extrabold leading-tight">Pro Tango Shoes</h2>
            <p className="text-white/80 text-sm mt-1 font-body">Engineered for grace and precision.</p>
            <button className="mt-4 bg-[#1A73E8] text-white w-fit px-6 py-2 rounded-full text-xs font-bold font-headline active:scale-95 transition-transform">SHOP COLLECTION</button>
          </div>
        </div>
      </div>

      {/* 4. Product Grid */}
      <div className="mt-8 px-4 mb-10 text-left min-h-[400px]">
        <div className="flex items-center justify-between mb-4">
          <h3 className="font-headline text-lg font-bold text-[#2d3435]">
            {activeCategory === 'All' ? 'Group Favorites' : `${activeCategory}`}
          </h3>
          <span className="text-[10px] font-black text-gray-300 uppercase tracking-widest">{filteredProducts.length} Items</span>
        </div>

        {filteredProducts.length === 0 ? (
          <div className="flex flex-col items-center justify-center py-20 text-center opacity-30">
            <span className="material-symbols-outlined text-6xl mb-4">shopping_basket</span>
            <p className="text-xs font-black uppercase tracking-widest">No products found</p>
          </div>
        ) : (
          <div className="grid grid-cols-2 gap-4">
            {filteredProducts.map(product => (
              <div key={product.id} className="group cursor-pointer animate-in fade-in slide-in-from-bottom-2 duration-500">
                <div className="relative aspect-square rounded-xl bg-[#f2f4f4] overflow-hidden mb-3">
                  <img 
                    alt={product.name} 
                    className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-110" 
                    src={product.imageUrl} 
                  />
                  <button className="absolute top-3 right-3 w-8 h-8 bg-white/90 backdrop-blur rounded-full flex items-center justify-center text-[#2d3435] shadow-sm hover:text-red-500 transition-colors">
                    <span className="material-symbols-outlined text-lg">favorite</span>
                  </button>
                </div>
                <div className="px-1">
                  <p className="text-[10px] font-bold text-[#5c5f62] uppercase tracking-tighter font-label">{product.brand}</p>
                  <h4 className="text-sm font-semibold text-[#2d3435] font-body truncate">{product.name}</h4>
                  <div className="flex items-center justify-between mt-1">
                    <span className="text-sm font-bold text-[#2d3435] font-headline">
                      ${product.price.toLocaleString(undefined, { minimumFractionDigits: 2 })}
                    </span>
                    <button 
                      onClick={(e) => handleAddToCart(e, product)}
                      className={`p-1.5 rounded-lg transition-all ${
                        isAddingToCart === product.id ? 'bg-green-500 text-white' : 'bg-[#d8e2ff] text-[#004fa8] hover:bg-primary hover:text-white'
                      }`}
                    >
                      <span className="material-symbols-outlined text-lg leading-none">
                        {isAddingToCart === product.id ? 'check' : 'add_shopping_cart'}
                      </span>
                    </button>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* 5. Secondary Featured Bento Section (Visual Preservation) */}
      <div className="mt-4 px-4 pb-12">
        <div className="grid grid-cols-2 gap-4">
          <div className="bg-[#dde4e5] p-5 rounded-2xl flex flex-col justify-between h-40 text-left">
            <div>
              <h4 className="font-headline font-bold text-sm text-[#2d3435]">Weekly Deals</h4>
              <p className="text-xs text-[#596061] font-body mt-1">Up to 40% off biking gear</p>
            </div>
            <span className="material-symbols-outlined text-[#1A73E8] text-3xl">trending_down</span>
          </div>
          <div className="bg-[#d8e2ff] p-5 rounded-2xl flex flex-col justify-between h-40 text-left">
            <div>
              <h4 className="font-headline font-bold text-sm text-[#004fa8]">Group Pickup</h4>
              <p className="text-xs text-[#004fa8]/80 font-body mt-1">Free delivery at local studios</p>
            </div>
            <span className="material-symbols-outlined text-[#1A73E8] text-3xl">local_shipping</span>
          </div>
        </div>
      </div>

      {/* 6. Global Shop FAB (Consistent with WoC System) */}
      <button 
        onClick={() => setShowCreateModal(true)}
        className="fixed bottom-6 left-1/2 -translate-x-1/2 w-16 h-16 bg-primary text-white rounded-full shadow-2xl shadow-primary/40 flex items-center justify-center hover:scale-110 active:scale-95 transition-all z-50 group overflow-hidden"
      >
        <div className="absolute inset-0 bg-white/20 translate-y-full group-hover:translate-y-0 transition-transform duration-300" />
        <span className="material-symbols-outlined text-[32px] font-bold relative z-10">sell</span>
      </button>

      {/* Create Product Modal */}
      <AnimatePresence>
        {showCreateModal && (
          <CreateProduct 
            onClose={() => setShowCreateModal(false)}
            onSuccess={() => {
              // Option: Show success toast
            }}
          />
        )}
      </AnimatePresence>
    </main>
  );
}

'use client';

import React, { useState, useEffect } from 'react';
import { useAuth } from '@/components/providers/AuthProvider';
import { stayService } from '@/lib/firebase/stayService';
import { Stay } from '@/types/stay';
import CreateStay from '@/components/stay/CreateStay';
import { motion, AnimatePresence } from 'framer-motion';

export default function StayPage() {
  const { user } = useAuth();
  const [stays, setStays] = useState<Stay[]>([]);
  const [activeType, setActiveType] = useState('All');
  const [searchQuery, setSearchQuery] = useState('');
  const [showCreateModal, setShowCreateModal] = useState(false);
  const [selectedForCompare, setSelectedForCompare] = useState<string[]>([]);

  // 1. Subscribe to real-time stays
  useEffect(() => {
    const unsub = stayService.subscribeStays(
      activeType !== 'All' ? { type: activeType } : null,
      (data) => setStays(data)
    );
    return () => unsub();
  }, [activeType]);

  // 2. Local Filter for Search
  const filteredStays = stays.filter(s => 
    s.title.toLowerCase().includes(searchQuery.toLowerCase()) || 
    s.location.toLowerCase().includes(searchQuery.toLowerCase()) ||
    s.hostName.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const stayTypes = ['All', 'Couchsurfing', 'Dormitory', '1-Room', '2-Room', '3-Room', 'Pension'];

  const toggleCompare = (id: string) => {
    setSelectedForCompare(prev => 
      prev.includes(id) ? prev.filter(i => i !== id) : (prev.length < 2 ? [...prev, id] : [prev[1], id])
    );
  };

  // Bento Mapping Logic (Design Preservation)
  const featureStay = filteredStays[0];
  const secondaryStays = filteredStays.slice(1, 3);
  const wideStay = filteredStays[3];
  const otherStays = filteredStays.slice(4);

  return (
    <main className="max-w-7xl mx-auto px-4 pt-24 pb-8 space-y-8 bg-background min-h-screen relative">
      <style dangerouslySetInnerHTML={{ __html: `
        .no-scrollbar::-webkit-scrollbar { display: none; }
        .no-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }
        .material-symbols-outlined { font-variation-settings: 'FILL' 0, 'wght' 400, 'GRAD' 0, 'opsz' 24; }
      `}} />

      {/* Search & Filter Section */}
      <div className="space-y-6">
        <div className="relative max-w-2xl mx-auto">
          <div className="flex items-center bg-white rounded-full border border-[#acb3b4]/40 px-6 py-4 shadow-sm focus-within:ring-4 focus-within:ring-primary/5 transition-all">
            <span className="material-symbols-outlined text-[#757c7d] mr-4">search</span>
            <input 
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="bg-transparent border-none focus:ring-0 w-full font-body text-[#2d3435] placeholder:text-[#596061]" 
              placeholder="Search by location or hostname" 
              type="text" 
            />
            <button className="p-2 hover:bg-[#ebeeef] rounded-full text-primary transition-colors">
              <span className="material-symbols-outlined">tune</span>
            </button>
          </div>
        </div>

        <div className="flex overflow-x-auto gap-3 pb-2 no-scrollbar">
          {stayTypes.map(t => (
            <button 
              key={t}
              onClick={() => setActiveType(t)}
              className={`px-5 py-2.5 rounded-full font-label text-sm whitespace-nowrap transition-all ${
                activeType === t ? 'bg-primary text-white shadow-lg shadow-primary/20' : 'bg-white text-[#596061] border border-[#acb3b4]/40 hover:border-primary'
              }`}
            >
              {t}
            </button>
          ))}
        </div>

        {/* Global Floating Action Button for Hosting */}
        <button 
          onClick={() => setShowCreateModal(true)}
          className="fixed top-24 right-8 bg-primary text-white px-6 py-3 rounded-full font-black text-xs uppercase tracking-widest shadow-xl shadow-primary/30 flex items-center gap-2 hover:scale-110 active:scale-95 transition-all z-30"
        >
          <span className="material-symbols-outlined text-[18px]">add_home</span>
          Host a Stay
        </button>
      </div>

      {filteredStays.length === 0 ? (
        <div className="py-40 flex flex-col items-center justify-center text-center opacity-30">
          <span className="material-symbols-outlined text-6xl mb-4">home_work</span>
          <p className="text-sm font-black uppercase tracking-widest">No Stays Found in this area</p>
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-12 gap-6 pb-20">
          {/* 1. Feature Card (Main Listing) */}
          {featureStay && (
            <div className="md:col-span-8 group relative bg-white rounded-xl overflow-hidden border border-[#acb3b4]/30 hover:shadow-2xl transition-all duration-500 animate-in fade-in zoom-in-95">
              <div className="relative h-[400px]">
                <img className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-1000" alt={featureStay.title} src={featureStay.imageUrl} />
                <div className="absolute inset-0 bg-gradient-to-t from-black/70 via-transparent to-transparent"></div>
                <button className="absolute top-4 right-4 p-2 bg-white/20 backdrop-blur-md rounded-full text-white hover:bg-white hover:text-red-500 transition-all">
                  <span className="material-symbols-outlined" style={{ fontVariationSettings: "'FILL' 1" }}>favorite</span>
                </button>
                <div className="absolute bottom-6 left-6 text-white text-left">
                  <div className="flex items-center gap-2 mb-2">
                    {featureStay.isCommunityChoice && <span className="px-2 py-1 bg-primary text-white text-[10px] font-bold rounded uppercase">Group Choice</span>}
                    <span className="flex items-center gap-1 text-sm font-medium"><span className="material-symbols-outlined text-sm">location_on</span>{featureStay.location}</span>
                  </div>
                  <h2 className="text-3xl font-headline font-extrabold tracking-tight">{featureStay.title}</h2>
                </div>
              </div>
              <div className="p-6 flex justify-between items-end">
                <div className="flex items-center gap-4">
                  <img className="w-12 h-12 rounded-full border-2 border-primary object-cover" alt={featureStay.hostName} src={featureStay.hostPhoto || "https://lh3.googleusercontent.com/a/default-user"} />
                  <div className="text-left">
                    <p className="font-headline text-lg font-bold text-[#2d3435]">Hosted by {featureStay.hostName}</p>
                    <p className="text-sm text-[#596061]">{featureStay.hostRole} • ⭐ {featureStay.hostRating || 'New'}</p>
                  </div>
                </div>
                <div className="text-right">
                  <p className="text-2xl font-headline font-black text-primary">${featureStay.pricePerNight}<span className="text-sm font-normal text-[#596061]">/night</span></p>
                  <div className="mt-2 flex items-center gap-2">
                    <input checked={selectedForCompare.includes(featureStay.id)} onChange={() => toggleCompare(featureStay.id)} className="w-4 h-4 rounded border-[#acb3b4] text-primary focus:ring-primary" id={`compare-${featureStay.id}`} type="checkbox" />
                    <label className="text-xs font-bold text-[#596061] uppercase tracking-widest cursor-pointer" htmlFor={`compare-${featureStay.id}`}>Compare</label>
                  </div>
                </div>
              </div>
            </div>
          )}

          {/* 2. Secondary Cards */}
          <div className="md:col-span-4 flex flex-col gap-6 text-left">
            {secondaryStays.map(s => (
              <div key={s.id} className="bg-white rounded-xl overflow-hidden border border-[#acb3b4]/30 hover:shadow-xl transition-all cursor-pointer animate-in fade-in slide-in-from-right-4 duration-500">
                <div className="h-48 relative">
                  <img className="w-full h-full object-cover" alt={s.title} src={s.imageUrl} />
                  <div className="absolute top-3 left-3 bg-white/90 backdrop-blur-sm px-2 py-1 rounded text-[10px] font-bold text-primary shadow-sm uppercase tracking-tighter">{s.distance || 'Near event'}</div>
                </div>
                <div className="p-4">
                  <h3 className="font-headline font-bold text-lg mb-1 text-[#2d3435] truncate">{s.title}</h3>
                  <div className="flex items-center gap-2 mb-4">
                    <span className="material-symbols-outlined text-xs text-[#596061]">person</span>
                    <span className="text-xs text-[#596061] font-medium">{s.hostName}, {s.hostRole}</span>
                  </div>
                  <div className="flex justify-between items-center">
                    <p className="font-headline font-extrabold text-lg text-[#2d3435]">${s.pricePerNight}<span className="text-xs font-normal">/night</span></p>
                    <input checked={selectedForCompare.includes(s.id)} onChange={() => toggleCompare(s.id)} className="w-4 h-4 rounded border-[#acb3b4] text-primary focus:ring-primary" type="checkbox" />
                  </div>
                </div>
              </div>
            ))}
          </div>

          {/* 3. Wide Card */}
          {wideStay && (
            <div className="md:col-span-12 group bg-white rounded-xl overflow-hidden border border-[#acb3b4]/30 flex flex-col md:flex-row hover:shadow-xl transition-all text-left animate-in fade-in slide-in-from-bottom-8 duration-700">
              <div className="md:w-1/3 h-64 md:h-auto overflow-hidden">
                <img className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-700" alt={wideStay.title} src={wideStay.imageUrl} />
              </div>
              <div className="p-8 flex-1 flex flex-col justify-between">
                <div>
                  <div className="flex justify-between items-start mb-4">
                    <div>
                      {wideStay.isNewlyListed && <span className="text-primary font-bold text-[10px] uppercase tracking-widest block mb-1">Newly Listed</span>}
                      <h3 className="text-2xl font-headline font-extrabold text-[#2d3435]">{wideStay.title}</h3>
                    </div>
                    <span className="flex items-center gap-1 font-bold text-primary">
                      <span className="material-symbols-outlined text-sm" style={{ fontVariationSettings: "'FILL' 1" }}>star</span>
                      {wideStay.hostRating || 'New'}
                    </span>
                  </div>
                  <p className="text-[#596061] leading-relaxed mb-6 max-w-2xl line-clamp-3">{wideStay.description}</p>
                  <div className="flex flex-wrap gap-4">
                    {wideStay.amenities.map(a => (
                      <div key={a} className="flex items-center gap-1 bg-[#f2f4f4] px-3 py-1 rounded-full text-xs font-semibold text-[#596061] uppercase tracking-tighter">
                        <span className="material-symbols-outlined text-sm">{a}</span> {a}
                      </div>
                    ))}
                  </div>
                </div>
                <div className="flex justify-between items-center mt-8 pt-6 border-t border-[#acb3b4]/30">
                  <div className="flex items-center gap-3">
                    <img className="w-10 h-10 rounded-full object-cover" alt={wideStay.hostName} src={wideStay.hostPhoto || "https://lh3.googleusercontent.com/a/default-user"} />
                    <span className="text-sm font-bold text-[#2d3435]">Hosted by {wideStay.hostName}</span>
                  </div>
                  <div className="flex items-center gap-6">
                    <div className="text-right">
                      <p className="text-xl font-headline font-black text-primary">${wideStay.pricePerNight}<span className="text-sm font-normal text-[#596061]">/night</span></p>
                    </div>
                    <input checked={selectedForCompare.includes(wideStay.id)} onChange={() => toggleCompare(wideStay.id)} className="w-5 h-5 rounded border-[#acb3b4] text-primary focus:ring-primary" type="checkbox" />
                  </div>
                </div>
              </div>
            </div>
          )}

          {/* 4. Rest of Stays */}
          {otherStays.map(s => (
             <div key={s.id} className="md:col-span-4 bg-white rounded-xl overflow-hidden border border-[#acb3b4]/30 hover:shadow-xl transition-all cursor-pointer animate-in fade-in duration-500">
               <div className="h-48 relative">
                 <img className="w-full h-full object-cover" alt={s.title} src={s.imageUrl} />
               </div>
               <div className="p-4">
                 <h3 className="font-headline font-bold text-lg mb-1 text-[#2d3435] truncate">{s.title}</h3>
                 <p className="text-xs text-[#596061] mb-4 truncate">{s.location}</p>
                 <div className="flex justify-between items-center">
                   <p className="font-headline font-extrabold text-lg text-[#2d3435]">${s.pricePerNight}<span className="text-xs font-normal">/night</span></p>
                   <input checked={selectedForCompare.includes(s.id)} onChange={() => toggleCompare(s.id)} className="w-4 h-4 rounded border-[#acb3b4] text-primary focus:ring-primary" type="checkbox" />
                 </div>
               </div>
             </div>
          ))}
        </div>
      )}

      {/* Floating Interaction Bar: Compare Selection */}
      <AnimatePresence>
        {selectedForCompare.length > 0 && (
          <motion.div 
            initial={{ y: 100, x: '-50%', opacity: 0 }}
            animate={{ y: 0, x: '-50%', opacity: 1 }}
            exit={{ y: 100, x: '-50%', opacity: 0 }}
            className="fixed bottom-28 left-1/2 z-40 w-[max-content]"
          >
            <div className="bg-[#0c0f0f] text-[#9c9d9d] px-8 py-4 rounded-full shadow-2xl flex items-center gap-10 border border-white/10 backdrop-blur-xl bg-opacity-90">
              <div className="flex items-center gap-4">
                <div className="flex -space-x-3">
                  {selectedForCompare.map(id => (
                    <div key={id} className="w-10 h-10 rounded-full border-2 border-[#0c0f0f] overflow-hidden bg-[#d8e2ff] animate-in zoom-in">
                      <img className="w-full h-full object-cover" alt="selected" src={stays.find(s => s.id === id)?.imageUrl} />
                    </div>
                  ))}
                  {selectedForCompare.length < 2 && (
                    <div className="w-10 h-10 rounded-full border-2 border-[#0c0f0f] overflow-hidden bg-[#d8e2ff] flex items-center justify-center">
                      <span className="material-symbols-outlined text-[#9c9d9d] opacity-40">add</span>
                    </div>
                  )}
                </div>
                <p className="font-label text-sm font-bold">{selectedForCompare.length} item{selectedForCompare.length > 1 ? 's' : ''} selected for <span className="text-[#c2d4ff]">Comparison</span></p>
              </div>
              <div className="h-6 w-px bg-white/20"></div>
              <button className="bg-primary text-white px-6 py-2 rounded-full font-label text-sm font-bold hover:scale-105 active:scale-95 transition-all">
                Compare Now
              </button>
              <button 
                onClick={() => setSelectedForCompare([])}
                className="text-[#9c9d9d]/60 hover:text-white transition-colors"
              >
                <span className="material-symbols-outlined">close</span>
              </button>
            </div>
          </motion.div>
        )}
      </AnimatePresence>

      {/* Create Stay Modal */}
      <AnimatePresence>
        {showCreateModal && (
          <CreateStay onClose={() => setShowCreateModal(false)} />
        )}
      </AnimatePresence>
    </main>
  );
}

'use client';

import React, { useState, useEffect, useRef } from 'react';
import ChatRoom from '@/components/chat/ChatRoom';
import { useAuth } from '@/components/providers/AuthProvider';
import { chatService } from '@/lib/firebase/chatService';
import { ChatRoom as ChatRoomType } from '@/types/chat';
import { formatDistanceToNow } from 'date-fns';
import { collection, query, where, getDocs, doc, getDoc, addDoc, serverTimestamp } from 'firebase/firestore';
import { db } from '@/lib/firebase/clientApp';
import Script from 'next/script';

export default function ChatPage() {
  const { user, loading: authLoading } = useAuth();
  const [selectedRoomId, setSelectedRoomId] = useState<string | null>(null);
  const [rooms, setRooms] = useState<ChatRoomType[]>([]);
  const [privateUserNames, setPrivateUserNames] = useState<Record<string, string>>({});
  const [privateUserImages, setPrivateUserImages] = useState<Record<string, string>>({});
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState<'Personal' | 'Groups'>('Personal');
  const [searchQuery, setSearchQuery] = useState('');

  const [isNewChatOpen, setIsNewChatOpen] = useState(false);
  const [newChatSearchQuery, setNewChatSearchQuery] = useState('');
  const [selectedNewChatUsers, setSelectedNewChatUsers] = useState<any[]>([]);
  const [allUsers, setAllUsers] = useState<any[]>([]);
  const [groupChatName, setGroupChatName] = useState('');

  useEffect(() => {
    if (isNewChatOpen && allUsers.length === 0) {
      const fetchUsers = async () => {
        try {
          const q = query(collection(db, 'users'));
          const snapshot = await getDocs(q);
          const usersList = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() }));
          setAllUsers(usersList.filter(u => u.id !== user?.uid));
        } catch (error) {
          console.error("Error fetching users:", error);
        }
      };
      fetchUsers();
    }
  }, [isNewChatOpen, user]);

  const filteredNewChatUsers = allUsers.filter(u => {
    const query = newChatSearchQuery.toLowerCase().replace(/-/g, '').replace(/^0/, '+82'); // Normalize query phone to +82 if it starts with 0
    const queryNoDash = newChatSearchQuery.toLowerCase().replace(/-/g, '');

    const nickname = (u.nickname || '').toLowerCase();
    const nativeNickname = (u.nativeNickname || '').toLowerCase();
    const displayName = (u.displayName || '').toLowerCase();
    const phoneNumber = (u.phoneNumber || '').toLowerCase().replace(/-/g, '');
    const phoneNumberLocal = phoneNumber.replace(/^\+82/, '0'); // Convert +82 to 0 for local match

    return nickname.includes(queryNoDash) || 
           nativeNickname.includes(queryNoDash) || 
           displayName.includes(queryNoDash) ||
           phoneNumber.includes(queryNoDash) || 
           phoneNumberLocal.includes(queryNoDash);
  });

  const toggleUserSelection = (u: any) => {
    if (selectedNewChatUsers.find(su => su.id === u.id)) {
      setSelectedNewChatUsers(selectedNewChatUsers.filter(su => su.id !== u.id));
    } else {
      setSelectedNewChatUsers([...selectedNewChatUsers, u]);
    }
  };

  const handleStartChat = async () => {
    if (selectedNewChatUsers.length === 0 || !user) return;

    try {
      if (selectedNewChatUsers.length === 1) {
        const roomId = await chatService.getOrCreatePrivateRoom(
          [user.uid, selectedNewChatUsers[0].id],
          user.uid
        );
        setSelectedRoomId(roomId);
        setIsNewChatOpen(false);
        setSelectedNewChatUsers([]);
        setGroupChatName('');
      } else {
        const docRef = await addDoc(collection(db, 'chat_rooms'), {
          type: 'group',
          name: groupChatName || 'New Group Chat',
          participants: [user.uid, ...selectedNewChatUsers.map(u => u.id)],
          createdBy: user.uid,
          createdAt: serverTimestamp(),
          lastMessageTime: serverTimestamp(),
          lastMessage: '대화가 시작되었습니다.',
          unreadCounts: {}
        });
        setSelectedRoomId(docRef.id);
        setIsNewChatOpen(false);
        setSelectedNewChatUsers([]);
        setGroupChatName('');
      }
    } catch (error) {
      console.error("Failed to create chat:", error);
    }
  };

  const [contextMenu, setContextMenu] = useState<{
    roomId: string;
    x: number;
    y: number;
    isPinned: boolean;
  } | null>(null);
  const longPressTimer = useRef<NodeJS.Timeout | null>(null);

  const handleContextMenu = (e: React.MouseEvent, room: ChatRoomType) => {
    e.preventDefault();
    if (!user) return;
    const isPinned = room.pinnedBy?.includes(user.uid) || false;
    setContextMenu({
      roomId: room.id,
      x: e.clientX,
      y: e.clientY,
      isPinned
    });
  };

  const handleTouchStart = (e: React.TouchEvent, room: ChatRoomType) => {
    if (!user) return;
    const touch = e.touches[0];
    const x = touch.clientX;
    const y = touch.clientY;

    if (longPressTimer.current) clearTimeout(longPressTimer.current);

    longPressTimer.current = setTimeout(() => {
      const isPinned = room.pinnedBy?.includes(user.uid) || false;
      setContextMenu({
        roomId: room.id,
        x,
        y,
        isPinned
      });
    }, 500);
  };

  const handleTouchEnd = () => {
    if (longPressTimer.current) clearTimeout(longPressTimer.current);
  };

  const handlePin = async () => {
    if (!contextMenu || !user) return;
    try {
      await chatService.pinRoom(contextMenu.roomId, user.uid, !contextMenu.isPinned);
    } catch (error) {
      console.error("Failed to pin room", error);
    }
    setContextMenu(null);
  };

  const handleNudge = async () => {
    if (!contextMenu || !user) return;
    try {
      await chatService.nudgeRoom(contextMenu.roomId, user.uid, user.displayName || 'Someone');
    } catch (error) {
      console.error("Failed to nudge room", error);
    }
    setContextMenu(null);
  };

  const handleLeave = async () => {
    if (!contextMenu || !user) return;
    try {
      if (confirm("Are you sure you want to leave this chat?")) {
        await chatService.leaveRoom(contextMenu.roomId, user.uid);
      }
    } catch (error) {
      console.error("Failed to leave room", error);
    }
    setContextMenu(null);
  };

  useEffect(() => {
    if (!user) return;

    chatService.initializeSystemRooms();
    const unsub = chatService.subscribeRooms(user.uid, async (updatedRooms) => {
      setRooms(updatedRooms);

      // Fetch user data for private rooms
      const newNames: Record<string, string> = {};
      const newImages: Record<string, string> = {};

      for (const room of updatedRooms) {
        if (room.type === 'private') {
          const otherUserId = room.participants.find(p => p !== user.uid);
          if (otherUserId && !privateUserNames[otherUserId]) {
            try {
              const userDoc = await getDoc(doc(db, 'users', otherUserId));
              if (userDoc.exists()) {
                const userData = userDoc.data();
                newNames[otherUserId] = userData.nickname || userData.nativeNickname || userData.displayName || 'Unknown';
                if (userData.photoURL) {
                  newImages[otherUserId] = userData.photoURL;
                }
              }
            } catch (err) {
              console.error("Failed to fetch user data for private room", err);
            }
          }
        }
      }

      if (Object.keys(newNames).length > 0) {
        setPrivateUserNames(prev => ({ ...prev, ...newNames }));
      }
      if (Object.keys(newImages).length > 0) {
        setPrivateUserImages(prev => ({ ...prev, ...newImages }));
      }

      setLoading(false);
    });

    return () => unsub();
  }, [user]);

  // Auth 로딩 중: 스켈레톤 표시
  if (authLoading) {
    return (
      <div className="w-full flex flex-col items-center">
        <div className="w-full max-w-[896px] pt-4 pb-6 px-4 flex flex-col gap-4">
          <div className="h-12 bg-surface-container rounded-xl animate-pulse" />
          <div className="h-12 bg-surface-container-low rounded-xl animate-pulse" />
          {[1,2,3,4].map(i => (
            <div key={i} className="flex items-center gap-4 p-4 bg-surface-container-lowest rounded-xl">
              <div className="w-14 h-14 rounded-full bg-surface-container animate-pulse shrink-0" />
              <div className="flex-1 flex flex-col gap-2">
                <div className="h-4 bg-surface-container rounded animate-pulse w-1/2" />
                <div className="h-3 bg-surface-container-low rounded animate-pulse w-3/4" />
              </div>
            </div>
          ))}
        </div>
      </div>
    );
  }

  if (selectedRoomId) {
    return (
      <div className="fixed inset-0 z-[9999] bg-white flex flex-col">
        <ChatRoom
          roomId={selectedRoomId}
          onBack={() => setSelectedRoomId(null)}
        />
      </div>
    );
  }

  // Filter based on Tab
  const tabFilteredRooms = rooms.filter(room => {
    if (activeTab === 'Personal') {
      return room.type === 'private';
    } else {
      return room.type !== 'private';
    }
  });

  // Then filter based on search
  const filteredRooms = tabFilteredRooms.filter(room => {
    let nameToMatch = room.name || 'Unknown';
    if (room.type === 'private') {
      const otherUserId = room.participants.find(p => p !== user?.uid);
      if (otherUserId && privateUserNames[otherUserId]) {
        nameToMatch = privateUserNames[otherUserId];
      }
    }
    return nameToMatch.toLowerCase().includes(searchQuery.toLowerCase());
  });

  const pinnedRooms = filteredRooms.filter(r => user && r.pinnedBy?.includes(user.uid));
  const recentRooms = filteredRooms.filter(r => !(user && r.pinnedBy?.includes(user.uid)));

  return (
    <>
      <div className="w-full flex flex-col items-center relative">
        {/* Main Content Canvas */}
        <div className="w-full max-w-[896px] pt-4 pb-6 px-4 flex flex-col gap-element-gap relative">

          {/* Header & Tabs */}
          <div className="flex flex-col gap-6 mb-2">
            {/* Segmented Control for Tabs */}
            <div className="flex p-1 bg-surface-container rounded-xl w-full">
              <button
                onClick={() => setActiveTab('Personal')}
                className={`flex-1 py-2 px-4 rounded-lg flex items-center justify-center gap-2 transition-all font-[Plus_Jakarta_Sans] text-[1.125rem] leading-[1.5rem] font-bold ${activeTab === 'Personal' ? 'bg-surface-container-lowest shadow-sm text-primary' : 'text-on-surface-variant hover:text-on-surface'}`}
              >
                <span className="material-symbols-outlined text-[20px]" data-icon="person">person</span>
                Personal
              </button>
              <button
                onClick={() => setActiveTab('Groups')}
                className={`flex-1 py-2 px-4 rounded-lg flex items-center justify-center gap-2 transition-all font-[Plus_Jakarta_Sans] text-[1.125rem] leading-[1.5rem] font-bold ${activeTab === 'Groups' ? 'bg-surface-container-lowest shadow-sm text-primary' : 'text-on-surface-variant hover:text-on-surface'}`}
              >
                <span className="material-symbols-outlined text-[20px]" data-icon="diversity_3">diversity_3</span>
                Groups
              </button>
            </div>

            {/* 통합형 검색바 - HTML 원본 1:1 */}
            <div className="mt-4 relative flex items-center">
              <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                <span className="material-symbols-outlined text-outline text-[20px]" data-icon="search">search</span>
              </div>
              <input
                className="block w-full pl-10 pr-12 py-3 bg-surface-container-low border-none rounded-xl text-[0.875rem] leading-[1.25rem] font-medium placeholder-on-surface-variant focus:ring-2 focus:ring-primary/20"
                placeholder="Search messages or people..."
                type="text"
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
              />
              <button
                onClick={() => setIsNewChatOpen(true)}
                className="absolute right-2 w-9 h-9 rounded-lg bg-primary text-on-primary flex items-center justify-center hover:bg-primary/90 transition-colors shadow-sm focus:outline-none focus:ring-2 focus:ring-primary focus:ring-offset-2"
              >
                <span className="material-symbols-outlined text-[20px]" data-icon="add">add</span>
              </button>
            </div>
          </div>

          {loading ? (
            <div className="flex-1 flex flex-col gap-4 py-6 animate-pulse">
              {[1, 2, 3].map(i => (
                <div key={i} className="flex gap-4 items-center">
                  <div className="w-14 h-14 rounded-full bg-gray-200" />
                  <div className="flex-1 space-y-2">
                    <div className="h-4 bg-gray-200 rounded w-1/3" />
                    <div className="h-3 bg-gray-200 rounded w-2/3" />
                  </div>
                </div>
              ))}
            </div>
          ) : (
            <>
              {/* Pinned Content */}
              {pinnedRooms.length > 0 && (
                <section className="flex flex-col gap-3">
                  <h2 className="text-[0.75rem] leading-[1rem] font-semibold font-[Inter] text-outline uppercase tracking-wider pl-2 mt-2">Pinned</h2>

                  {pinnedRooms.map((room, index) => {
                    const lastTime = room.lastMessageTime?.toDate
                      ? formatDistanceToNow(room.lastMessageTime.toDate(), { addSuffix: true })
                      : 'Just now';
                    const unreadCount = user && room.unreadCounts ? (room.unreadCounts[user.uid] || 0) : 0;

                    let displayImage = room.imageUrl;
                    let displayName = room.name || 'Unknown';

                    if (room.type === 'private') {
                      const otherUserId = room.participants.find(p => p !== user?.uid);
                      if (otherUserId) {
                        if (privateUserNames[otherUserId]) displayName = privateUserNames[otherUserId];
                        if (privateUserImages[otherUserId]) displayImage = privateUserImages[otherUserId];
                      }
                    }

                    const colors = [
                      'bg-secondary-container text-on-secondary-container',
                      'bg-tertiary-container text-on-tertiary-container',
                      'bg-primary-container text-on-primary-container'
                    ];
                    const colorClass = colors[index % colors.length];

                    return (
                      <article
                        key={room.id}
                        onClick={() => setSelectedRoomId(room.id)}
                        onContextMenu={(e) => handleContextMenu(e, room)}
                        onTouchStart={(e) => handleTouchStart(e, room)}
                        onTouchEnd={handleTouchEnd}
                        onTouchMove={handleTouchEnd}
                        className="flex items-center gap-4 p-4 bg-surface-container-lowest rounded-xl shadow-sm hover:shadow-md transition-shadow outline outline-1 outline-transparent hover:outline-outline-variant cursor-pointer group"
                      >
                        <div className={`w-14 h-14 rounded-full ${colorClass} bg-slate-100 flex items-center justify-center shrink-0 overflow-hidden relative`}>
                          {displayImage ? (
                            <img src={displayImage} alt={displayName} className="w-full h-full object-cover" />
                          ) : (
                            <span className="material-symbols-outlined text-[32px]" data-icon="account_circle">account_circle</span>
                          )}
                        </div>
                        <div className="flex-1 min-w-0">
                          <div className="flex justify-between items-baseline mb-1">
                            <h3 className="font-[Plus_Jakarta_Sans] text-[1.125rem] leading-[1.5rem] font-bold text-on-surface truncate">{displayName}</h3>
                            <span className="font-[Inter] text-[0.75rem] leading-[1rem] font-bold text-primary shrink-0 ml-2">{lastTime}</span>
                          </div>
                          <p className="font-[Inter] text-[0.875rem] leading-[1.25rem] font-medium text-on-surface truncate">
                            {room.lastMessage || 'No recent message'}
                          </p>
                        </div>
                        {unreadCount > 0 && (
                          <div className="w-5 h-5 bg-primary text-on-primary rounded-full flex items-center justify-center text-[10px] font-bold shrink-0">
                            {unreadCount}
                          </div>
                        )}
                      </article>
                    );
                  })}
                </section>
              )}

              {/* Recent Messages Content */}
              {recentRooms.length > 0 && (
                <section className="flex flex-col gap-3 mt-2">
                  <h2 className="text-[0.75rem] leading-[1rem] font-semibold font-[Inter] text-outline uppercase tracking-wider pl-2 mt-2">Recent Messages</h2>

                  {recentRooms.map((room, index) => {
                    const lastTime = room.lastMessageTime?.toDate
                      ? formatDistanceToNow(room.lastMessageTime.toDate(), { addSuffix: true })
                      : 'Just now';
                    const unreadCount = user && room.unreadCounts ? (room.unreadCounts[user.uid] || 0) : 0;

                    let displayImage = room.imageUrl;
                    let displayName = room.name || 'Unknown';

                    if (room.type === 'private') {
                      const otherUserId = room.participants.find(p => p !== user?.uid);
                      if (otherUserId) {
                        if (privateUserNames[otherUserId]) displayName = privateUserNames[otherUserId];
                        if (privateUserImages[otherUserId]) displayImage = privateUserImages[otherUserId];
                      }
                    }

                    const colors = [
                      'bg-secondary-container text-on-secondary-container',
                      'bg-tertiary-container text-on-tertiary-container',
                      'bg-primary-container text-on-primary-container'
                    ];
                    const colorClass = colors[(index + (pinnedRooms.length || 0)) % colors.length];

                    return (
                      <article
                        key={room.id}
                        onClick={() => setSelectedRoomId(room.id)}
                        onContextMenu={(e) => handleContextMenu(e, room)}
                        onTouchStart={(e) => handleTouchStart(e, room)}
                        onTouchEnd={handleTouchEnd}
                        onTouchMove={handleTouchEnd}
                        className="flex items-center gap-4 p-4 bg-surface-container-lowest rounded-xl shadow-sm hover:shadow-md transition-shadow outline outline-1 outline-transparent hover:outline-outline-variant cursor-pointer group"
                      >
                        <div className={`w-14 h-14 rounded-full ${colorClass} bg-slate-100 flex items-center justify-center shrink-0 overflow-hidden relative`}>
                          {displayImage ? (
                            <img src={displayImage} alt={displayName} className="w-full h-full object-cover" />
                          ) : (
                            <span className="material-symbols-outlined text-[32px]" data-icon="account_circle">account_circle</span>
                          )}
                        </div>
                        <div className="flex-1 min-w-0">
                          <div className="flex justify-between items-baseline mb-1">
                            <h3 className="font-[Plus_Jakarta_Sans] text-[1.125rem] leading-[1.5rem] font-bold text-on-surface truncate">{displayName}</h3>
                            <span className="font-[Inter] text-[0.75rem] leading-[1rem] font-medium text-outline shrink-0 ml-2">{lastTime}</span>
                          </div>
                          <p className="font-[Inter] text-[0.875rem] leading-[1.25rem] font-medium text-on-surface-variant truncate">
                            {room.lastMessage || 'No recent message'}
                          </p>
                        </div>
                        {unreadCount > 0 && (
                          <div className="w-5 h-5 bg-primary text-on-primary rounded-full flex items-center justify-center text-[10px] font-bold shrink-0">
                            {unreadCount}
                          </div>
                        )}
                      </article>
                    );
                  })}
                </section>
              )}
            </>
          )}

        </div>
      </div>

        {/* ===== NEW CHAT MODAL - HTML 1:1 ===== */}
        {isNewChatOpen && (
          <>
            {/* Scrim */}
            <div
              className="fixed inset-0 bg-inverse-surface/40 backdrop-blur-sm z-40"
              onClick={() => setIsNewChatOpen(false)}
            />
            {/* Bottom Sheet */}
            <div className="fixed inset-x-0 bottom-0 sm:inset-0 flex flex-col items-end sm:items-center sm:justify-center z-50 p-0 sm:p-6">
              <div className="w-full max-w-[896px] bg-surface-container-lowest rounded-t-[32px] sm:rounded-[32px] shadow-[0_-8px_30px_rgba(0,0,0,0.15)] flex flex-col h-[85vh] overflow-hidden relative pb-12 sm:pb-0">

                {/* Grab Handle (Mobile) */}
                <div className="w-full flex justify-center pt-3 pb-1 sm:hidden">
                  <div className="w-12 h-1.5 bg-outline-variant rounded-full" />
                </div>

                {/* Header */}
                <header className="px-6 pt-4 pb-2 flex items-center justify-between">
                  <h2 className="font-[Plus_Jakarta_Sans] text-[1.5rem] leading-[2rem] font-extrabold tracking-tight text-on-surface">Start New Chat</h2>
                  <button
                    onClick={() => setIsNewChatOpen(false)}
                    className="p-2 rounded-full hover:bg-surface-container-low transition-colors text-on-surface-variant"
                  >
                    <span className="material-symbols-outlined">close</span>
                  </button>
                </header>

                {/* Search Bar */}
                <div className="px-6 py-2">
                  <div className="relative flex items-center w-full bg-surface-container-low rounded-xl border border-outline-variant focus-within:border-primary focus-within:ring-1 focus-within:ring-primary transition-all">
                    <span className="material-symbols-outlined text-outline ml-4">search</span>
                    <input
                      className="w-full bg-transparent border-none text-on-surface font-[Inter] text-[0.875rem] leading-[1.25rem] font-medium py-3 px-3 focus:ring-0 placeholder:text-outline"
                      placeholder="Search users by name..."
                      type="text"
                      value={newChatSearchQuery}
                      onChange={(e) => setNewChatSearchQuery(e.target.value)}
                    />
                  </div>
                </div>

                {/* Selected Users Chips */}
                {selectedNewChatUsers.length > 0 && (
                  <div className="px-6 py-3 flex overflow-x-auto gap-2 border-b border-surface-container-high">
                    {selectedNewChatUsers.map(su => (
                      <div key={su.id} className="flex items-center gap-2 bg-surface-container-high pl-1 pr-2 py-1 rounded-full shrink-0 border border-transparent">
                        {su.photoURL ? (
                          <img src={su.photoURL} alt={su.nickname || su.nativeNickname || 'User'} className="w-6 h-6 rounded-full object-cover" />
                        ) : (
                          <div className="w-6 h-6 rounded-full bg-secondary text-on-secondary flex items-center justify-center font-[Inter] text-[10px] font-bold">
                            {(su.nickname || su.nativeNickname || 'U')[0].toUpperCase()}
                          </div>
                        )}
                        <span className="font-[Inter] text-[0.75rem] leading-[1rem] font-semibold text-on-surface">{su.nickname || su.nativeNickname}</span>
                        <button
                          onClick={(e) => { e.preventDefault(); toggleUserSelection(su); }}
                          className="text-outline hover:text-error transition-colors flex items-center justify-center"
                        >
                          <span className="material-symbols-outlined text-[16px]">cancel</span>
                        </button>
                      </div>
                    ))}
                  </div>
                )}

                {/* Contact List */}
                <div className="flex-1 overflow-y-auto px-6 py-2 flex flex-col gap-1">
                  {filteredNewChatUsers.map(u => {
                    const isSelected = !!selectedNewChatUsers.find(su => su.id === u.id);
                    const displayName = u.nickname || u.nativeNickname || 'Unknown';
                    return (
                      <label
                        key={u.id}
                        className={`flex items-center gap-4 p-3 rounded-xl transition-colors cursor-pointer border border-transparent hover:border-outline-variant ${
                          isSelected
                            ? 'bg-surface-container-low hover:bg-surface-container'
                            : 'hover:bg-surface-container'
                        }`}
                      >
                        {/* Checkbox */}
                        <div className="relative flex items-center justify-center w-5 h-5 shrink-0">
                          <input
                            type="checkbox"
                            checked={isSelected}
                            onChange={() => toggleUserSelection(u)}
                            className="peer appearance-none w-5 h-5 rounded border border-outline checked:bg-primary checked:border-primary transition-all focus:ring-primary focus:ring-offset-surface-container-lowest"
                          />
                          <span className="material-symbols-outlined absolute text-on-primary text-[16px] pointer-events-none opacity-0 peer-checked:opacity-100" style={{fontVariationSettings: "'FILL' 1"}}>check</span>
                        </div>
                        {/* Avatar */}
                        <div className="w-10 h-10 rounded-full bg-secondary-container text-on-secondary-container flex items-center justify-center overflow-hidden shrink-0 border border-surface-dim">
                          {u.photoURL ? (
                            <img src={u.photoURL} alt={displayName} className="w-full h-full object-cover" />
                          ) : (
                            <span className="font-[Plus_Jakarta_Sans] text-[1.125rem] font-bold">{displayName[0].toUpperCase()}</span>
                          )}
                        </div>
                        {/* Info */}
                        <div className="flex-1 min-w-0 flex flex-col">
                          <div className="flex items-center gap-2">
                            <span className="font-[Plus_Jakarta_Sans] text-[1.125rem] leading-[1.5rem] font-bold text-on-surface truncate">{displayName}</span>
                            {u.nativeNickname && u.nickname && (
                              <span className="font-[Inter] text-[10px] font-bold bg-surface-dim text-on-surface-variant px-1.5 py-0.5 rounded uppercase shrink-0">{u.nativeNickname}</span>
                            )}
                          </div>
                          <span className="font-[Inter] text-[0.875rem] leading-[1.25rem] font-medium text-on-surface-variant truncate">
                            {u.phoneNumber ? u.phoneNumber.replace(new RegExp('^(.{3})(.{4})(.+)$'), '$1-****-$3').replace('+82', '0') : 'Member'}
                          </span>
                        </div>
                      </label>
                    );
                  })}
                </div>

                {/* Footer Action */}
                <div className="px-6 py-4 border-t border-surface-container-high bg-surface-container-lowest">
                  {/* Chat Name Input - groups only */}
                  {selectedNewChatUsers.length > 1 && (
                    <div className="mb-4">
                      <div className="relative flex items-center w-full bg-surface-container-low rounded-xl border border-outline-variant focus-within:border-primary-container focus-within:ring-1 focus-within:ring-primary-container transition-all">
                        <input
                          className="w-full bg-transparent border-none text-on-surface font-[Inter] text-[0.875rem] py-3 px-4 focus:ring-0 placeholder:text-outline"
                          placeholder="Chat name (Optional)"
                          type="text"
                          value={groupChatName}
                          onChange={(e) => setGroupChatName(e.target.value)}
                        />
                      </div>
                    </div>
                  )}
                  <button
                    onClick={handleStartChat}
