              onClick={(e) => e.stopPropagation()}
            >
              <button onClick={handlePin} className="w-full text-left px-4 py-3 hover:bg-surface-container font-body-md text-on-surface flex items-center gap-3 transition-colors">
                <span className="material-symbols-outlined text-[20px]" data-icon={contextMenu.isPinned ? "keep_off" : "push_pin"}>{contextMenu.isPinned ? 'keep_off' : 'push_pin'}</span>
