'use client';

import React, { useState, useEffect, useMemo } from 'react';
import { useAuth } from '@/components/providers/AuthProvider';
import { eventService } from '@/lib/firebase/eventService';
import { Event } from '@/types/event';
import { format, isSameDay, startOfDay, addDays, getDay, startOfWeek, endOfWeek, eachDayOfInterval, differenceInCalendarDays, endOfDay, startOfMonth, endOfMonth } from 'date-fns';
import CreateEvent from '@/components/events/CreateEvent';
import EventDetail from '@/components/events/EventDetail';
import { motion, AnimatePresence } from 'framer-motion';
import { useLocation } from '@/components/providers/LocationProvider';
import { useNavigation } from '@/components/providers/NavigationProvider';

// Helper to safely convert Firestore timestamp or other date formats and strip time
const getNormalizedDate = (val: any): Date => {
  if (!val) return startOfDay(new Date());
  let date: Date;
  if (typeof val.toDate === 'function') date = val.toDate();
  else if (val instanceof Date) date = val;
  else {
    try { date = new Date(val); } catch (e) { date = new Date(); }
  }
  return startOfDay(date);
};

// Helper to convert country names into flag images
const getFlagImageUrl = (countryName: string) => {
  if (!countryName) return null;
  const codeMapping: Record<string, string> = {
    'korea': 'kr', 'south korea': 'kr', 'korea, republic of': 'kr', '대한민국': 'kr', '한국': 'kr',
    'japan': 'jp', '일본': 'jp',
    'china': 'cn', '중국': 'cn',
    'taiwan': 'tw', '대만': 'tw',
    'hong kong': 'hk', '홍콩': 'hk',
    'united states': 'us', 'usa': 'us', 'us': 'us', '미국': 'us',
    'argentina': 'ar', '아르헨티나': 'ar',
    'singapore': 'sg', '싱가포르': 'sg',
    'uk': 'gb', 'united kingdom': 'gb', 'england': 'gb', '영국': 'gb',
    'france': 'fr', '프랑스': 'fr',
    'germany': 'de', '독일': 'de',
    'italy': 'it', '이탈리아': 'it',
    'spain': 'es', '스페인': 'es',
    'australia': 'au', '호주': 'au',
    'canada': 'ca', '캐나다': 'ca',
    'brazil': 'br', '브라질': 'br',
    'mexico': 'mx', '멕시코': 'mx',
    'vietnam': 'vn', '베트남': 'vn',
    'thailand': 'th', '태국': 'th',
    'indonesia': 'id', '인도네시아': 'id',
    'malaysia': 'my', '말레이시아': 'my',
    'philippines': 'ph', '필리핀': 'ph',
  };
  const code = codeMapping[countryName.toLowerCase().trim()];
  if (!code) return null;
  return `https://flagcdn.com/16x12/${code}.png`;
};

export default function EventsPage() {
  const { toggleDrawer } = useNavigation();
  const { location } = useLocation();
  const { profile } = useAuth();
  const [events, setEvents] = useState<Event[]>([]);
  const [showCreateModal, setShowCreateModal] = useState(false);
  const [selectedEvent, setSelectedEvent] = useState<Event | null>(null);
  const [currentDate, setCurrentDate] = useState(new Date());

  // Real-time Subscription
  useEffect(() => {
    const unsub = eventService.subscribeEvents((data) => {
      const validEvents = data.filter(e => e.startDate);
      setEvents(validEvents);
    });
    return () => unsub();
  }, []);

  // Handle browser back button for modals
  useEffect(() => {
    const handlePopState = (e: PopStateEvent) => {
      if (selectedEvent) {
        setSelectedEvent(null);
      } else if (showCreateModal) {
        setShowCreateModal(false);
      }
    };

    if (selectedEvent || showCreateModal) {
      window.history.pushState({ modal: true }, '');
      window.addEventListener('popstate', handlePopState);
    }

    return () => {
      window.removeEventListener('popstate', handlePopState);
    };
  }, [selectedEvent, showCreateModal]);

  const handleCloseEvent = () => {
    setSelectedEvent(null);
    if (window.history.state?.modal) {
      window.history.back();
    }
  };

  const handleCloseCreate = () => {
    setShowCreateModal(false);
    if (window.history.state?.modal) {
      window.history.back();
    }
  };

  // Filter events by location
  const filteredLocationEvents = useMemo(() => {
    if (!location) return events;
    return events.filter(e => {
      const eventLoc = e.location?.toLowerCase() || '';
      const countryMatch = eventLoc.includes(location.country.toLowerCase());
      if (location.city === 'ALL') return countryMatch;
      const cityMatch = eventLoc.includes(location.city.toLowerCase());
      return countryMatch && cityMatch;
    });
  }, [events, location]);

  const sortedEvents = useMemo(() => {
    return [...filteredLocationEvents].sort((a, b) => 
      getNormalizedDate(a.startDate).getTime() - getNormalizedDate(b.startDate).getTime()
    );
  }, [filteredLocationEvents]);

  // Hot 5 Section (Current/Upcoming)
  const hot5Events = useMemo(() => {
    const today = startOfDay(new Date());
    return sortedEvents
      .filter(e => getNormalizedDate(e.endDate || e.startDate) >= today)
      .slice(0, 5);
  }, [sortedEvents]);

  // Calendar Logic (Current Month)
  const calendarRange = useMemo(() => {
    const startOfCurrentMonth = startOfMonth(currentDate);
    const startOfView = startOfWeek(startOfCurrentMonth, { weekStartsOn: 1 }); // Mon
    const days = [];

    // Create 35 days (5 weeks) or 42 days (6 weeks) to cover the month
    for (let i = 0; i < 42; i++) {
        days.push(addDays(startOfView, i));
    }

    return { days };
  }, [currentDate]);

  // Stack logic for calendar bars
  const eventSlots = useMemo(() => {
    const slotsMap: { [eventId: string]: number } = {};
    const occupiedUntil: { [slot: number]: Date } = {};

    [...events].sort((a, b) => 
      getNormalizedDate(a.startDate).getTime() - getNormalizedDate(b.startDate).getTime()
    ).forEach(event => {
      const start = getNormalizedDate(event.startDate);
      const end = getNormalizedDate(event.endDate || event.startDate);

      let slot = 0;
      while (occupiedUntil[slot] && occupiedUntil[slot] >= start) {
        slot++;
      }
      slotsMap[event.id] = slot;
      occupiedUntil[slot] = end;
    });

    return slotsMap;
  }, [events]);

  const STACK_COLORS = [
    { bg: '#0057bd', text: '#ffffff' },   // primary
    { bg: '#3d56ba', text: '#ffffff' },   // secondary
    { bg: '#6e9fff', text: '#002150' },   // primary-container
    { bg: '#8097ff', text: '#03288f' },   // secondary-container
    { bg: '#883b91', text: '#ffffff' },   // tertiary
  ];

  return (
    <>
      <style dangerouslySetInnerHTML={{ __html: `
        .no-scrollbar::-webkit-scrollbar { display: none; }
        .no-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }

        .calendar-grid {
            display: grid;
            grid-template-columns: repeat(7, 1fr);
            border-left: 1px solid var(--color-outline-variant, #a3abd7);
            border-top: 1px solid var(--color-outline-variant, #a3abd7);
        }

        .calendar-cell {
            min-height: 100px;
            border-right: 1px solid var(--color-outline-variant, #a3abd7);
            border-bottom: 1px solid var(--color-outline-variant, #a3abd7);
            padding: 4px;
            position: relative;
            display: flex;
            flex-direction: column;
            gap: 2px;
        }

        .event-container {
            position: absolute;
            top: 24px;
            left: 0;
            right: 0;
            pointer-events: none;
            z-index: 10;
        }

        .event-bar {
            height: 24px;
            font-size: 12px;
            font-weight: 800;
            padding: 0 6px;
            display: flex;
            align-items: center;
            border-radius: 4px;
            white-space: nowrap;
            overflow: hidden;
            text-overflow: ellipsis;
            pointer-events: auto;
            position: absolute;
            cursor: pointer;
            box-shadow: 0 1px 2px rgba(0,0,0,0.1);
        }
      `}} />

      <div className="min-h-screen">
        <main className="pt-24 pb-24">
          {/* Top 5 Section */}
          <section className="mb-8 px-4">
            <div className="flex items-end justify-between mb-4">
              <div>
                <h2 className="text-2xl font-extrabold font-headline tracking-tight text-on-background">Top 5</h2>
                <p className="text-on-surface-variant text-sm font-medium">Meet more popular events</p>
              </div>
              <span className="text-primary font-bold text-sm flex items-center gap-1 cursor-pointer">View all <span className="material-symbols-outlined text-sm">arrow_forward</span></span>
            </div>
            <div className="flex gap-4 overflow-x-auto no-scrollbar snap-x snap-mandatory">
              {hot5Events.length === 0 ? (
                <div className="w-full h-40 bg-white rounded-xl flex items-center justify-center border border-dashed border-gray-300">
                  <p className="text-gray-400">No events currently featured</p>
                </div>
              ) : (
                hot5Events.map((event, idx) => (
                  <div key={event.id} onClick={() => setSelectedEvent(event)} className="flex-shrink-0 w-[85%] snap-center rounded-xl overflow-hidden relative aspect-[4/3] shadow-sm cursor-pointer hover:opacity-95 transition-opacity">
                    <img 
                      alt={event.title} 
                      className="w-full h-full object-cover" 
                      src={event.imageUrl || "https://images.unsplash.com/photo-1501281668745-f7f57925c3b4?auto=format&fit=crop&q=80&w=1000"} 
                    />
                    <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-black/20 to-transparent flex flex-col justify-end p-4">
                      <span className="bg-[#0057bd] text-white w-fit px-2 py-0.5 rounded text-[10px] font-bold mb-2 tracking-wider uppercase">
                        {idx === 0 ? 'FEATURED' : idx < 3 ? 'POPULAR' : 'LIMITED'}
                      </span>
                      <h3 className="font-bold text-white text-lg leading-tight">{event.title}</h3>
                      {event.nativeName && (
                        <p className="text-white/90 text-[13px] font-medium leading-tight mt-0.5">{event.nativeName}</p>
                      )}
                      <p className="text-white/80 text-sm flex items-center gap-1.5 mt-1.5">
                        {(() => {
                          const flagUrl = getFlagImageUrl(event.location?.split(',').pop()?.trim() || '');
                          return flagUrl ? <img src={flagUrl} alt="flag" className="inline-block w-4 h-3 object-cover rounded-sm shadow-sm" /> : null;
                        })()}
                        {event.location?.split(',')[0]} • {format(getNormalizedDate(event.startDate), 'MMM dd')}
                      </p>
                    </div>
                  </div>
                ))
              )}
            </div>
          </section>

          {/* Upcoming (Calendar) Section */}
          <section className="px-4">
            <div className="flex justify-between items-center mb-4">
              <div>
                <h2 className="text-2xl font-extrabold font-headline tracking-tight text-on-background">Upcoming</h2>
                <p className="text-on-surface-variant text-sm font-medium">Enjoy a variety of global events</p>
              </div>
              <div className="flex items-center gap-1 bg-surface-container-lowest px-1 py-1 rounded-xl border border-outline-variant shadow-sm">
                <button onClick={() => setCurrentDate(prev => new Date(prev.getFullYear(), prev.getMonth() - 1, 1))} className="p-1 hover:bg-surface-container rounded-lg flex items-center justify-center transition-colors">
                  <span className="material-symbols-outlined text-on-surface-variant text-lg">chevron_left</span>
                </button>
                <span className="font-bold text-on-surface text-sm px-2 cursor-pointer select-none" onClick={() => setCurrentDate(new Date())}>
                  {format(currentDate, 'MMM yyyy')}
                </span>
                <button onClick={() => setCurrentDate(prev => new Date(prev.getFullYear(), prev.getMonth() + 1, 1))} className="p-1 hover:bg-surface-container rounded-lg flex items-center justify-center transition-colors">
                  <span className="material-symbols-outlined text-on-surface-variant text-lg">chevron_right</span>
                </button>
              </div>
            </div>

            <div className="bg-surface-container-lowest rounded-xl overflow-hidden shadow-sm border border-outline-variant">
              {/* Calendar Header Days */}
              <div className="grid grid-cols-7 bg-surface-container-low border-b border-outline-variant">
                {['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'].map(day => (
                  <div key={day} className="py-2 text-center text-[12px] font-semibold text-on-surface-variant uppercase">{day}</div>
                ))}
              </div>

              {/* Calendar Grid */}
              <div className="calendar-grid">
                {calendarRange.days.map((date, i) => {
                  const isCurrentMonth = date.getMonth() === currentDate.getMonth();
                  const isToday = isSameDay(date, new Date());

                  // Filter events occurring on this specific day
                  const dayEvents = events.filter(e => {
                    const start = getNormalizedDate(e.startDate);
                    const end = getNormalizedDate(e.endDate || e.startDate);
                    return date >= start && date <= end;
                  });

                  const dayMaxSlot = dayEvents.reduce((max, e) => Math.max(max, eventSlots[e.id] ?? 0), -1);
                  const cellMinHeight = Math.max(100, 28 + (dayMaxSlot + 1) * 26 + 8);

                  return (
                    <div key={i} className={`calendar-cell ${!isCurrentMonth ? 'bg-gray-50/30' : ''}`} style={{ minHeight: `${cellMinHeight}px` }}>
                      <span className={`text-[10px] font-bold ${isToday ? 'text-[#0057bd] w-5 h-5 bg-[#d3e4fe] rounded-full flex items-center justify-center' : 'text-gray-400'}`}>
                        {date.getDate()}
                      </span>

                      <div className="event-container">
                        {dayEvents.map(event => {
                          const start = getNormalizedDate(event.startDate);
                          const end = getNormalizedDate(event.endDate || event.startDate);

                          // Only render the bar if it's the start of the event or start of the week
                          const isStartOfBar = isSameDay(date, start) || getDay(date) === 1;

                          if (isStartOfBar) {
                            // Calculate how many days this event spans within the current week (up to 7 - dayOfWeek)
                            const dayOfWeek = (getDay(date) + 6) % 7; // 0-6 (Mon-Sun)
                            const remainingInWeek = 7 - dayOfWeek;
                            const totalDuration = differenceInCalendarDays(end, date) + 1;
                            const span = Math.min(totalDuration, remainingInWeek);

                            const slotIdx = eventSlots[event.id] ?? 0;
                            const colorSet = STACK_COLORS[slotIdx % STACK_COLORS.length];

                            return (
                              <div 
                                key={event.id} 
                                onClick={() => setSelectedEvent(event)}
                                className="event-bar" 
                                style={{ 
                                  backgroundColor: colorSet.bg, 
                                  color: colorSet.text,
                                  width: `calc(${span * 100}% - 4px)`,
                                  top: `${slotIdx * 26}px`,
                                  left: '2px',
                                  zIndex: 10
                                }}
                              >
                                {event.location ? (
                                  (() => {
                                    const flagUrl = getFlagImageUrl(event.location.split(',').pop()?.trim() || '');
                                    return flagUrl ? <img src={flagUrl} alt="flag" className="inline-block mr-1 w-3.5 h-[10.5px] object-cover rounded-sm shadow-sm" /> : null;
                                  })()
                                ) : null}
                                <span className="truncate">{event.title}</span>
                              </div>
                            );
                          }
                          return null;
                        })}
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          </section>
        </main>


        {/* Floating Add Button */}
        <button 
          onClick={() => setShowCreateModal(true)}
          className="fixed bottom-28 right-6 w-14 h-14 bg-[#0057bd] text-white rounded-full shadow-lg flex items-center justify-center hover:scale-110 active:scale-95 transition-all z-50"
        >
          <span className="material-symbols-outlined text-3xl">add</span>
        </button>

        <AnimatePresence>
          {showCreateModal && (
            <CreateEvent onClose={handleCloseCreate} onSuccess={() => {}} />
          )}
          {selectedEvent && (
            <EventDetail 
              event={selectedEvent} 
              onClose={handleCloseEvent}
              onDelete={(id) => {
                setEvents(prev => prev.filter(e => e.id !== id));
                handleCloseEvent();
              }}
              onEdit={(evt) => {
                alert("Edit functionality coming soon!");
              }}
            />
          )}
        </AnimatePresence>
      </div>
    </>
  );
}

'use client';

import '../gallery.css';
import React, { useState, useEffect, useRef, Suspense } from 'react';
import { useRouter, useSearchParams } from 'next/navigation';
import { 
  X, 
  Camera, 
  ChevronLeft, 
  MapPin, 
  Calendar, 
  Search,
  Check
} from 'lucide-react';
import { useAuth } from '@/components/providers/AuthProvider';
import { galleryService } from '@/lib/firebase/galleryService';
import { venueService } from '@/lib/firebase/venueService';
import { socialService } from '@/lib/firebase/socialService';
import { eventService } from '@/lib/firebase/eventService';
import { storage } from '@/lib/firebase/config';
import { ref, uploadBytes, uploadBytesResumable, getDownloadURL } from 'firebase/storage';

const GalleryCreateContent = () => {
  const router = useRouter();
  const { user } = useAuth();
  
  const [images, setImages] = useState<File[]>([]);
  const [previews, setPreviews] = useState<{url: string, type: 'image'|'video'}[]>([]);
  const [caption, setCaption] = useState('');
  const [isUploading, setIsUploading] = useState(false);
  const [uploadProgress, setUploadProgress] = useState(0);
  const [isEditMode, setIsEditMode] = useState(false);
  const [existingImages, setExistingImages] = useState<{url: string, type: 'image'|'video'}[]>([]);
  const searchParams = useSearchParams();
  const editId = searchParams.get('edit');

  // Search States
  const [venueSearch, setVenueSearch] = useState('');
  const [venueResults, setVenueResults] = useState<any[]>([]);
  const [selectedVenue, setSelectedVenue] = useState<any | null>(null);

  const [socialSearch, setSocialSearch] = useState('');
  const [socialResults, setSocialResults] = useState<any[]>([]);
  const [selectedSocial, setSelectedSocial] = useState<any | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Initial Load for Edit Mode
  useEffect(() => {
    if (editId) {
      setIsEditMode(true);
      galleryService.getPost(editId).then(post => {
        if (post) {
          if (user && post.authorId !== user.uid) {
            alert('수정 권한이 없습니다.');
            router.push('/gallery');
            return;
          }
          setCaption(post.caption);
          
          const loadedMedia = post.media.map((url, i) => ({
             url,
             type: post.mediaTypes ? post.mediaTypes[i] : (url.toLowerCase().includes('.mp4') || url.toLowerCase().includes('.mov') || url.toLowerCase().includes('.webm') || url.toLowerCase().includes('video') ? 'video' : 'image')
          })) as { url: string; type: 'image' | 'video' }[];
          
          setExistingImages(loadedMedia);
          setPreviews(loadedMedia);
          if (post.venueId) setSelectedVenue({ id: post.venueId, name: post.venueName });
          if (post.eventId) setSelectedSocial({ id: post.eventId, name: post.eventName });
        }
      });
    }
  }, [editId, user]);

  // Venue Search Logic
  useEffect(() => {
    const timer = setTimeout(async () => {
      if (venueSearch.length >= 1) {
        // Try original and capitalized to overcome Firestore case-sensitivity
        const capitalized = venueSearch.charAt(0).toUpperCase() + venueSearch.slice(1);
        const results = await venueService.searchVenues(venueSearch);
        const capResults = await venueService.searchVenues(capitalized);
        
        const combined = [...results, ...capResults];
        const unique = combined.filter((v, i, a) => a.findIndex(t => t.id === v.id) === i);
        setVenueResults(unique);
      } else {
        setVenueResults([]);
      }
    }, 300);
    return () => clearTimeout(timer);
  }, [venueSearch]);

  // Social (Event) Search Logic
  useEffect(() => {
    const timer = setTimeout(async () => {
      if (socialSearch.length >= 1) {
        const capitalized = socialSearch.charAt(0).toUpperCase() + socialSearch.slice(1);
        
        // Search BOTH events and socials
        const [evResults, evCapResults, socResults, socCapResults] = await Promise.all([
          eventService.searchEvents(socialSearch),
          eventService.searchEvents(capitalized),
          socialService.searchSocials(socialSearch),
          socialService.searchSocials(capitalized)
        ]);
        
        const combined = [...evResults, ...evCapResults, ...socResults, ...socCapResults];
        const unique = combined.filter((v, i, a) => a.findIndex(t => t.id === v.id) === i);
        setSocialResults(unique.map(e => ({ id: e.id, name: (e as any).title })));
      } else {
        setSocialResults([]);
      }
    }, 300);
    return () => clearTimeout(timer);
  }, [socialSearch]);

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files || []);
    if (files.length + images.length + existingImages.length > 10) return alert('Maximum 10 files allowed.');

    const newPreviews = files.map(file => ({
      url: URL.createObjectURL(file),
      type: file.type.startsWith('video/') ? 'video' as const : 'image' as const
    }));
    setImages([...images, ...files]);
    setPreviews([...previews, ...newPreviews]);
  };

  const removeImage = (index: number) => {
    const previewToRemove = previews[index];
    
    // If it's an existing image (URL)
    const existingIndex = existingImages.findIndex(img => img.url === previewToRemove.url);
    if (existingIndex >= 0) {
      setExistingImages(prev => prev.filter((_, i) => i !== existingIndex));
    } else {
      // It's a new file. Find its index in the 'images' array.
      // We need to know which of the 'previews' are new files.
      const newImagesStartIndex = existingImages.length;
      const fileIndex = index - newImagesStartIndex;
      if (fileIndex >= 0) {
        setImages(prev => {
          const next = [...prev];
          next.splice(fileIndex, 1);
          return next;
        });
      }
    }

    setPreviews(prev => {
      const next = [...prev];
      next.splice(index, 1);
      return next;
    });
  };

  const handlePost = async () => {
    if (!user) return alert('로그인이 필요합니다.');
    if (images.length === 0 && existingImages.length === 0) return alert('최소 1개의 미디어가 필요합니다.');
    if (!caption.trim()) return alert('설명을 입력해주세요.');

    setIsUploading(true);
    setUploadProgress(0);
    try {
      // 1. Upload NEW Images/Videos to Storage
      let totalBytesTransferred = 0;
      let totalBytes = images.reduce((acc, file) => acc + file.size, 0);

      const newMediaData = await Promise.all(
        images.map((file) => {
          return new Promise<{url: string, type: 'image'|'video'}>((resolve, reject) => {
            const storageRef = ref(storage, `gallery/${user.uid}/${Date.now()}_${file.name}`);
            const uploadTask = uploadBytesResumable(storageRef, file);
            
            let lastTransferred = 0;
            uploadTask.on('state_changed', 
              (snapshot) => {
                const diff = snapshot.bytesTransferred - lastTransferred;
                lastTransferred = snapshot.bytesTransferred;
                totalBytesTransferred += diff;
                const progress = Math.round((totalBytesTransferred / totalBytes) * 100);
                setUploadProgress(progress > 100 ? 100 : progress);
              },
              (error) => reject(error),
              async () => {
                const url = await getDownloadURL(uploadTask.snapshot.ref);
                resolve({ url, type: file.type.startsWith('video/') ? 'video' : 'image' });
              }
            );
          });
        })
      );

      const finalMediaUrls = [...existingImages.map(img => img.url), ...newMediaData.map(m => m.url)];
      const finalMediaTypes = [...existingImages.map(img => img.type), ...newMediaData.map(m => m.type)];

      if (isEditMode && editId) {
        // Update existing post
        await galleryService.updatePost(editId, {
          media: finalMediaUrls,
          mediaTypes: finalMediaTypes,
          caption: caption,
          venueId: selectedVenue?.id || '',
          venueName: selectedVenue?.name || '',
          eventId: selectedSocial?.id || '',
          eventName: selectedSocial?.name || '',
        });
      } else {
        // Create NEW post
        await galleryService.createPost({
          authorId: user.uid,
          authorName: user.displayName || 'Anonymous',
          authorPhoto: user.photoURL || '',
          media: finalMediaUrls,
          mediaTypes: finalMediaTypes,
          caption: caption,
          venueId: selectedVenue?.id || '',
          venueName: selectedVenue?.name || '',
          eventId: selectedSocial?.id || '',
          eventName: selectedSocial?.name || '',
        });
      }

      router.push('/gallery');
    } catch (error) {
      console.error(error);
      alert(isEditMode ? '수정 중 오류가 발생했습니다.' : '게시 중 오류가 발생했습니다.');
    } finally {
      setIsUploading(false);
    }
  };

  return (
    <div className="fixed inset-0 z-[100] bg-white md:bg-black/80 flex justify-center backdrop-blur-sm">
      <div className="gallery-create-container w-full h-full overflow-y-auto bg-white shadow-xl flex flex-col relative">
      {/* Header */}
      <div className="create-header">
        <button onClick={() => router.back()}><ChevronLeft size={24} /></button>
        <span className="create-title">{isEditMode ? 'Edit Post' : 'New Post'}</span>
        <button 
          className="btn-post" 
          onClick={handlePost} 
          disabled={isUploading || (images.length === 0 && existingImages.length === 0)}
        >
          {isUploading ? `${uploadProgress}%` : (isEditMode ? 'Update' : 'Post')}
        </button>
      </div>

      {isUploading && (
        <div className="w-full bg-gray-100 h-1">
          <div className="bg-primary h-1 transition-all duration-300" style={{ width: `${uploadProgress}%` }}></div>
        </div>
      )}

      {/* Image Upload Area */}
      <div className="upload-section">
        <div className="image-preview-scroll">
          {previews.map((item, idx) => (
            <div key={idx} className="preview-item">
              {item.type === 'video' ? (
                <video src={item.url} className="w-full h-full object-cover" muted loop autoPlay playsInline />
              ) : (
                <img src={item.url} alt="" className="w-full h-full object-cover" />
              )}
              <button className="btn-remove-image" onClick={() => removeImage(idx)}>
                <X size={14} />
              </button>
            </div>
          ))}
          <button className="btn-add-more" onClick={() => fileInputRef.current?.click()}>
            <Camera size={24} />
            <span>Add More</span>
          </button>
        </div>
        <input 
          type="file" 
          multiple 
          accept="image/*,video/*" 
          hidden 
          ref={fileInputRef} 
          onChange={handleImageChange} 
        />
      </div>

      {/* Form Fields */}
      <div className="form-section">
        <textarea 
          className="caption-input" 
          placeholder="Write a caption..." 
          value={caption}
          onChange={(e) => setCaption(e.target.value)}
        />

        {/* Venue Tagging (Real DB Search) */}
        <div className="tag-search-container border-t pt-6">
          <div className="tag-label">
            <MapPin size={18} />
            <span>Place</span>
          </div>
          {selectedVenue ? (
            <div className="selected-tag-chip">
              <span>{selectedVenue.name}</span>
              <button onClick={() => setSelectedVenue(null)}><X size={14} /></button>
            </div>
          ) : (
            <div className="search-input-wrapper">
              <input 
                type="text" 
                className="search-input" 
                placeholder="Search venue..." 
                value={venueSearch}
                onChange={(e) => setVenueSearch(e.target.value)}
              />
              {venueResults.length > 0 && (
                <div className="search-results">
                  {venueResults.map(v => (
                    <div key={v.id} className="search-item" onClick={() => {
                      setSelectedVenue(v);
                      setVenueResults([]);
                      setVenueSearch('');
                    }}>
                      <MapPin size={16} className="text-gray-400" />
                      <div>
                        <div className="font-semibold text-sm">{v.name}</div>
                        <div className="text-xs text-gray-400">{v.location}</div>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          )}
        </div>

        {/* Social Tagging (Real DB Search) */}
        <div className="tag-search-container pt-4">
          <div className="tag-label">
            <Calendar size={18} />
            <span>Event / Social</span>
          </div>
          {selectedSocial ? (
            <div className="selected-tag-chip">
              <span>{selectedSocial.name}</span>
              <button onClick={() => setSelectedSocial(null)}><X size={14} /></button>
            </div>
          ) : (
            <div className="search-input-wrapper">
              <input 
                type="text" 
                className="search-input" 
                placeholder="Search event or organizer..." 
                value={socialSearch}
                onChange={(e) => setSocialSearch(e.target.value)}
              />
              {socialResults.length > 0 && (
                <div className="search-results">
                  {socialResults.map(s => (
                    <div key={s.id} className="search-item" onClick={() => {
                      setSelectedSocial(s);
                      setSocialResults([]);
                      setSocialSearch('');
                    }}>
                      <Calendar size={16} className="text-gray-400" />
                      <span className="text-sm">{s.name}</span>
                    </div>
                  ))}
                </div>
              )}
            </div>
          )}
        </div>
      </div>
    </div>
    </div>
  );
};

const GalleryCreatePage = () => (
  <Suspense fallback={
    <div className="flex items-center justify-center min-h-screen">
      <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary"></div>
    </div>
  }>
    <GalleryCreateContent />
  </Suspense>
);

export default GalleryCreatePage;

