                <button 
                  onClick={() => setSelectedFilters(prev => ({ ...prev, organizers: prev.organizers.filter(o => o !== org) }))}
                  className="w-4 h-4 flex items-center justify-center rounded-full hover:bg-primary/20 transition-colors"
