import GroupDetail from "@/components/group/GroupDetail";
import { groupService } from "@/lib/firebase/groupService";
import { notFound } from "next/navigation";

export const dynamic = 'force-dynamic';

export default async function SpaceStandalonePage(props: { params: Promise<{ groupId: string }> }) {
  const params = await props.params;
  const groupId = params.groupId;
  
  try {
    const group = await groupService.getGroup(groupId);
    
    if (!group) {
      notFound();
    }
    
    return <GroupDetail group={group} />;
  } catch (error) {
    console.error(`Error loading space ${groupId}:`, error);
    // Return a graceful error UI instead of crashing the whole server
    return (
      <div className="min-h-screen flex flex-col items-center justify-center p-6 bg-surface text-center">
        <div className="w-20 h-20 bg-red-50 rounded-full flex items-center justify-center mb-6">
          <span className="material-symbols-outlined text-red-500 text-4xl">error</span>
        </div>
        <h1 className="text-2xl font-black text-on-surface mb-2">공간 정보를 불러올 수 없습니다</h1>
        <p className="text-on-surface-variant max-w-sm mb-4">
          데이터를 가져오는 중 문제가 발생했습니다. 일시적인 오류일 수 있으니 잠시 후 다시 시도해 주세요.
        </p>
        <div className="bg-red-50 text-red-500 text-xs p-4 rounded-lg mb-8 max-w-lg overflow-auto text-left">
          {error instanceof Error ? error.message : String(error)}
        </div>
        <a 
          href="" 
          className="px-8 py-3 bg-primary text-on-primary rounded-full font-bold hover:opacity-90 transition-all inline-block"
        >
          다시 시도
        </a>
      </div>
    );
  }
}

"use client";

import React, { useState, useEffect, Suspense } from 'react';
import { Event } from '@/types/event';
import { eventService } from '@/lib/firebase/eventService';
import { userService } from '@/lib/firebase/userService';
import { PlatformUser } from '@/types/user';
import { useAuth } from '@/components/providers/AuthProvider';
import { useSearchParams } from 'next/navigation';
import societiesData from '../../../woc_societies_data.json';

export default function HomePage() {
  return (
    <Suspense fallback={<div className="min-h-screen flex items-center justify-center"><div className="w-8 h-8 border-4 border-primary/20 border-t-primary rounded-full animate-spin"></div></div>}>
      <HomeContent />
    </Suspense>
  );
}

function HomeContent() {
  const { user, profile } = useAuth();
  const searchParams = useSearchParams();
  const societyId = searchParams.get('society') || 'tango';
  const societyInfo = societiesData.find((s: any) => s.id === societyId) || societiesData[0];
  const [isSafeFloorOpen, setIsSafeFloorOpen] = useState(false);
  const [isRegionalReportsOpen, setIsRegionalReportsOpen] = useState(false);
  const [isRegistrationOpen, setIsRegistrationOpen] = useState(false);
  const [upcomingEvent, setUpcomingEvent] = useState<Event | null>(null);
  const [loadingEvent, setLoadingEvent] = useState(true);
  const [topMembers, setTopMembers] = useState<PlatformUser[]>([]);
  const [loadingMembers, setLoadingMembers] = useState(true);
  const [toastMessage, setToastMessage] = useState<string | null>(null);

  useEffect(() => {
    const fetchEvent = async () => {
      try {
        const events = await eventService.getUpcomingEvents(1);
        if (events.length > 0) {
          setUpcomingEvent(events[0]);
        }
      } catch (error) {
        console.error("Failed to fetch upcoming event:", error);
      } finally {
        setLoadingEvent(false);
      }
    };
    const fetchMembers = async () => {
      try {
        const members = await userService.getTopMembers(3);
        setTopMembers(members);
      } catch (error) {
        console.error("Failed to fetch top members:", error);
      } finally {
        setLoadingMembers(false);
      }
    };
    fetchEvent();
    fetchMembers();
  }, []);

  const handleLeaderboardClick = () => {
    setToastMessage("The society is not yet active enough to show the leaderboard.");
    setTimeout(() => {
      setToastMessage(null);
    }, 3000);
  };

  const displayName = profile?.nickname || user?.displayName || 'Dancer';

  return (
    <main className="py-6 px-4 max-w-7xl mx-auto space-y-10 pb-24">
      {/* Welcome Section */}
      <section className="bg-surface-container-low rounded-[24px] p-8 md:p-12 shadow-md relative overflow-hidden flex flex-col md:flex-row gap-8 items-center">
        {/* Background Decorative Element */}
        <div className="absolute -top-24 -right-24 w-64 h-64 bg-primary opacity-5 rounded-full blur-3xl pointer-events-none"></div>
        {/* Content Area */}
        <div className="flex-1 z-10 flex flex-col gap-6">
          <div>
            <h1 className="text-headline-lg text-on-surface mb-4 font-medium text-headline-lg">
              <span className="font-bold">{displayName},</span> {societyInfo.welcome_message.replace(/^Hi Stony,\s*/, '')}
            </h1>
            <p className="font-body-md text-body-md text-on-surface-variant max-w-lg leading-relaxed">
              {societyInfo.welcome_text}
            </p>
          </div>
          {/* Action Buttons */}
          <div className="flex flex-col sm:flex-row mt-4">
            <div className="flex items-center gap-2 text-primary">
              <span className="material-symbols-outlined text-[20px]" style={{ fontVariationSettings: "'FILL' 1" }}>favorite</span>
              <span className="font-title-md text-[0.9375rem]">{societyInfo.keyword_badges[0]}</span>
            </div>
            <div className="hidden sm:block w-px h-4 bg-primary/20 mx-2"></div>
            <div className="flex items-center gap-2 text-primary">
              <span className="material-symbols-outlined text-[20px]" style={{ fontVariationSettings: "'FILL' 1" }}>public</span>
              <span className="font-title-md text-[0.9375rem]">{societyInfo.keyword_badges[1]}</span>
            </div>
          </div>
        </div>
        {/* Illustrative Area (Optional, for balance) */}
        <div className="hidden md:flex w-64 h-64 rounded-full overflow-hidden border-4 border-surface-container-lowest shadow-xl z-10 shrink-0">
          <img 
            alt="Tango Dancers" 
            className="w-full h-full object-cover" 
            data-alt="couple dancing argentine tango in a warm dimly lit studio with elegant movements"
            src="https://lh3.googleusercontent.com/aida-public/AB6AXuCCYfQGQDXbHPIjXZgEql-aMFBFu7P7nmLDKstNGCaCi5uu3xVLVHFCE2vaPp4UlDnTpVvxHSxqYOf4V-KefxHnp6h1xdfzSyC8SQGhMjyeAJqTTNyM8dRPihZ9AvCR_vRHUabvoLdO0hf95kA3CuXK0XnZcgriNI_VD1wOxE-tDNLf7MHwUT4ih-yyPq9bsV0NkrTxQeWmQK6U160hjQo1js3JYdVm9xr1V41DWGaKJjgEsEoXuNIPih2w10o9vnkhida3XcyyizQ"
          />
        </div>
      </section>

      {/* Featured Highlight */}
      <section className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div 
          className="lg:col-span-2 relative aspect-video rounded-[40px] overflow-hidden shadow-xl group cursor-pointer"
          onClick={() => setIsSafeFloorOpen(true)}
        >
          <img 
            className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-700" 
            src="https://images.unsplash.com/photo-1518609878373-06d740f60d8b?q=80&w=1200" 
            alt="Safe Floor Policy" 
          />
          <div className="absolute inset-0 bg-gradient-to-t from-black/90 via-black/40 to-transparent" />
          <div className="absolute bottom-8 left-8 right-8">
            <span className="px-3 py-1 bg-red-600 text-white text-[10px] font-bold uppercase tracking-widest rounded-full mb-3 inline-block">{societyInfo.blog_core_keyword}</span>
            <h3 className="text-2xl md:text-3xl font-black text-white mb-2 leading-tight font-headline">
              {societyInfo.blog_title}<br/>
              <span className="text-lg md:text-xl font-normal text-white/90">{societyInfo.blog_subtitle}</span>
            </h3>
            <p className="text-white/80 max-w-lg font-body text-xs md:text-sm mt-3">
              {societyInfo.blog_description}
            </p>
            <button className="mt-5 px-6 py-3 bg-white text-slate-900 font-bold rounded-xl shadow-lg hover:bg-slate-100 transition-colors">
              Read Full Story
            </button>
          </div>
