'use client';

import React, { useState, useEffect } from 'react';
import { createPortal } from 'react-dom';
import { User, MapPin, Phone, Globe, ChevronRight } from 'lucide-react';

export default function ProfileSetupOverlay() {
  const [isOpen, setIsOpen] = useState(false);
  const [mounted, setMounted] = useState(false);
  const [formData, setFormData] = useState({
    nickname_en: '',
    nickname_ko: '',
    main_region: '서울',
    phone: ''
  });

  useEffect(() => {
    setMounted(true);
    const savedProfile = localStorage.getItem('woc_user_profile');
    if (!savedProfile) {
      setIsOpen(true);
    }
  }, []);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.nickname_en || !formData.nickname_ko) {
      alert('닉네임을 입력해주세요.');
      return;
    }
    localStorage.setItem('woc_user_profile', JSON.stringify({
      ...formData,
      setupAt: new Date().toISOString()
    }));
    setIsOpen(false);
  };

  if (!mounted || !isOpen) return null;

  return createPortal(
    <div className="fixed inset-0 z-[9999] flex items-end sm:items-center justify-center p-0 sm:p-4">
      {/* Backdrop */}
      <div className="absolute inset-0 bg-black/40 backdrop-blur-sm animate-in fade-in transition-opacity" />
      
      {/* Modal Content */}
      <div className="relative bg-background w-full max-w-lg h-[90vh] sm:h-auto sm:max-h-[85vh] sm:rounded-3xl border-t sm:border border-glass-border shadow-2xl overflow-hidden flex flex-col animate-slide-up">
        {/* Header */}
        <div className="px-8 py-8 text-center space-y-2">
          <div className="w-16 h-16 bg-primary/10 text-primary rounded-2xl flex items-center justify-center mx-auto mb-4">
            <User size={32} strokeWidth={1.5} />
          </div>
          <h2 className="text-2xl font-bold tracking-tight">반가워요!</h2>
          <p className="text-muted-foreground text-sm">
            WoC 플랫폼 시작을 위해<br />기본 프로필을 설정해주세요.
          </p>
        </div>

        {/* Form Content */}
        <div className="flex-1 overflow-y-auto px-8 pb-8 scrollbar-hide">
          <form id="profile-form" onSubmit={handleSubmit} className="space-y-6">
            {/* Nickname EN */}
            <div className="space-y-2">
              <label className="text-xs font-bold text-muted-foreground uppercase tracking-wider flex items-center gap-1.5 ml-1">
                <Globe size={14} /> 영문 닉네임 (Unique ID)
              </label>
              <input 
                required
                type="text" 
                placeholder="예: stone_tangogo"
                value={formData.nickname_en}
                onChange={(e) => setFormData({...formData, nickname_en: e.target.value.toLowerCase()})}
                className="w-full bg-glass border border-glass-border rounded-2xl px-4 py-3.5 text-sm focus:outline-none focus:ring-2 focus:ring-primary/20 transition-all font-mono"
              />
            </div>

            {/* Nickname KO */}
            <div className="space-y-2">
              <label className="text-xs font-bold text-muted-foreground uppercase tracking-wider flex items-center gap-1.5 ml-1">
                <User size={14} /> 한글 닉네임
              </label>
              <input 
                required
                type="text" 
                placeholder="예: 스톤홍"
                value={formData.nickname_ko}
                onChange={(e) => setFormData({...formData, nickname_ko: e.target.value})}
                className="w-full bg-glass border border-glass-border rounded-2xl px-4 py-3.5 text-sm focus:outline-none focus:ring-2 focus:ring-primary/20 transition-all"
              />
            </div>

            {/* Region */}
            <div className="space-y-2">
              <label className="text-xs font-bold text-muted-foreground uppercase tracking-wider flex items-center gap-1.5 ml-1">
                <MapPin size={14} /> 주 활동 지역
              </label>
              <select 
                value={formData.main_region}
                onChange={(e) => setFormData({...formData, main_region: e.target.value})}
                className="w-full bg-glass border border-glass-border rounded-2xl px-4 py-3.5 text-sm focus:outline-none focus:ring-2 focus:ring-primary/20 transition-all appearance-none cursor-pointer"
              >
                {['서울', '경기/인천', '부산/경남', '대구/경북', '광주/전라', '대전/충청', '강원', '제주'].map(r => (
                  <option key={r} value={r}>{r}</option>
                ))}
              </select>
            </div>

            {/* Phone */}
            <div className="space-y-2">
              <label className="text-xs font-bold text-muted-foreground uppercase tracking-wider flex items-center gap-1.5 ml-1">
                <Phone size={14} /> 전화번호
              </label>
              <input 
                type="tel" 
                id="tel"
                name="tel"
                autoComplete="tel"
                placeholder="예: 010-1234-5678"
                value={formData.phone}
                onChange={(e) => setFormData({...formData, phone: e.target.value})}
                className="w-full bg-glass border border-glass-border rounded-2xl px-4 py-3.5 text-sm focus:outline-none focus:ring-2 focus:ring-primary/20 transition-all font-mono"
              />
            </div>
          </form>
        </div>

        {/* Action Button */}
        <div className="p-8 pt-4 bg-background/50 backdrop-blur-sm sticky bottom-0">
          <button 
            type="submit"
            form="profile-form"
            className="w-full bg-primary text-white py-4 rounded-2xl font-bold flex items-center justify-center gap-2 hover:brightness-110 active:scale-95 transition-all shadow-xl shadow-primary/25"
          >
            시작하기 <ChevronRight size={20} />
          </button>
        </div>
      </div>
    </div>,
    document.body
  );
}

'use client';

import React, { useState, useEffect } from 'react';
import { chatService } from '@/lib/firebase/chatService';
import { ChatRoom } from '@/types/chat';
import { useAuth } from '@/components/providers/AuthProvider';
import { formatDistanceToNow } from 'date-fns';
import { ko } from 'date-fns/locale';

interface ChatListProps {
  onSelectRoom: (roomId: string) => void;
  selectedRoomId?: string | null;
}

export default function ChatList({ onSelectRoom, selectedRoomId }: ChatListProps) {
  const { user } = useAuth();
  const [rooms, setRooms] = useState<ChatRoom[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (!user) return;
    
    chatService.initializeSystemRooms();
    const unsub = chatService.subscribeRooms(user.uid, (updatedRooms) => {
      setRooms(updatedRooms);
      setLoading(false);
    });

    return () => unsub();
  }, [user]);

  if (loading) {
    return (
      <div className="flex-1 flex flex-col gap-4 p-6 animate-pulse">
        {[1, 2, 3, 4, 5].map(i => (
          <div key={i} className="flex gap-4 items-center">
            <div className="w-14 h-14 rounded-full bg-gray-100" />
            <div className="flex-1 space-y-2">
              <div className="h-4 bg-gray-100 rounded w-1/3" />
              <div className="h-3 bg-gray-100 rounded w-2/3" />
            </div>
          </div>
        ))}
      </div>
    );
  }

  return (
    <div className="flex-1 overflow-y-auto no-scrollbar">
      {rooms.length === 0 ? (
        <div className="flex flex-col items-center justify-center h-[60vh] text-center px-10">
          <div className="w-20 h-20 rounded-full bg-gray-50 flex items-center justify-center mb-6">
            <span className="material-symbols-outlined text-gray-200 text-4xl">chat_bubble</span>
          </div>
          <h3 className="text-lg font-black text-gray-900 mb-2 uppercase tracking-tighter">No Conversations</h3>
          <p className="text-xs text-gray-400 font-medium leading-relaxed">Start a new dialogue with the group or friends.</p>
        </div>
      ) : (
        <div className="divide-y divide-gray-50">
          {rooms.map((room) => {
            const isSelected = selectedRoomId === room.id;
            const unreadCount = room.unreadCounts?.[user?.uid || ''] || 0;
            const lastTime = room.lastMessageTime 
              ? formatDistanceToNow(room.lastMessageTime.toDate(), { addSuffix: true, locale: ko })
              : '';

            return (
              <button
                key={room.id}
                onClick={() => onSelectRoom(room.id)}
                className={`w-full flex items-center gap-4 p-5 transition-all text-left ${isSelected ? 'bg-primary/5' : 'hover:bg-gray-50'}`}
              >
                <div className="relative shrink-0">
                  <div className="w-14 h-14 rounded-full overflow-hidden bg-gray-100 ring-1 ring-gray-100 shadow-inner">
                    <img 
                      src={room.imageUrl || "https://lh3.googleusercontent.com/a/default-user"} 
                      alt={room.name} 
                      className="w-full h-full object-cover" 
                    />
                  </div>
                  {room.type === 'notice' && (
                    <div className="absolute -top-1 -right-1 bg-primary text-white w-6 h-6 rounded-full flex items-center justify-center border-2 border-white shadow-sm">
                      <span className="material-symbols-outlined text-[12px] font-black">campaign</span>
                    </div>
                  )}
                  {unreadCount > 0 && (
                    <div className="absolute -top-1 -right-1 bg-red-500 text-white min-w-[20px] h-5 rounded-full px-1.5 flex items-center justify-center text-[10px] font-black border-2 border-white animate-in zoom-in">
                      {unreadCount > 99 ? '99+' : unreadCount}
                    </div>
                  )}
                </div>
                
                <div className="flex-1 min-w-0">
                  <div className="flex justify-between items-baseline mb-1">
                    <h3 className={`text-[15px] font-black truncate uppercase tracking-tight ${unreadCount > 0 ? 'text-gray-900' : 'text-gray-600'}`}>
                      {room.name}
                    </h3>
                    <span className="text-[10px] text-gray-400 font-bold ml-2 shrink-0">{lastTime}</span>
                  </div>
                  <p className={`text-[13px] truncate font-medium ${unreadCount > 0 ? 'text-gray-500' : 'text-gray-400'}`}>
                    {room.lastMessage}
                  </p>
                </div>
              </button>
            );
          })}
        </div>
      )}
    </div>
  );
}

'use client';

import React, { useState, useEffect, useRef } from 'react';
import { chatService } from '@/lib/firebase/chatService';
import type { ChatRoom, ChatMessage, MessageType } from '@/types/chat';
import { useAuth } from '@/components/providers/AuthProvider';
import { format, isToday, isYesterday } from 'date-fns';
import { ko } from 'date-fns/locale';
import VoiceBubble from './VoiceBubble';
import GroupMembersPopup from './GroupMembersPopup';
import { motion, AnimatePresence } from 'framer-motion';
import { doc, onSnapshot, getDoc } from 'firebase/firestore';
import { db } from '@/lib/firebase/clientApp';

interface ChatRoomProps {
  roomId: string;
  onBack: () => void;
}

export default function ChatRoom({ roomId, onBack }: ChatRoomProps) {
  const { user } = useAuth();
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [inputText, setInputText] = useState('');
  const [room, setRoom] = useState<ChatRoom | null>(null);
  const [isUploading, setIsUploading] = useState(false);
  const [uploadProgress, setUploadProgress] = useState(0);
  const [replyTo, setReplyTo] = useState<ChatMessage | null>(null);
  const [menuMsgId, setMenuMsgId] = useState<string | null>(null);
  const [isRecording, setIsRecording] = useState(false);
  const [recordDuration, setRecordDuration] = useState(0);
  const [otherUser, setOtherUser] = useState<any>(null);
  const [isGroupMembersOpen, setIsGroupMembersOpen] = useState(false);
  const [selectedMedia, setSelectedMedia] = useState<{url: string, type: 'image' | 'video'} | null>(null);
  const [messageLimit, setMessageLimit] = useState(50);
  const [isLoadingMore, setIsLoadingMore] = useState(false);
  const [isOtherTyping, setIsOtherTyping] = useState(false);
  
  const scrollRef = useRef<HTMLDivElement>(null);
  const prevScrollHeightRef = useRef<number>(0);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);
  const timerRef = useRef<NodeJS.Timeout | null>(null);
  const typingTimeoutRef = useRef<NodeJS.Timeout | null>(null);

  const REACTION_EMOJIS = ['👍', '❤️', '🥰', '😂', '😮', '😢', '😡'];

  // 1. Subscribe to Messages & Room Info
  useEffect(() => {
    if (!user || !roomId) return;

    const unsubMessages = chatService.subscribeMessages(roomId, messageLimit, (newMsgs) => {
      setMessages(newMsgs);
      // Mark as read logic
      chatService.resetUnreadCount(roomId, user.uid);
      
      // Mark individual messages as read
      newMsgs.forEach(msg => {
        if (msg.readBy && !msg.readBy.includes(user.uid)) {
          chatService.markMessageAsRead(msg.id, user.uid);
        }
      });
    });

    const roomRef = doc(db, 'chat_rooms', roomId);
    const unsubRoom = onSnapshot(roomRef, (docSnap) => {
      if (docSnap.exists()) {
        const data = docSnap.data() as any;
        setRoom({ id: docSnap.id, ...data } as ChatRoom);
        
        // Check typing status
        const typingArray = data.typing || [];
        const othersTyping = typingArray.filter((uid: string) => uid !== user.uid);
        setIsOtherTyping(othersTyping.length > 0);
      }
    });

    return () => {
      unsubMessages();
      unsubRoom();
    };
  }, [roomId, user, messageLimit]);

  useEffect(() => {
    if (!room || !user) return;
    if (room.type === 'private') {
      const otherUserId = room.participants.find(p => p !== user.uid);
      if (otherUserId) {
        const fetchUser = async () => {
          try {
            const userDoc = await getDoc(doc(db, 'users', otherUserId));
            if (userDoc.exists()) {
              setOtherUser(userDoc.data());
            }
          } catch (err) {
            console.error("Failed to fetch other user", err);
          }
        };
        fetchUser();
      }
    }
  }, [room, user]);

  // 2. Scroll to Bottom or Maintain Scroll Pos
  useEffect(() => {
    if (scrollRef.current) {
      if (isLoadingMore) {
        // Restore scroll position after loading older messages
        scrollRef.current.scrollTop = scrollRef.current.scrollHeight - prevScrollHeightRef.current;
        setIsLoadingMore(false);
      } else {
        // Scroll to bottom on new message
        scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
      }
    }
  }, [messages]);

  const handleScroll = (e: React.UIEvent<HTMLDivElement>) => {
    if (e.currentTarget.scrollTop === 0 && messages.length >= messageLimit) {
      prevScrollHeightRef.current = e.currentTarget.scrollHeight;
      setIsLoadingMore(true);
      setMessageLimit(prev => prev + 50);
    }
  };

  // 3. Send Logic
  const handleSend = async () => {
    if (!inputText.trim() || !user) return;
    const text = inputText;
    setInputText('');
    
    await chatService.sendMessage({
      roomId,
      senderId: user.uid,
      senderName: user.displayName || 'Anonymous',
      text,
      type: 'text',
      replyTo: replyTo?.id
    });
    setReplyTo(null);
  };

  // 4. File Upload Logic
  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || !user) return;

    setIsUploading(true);
    setUploadProgress(0);
    try {
      const type: MessageType = file.type.startsWith('image/') ? 'image' : 'video';
      const path = `chat/${roomId}/${Date.now()}_${file.name}`;
      const url = await chatService.uploadChatMedia(file, path, (p) => setUploadProgress(Math.round(p)));

      await chatService.sendMessage({
        roomId,
        senderId: user.uid,
        senderName: user.displayName || 'Anonymous',
        text: type === 'image' ? 'Sent a photo' : 'Sent a video',
        type,
        mediaUrl: url
      });
    } catch (err) {
      console.error("Upload failed:", err);
    } finally {
      setIsUploading(false);
      setUploadProgress(0);
    }
  };

  // 5. Voice Recording
  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const recorder = new MediaRecorder(stream);
      mediaRecorderRef.current = recorder;
      audioChunksRef.current = [];

      recorder.ondataavailable = (e) => audioChunksRef.current.push(e.data);
      recorder.onstop = async () => {
        const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/webm' });
        if (audioBlob.size < 100) return;

        setIsUploading(true);
        const url = await chatService.uploadChatMedia(audioBlob, `chat/${roomId}/voice_${Date.now()}.webm`);
        await chatService.sendMessage({
          roomId,
          senderId: user?.uid || '',
          senderName: user?.displayName || 'Anonymous',
          text: 'Sent a voice message',
          type: 'voice',
          mediaUrl: url
        });
        setIsUploading(false);
      };

      recorder.start();
      setIsRecording(true);
      setRecordDuration(0);
      timerRef.current = setInterval(() => setRecordDuration(p => p + 1), 1000);
    } catch (err) {
      alert("Mic permission needed");
    }
  };

  const stopRecording = () => {
    mediaRecorderRef.current?.stop();
    mediaRecorderRef.current?.stream.getTracks().forEach(t => t.stop());
    setIsRecording(false);
    if (timerRef.current) clearInterval(timerRef.current);
  };

  // UI Helpers
  const formatTime = (ts: any) => {
    if (!ts) return '';
    const date = ts.toDate ? ts.toDate() : new Date(ts);
    return format(date, 'HH:mm');
  };

  const renderMessageText = (text: string) => {
    return text.split('\n').map((line, i) => (
      <React.Fragment key={i}>
        {line}
        {i !== text.split('\n').length - 1 && <br />}
      </React.Fragment>
    ));
  };

  return (
    <div className="flex flex-col h-full bg-white relative overflow-hidden font-manrope">
      {/* Header */}
      {room?.type === 'private' ? (
        <div className="px-6 py-4 border-b border-gray-100 flex items-center justify-between bg-white/80 backdrop-blur-xl z-20 sticky top-0">
          <div className="flex items-center gap-4">
            <button onClick={onBack} className="md:hidden w-10 h-10 rounded-full flex items-center justify-center bg-gray-50 hover:bg-gray-100 transition-all text-gray-500">
              <span className="material-symbols-outlined text-[20px]">arrow_back_ios_new</span>
            </button>
            <div className="relative">
              {otherUser?.photoURL ? (
                <img alt="Profile" className="w-12 h-12 rounded-full object-cover ring-2 ring-white shadow-sm" src={otherUser.photoURL} />
              ) : (
                <div className="w-12 h-12 rounded-full object-cover ring-2 ring-white shadow-sm bg-gray-200 flex items-center justify-center">
                  <span className="material-symbols-outlined text-gray-400">person</span>
                </div>
              )}
              <div className="absolute bottom-0 right-0 w-3 h-3 bg-green-500 rounded-full border-2 border-white"></div>
            </div>
            <div className="flex flex-col">
              <h2 className="text-[18px] font-black text-gray-900 uppercase tracking-tighter line-clamp-1">
                {otherUser?.nickname || otherUser?.nativeNickname || otherUser?.displayName || 'Unknown'}
              </h2>
              <div className="flex items-center gap-1.5">
                <span className="text-[11px] font-bold text-gray-400 uppercase tracking-widest">{otherUser?.location || 'Seoul, Korea'}</span>
              </div>
            </div>
          </div>
          <div className="flex items-center gap-1">
            <button className="w-10 h-10 rounded-full flex items-center justify-center text-gray-400 hover:text-primary hover:bg-primary/5 transition-all">
              <span className="material-symbols-outlined text-[22px]">call</span>
            </button>
            <button className="w-10 h-10 rounded-full flex items-center justify-center text-gray-400 hover:text-primary hover:bg-primary/5 transition-all">
              <span className="material-symbols-outlined text-[22px]">videocam</span>
            </button>
          </div>
        </div>
      ) : (
        <div className="px-6 py-4 border-b border-gray-50 flex items-center justify-between bg-white z-20 sticky top-0">
          <div className="flex items-center gap-4">
            <button onClick={onBack} className="md:hidden w-10 h-10 rounded-full flex items-center justify-center bg-gray-50 hover:bg-gray-100 transition-all text-gray-500">
              <span className="material-symbols-outlined text-[20px]">arrow_back_ios_new</span>
            </button>
            <div className="flex flex-col">
              <h2 className="text-[18px] font-black text-gray-900 uppercase tracking-tighter line-clamp-1">{room?.name || 'Room Chat'}</h2>
              <div className="flex items-center gap-1.5">
                <span className="w-1.5 h-1.5 rounded-full bg-green-500" />
                <span className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">{room?.participants ? `${room.participants.length} Members` : 'Live Syncing'}</span>
              </div>
            </div>
          </div>
          <div className="flex items-center gap-2">
            <button 
              onClick={() => setIsGroupMembersOpen(true)}
              className="w-10 h-10 rounded-full flex items-center justify-center bg-gray-50 hover:bg-gray-100 transition-all text-gray-500"
            >
              <span className="material-symbols-outlined text-[20px]">group</span>
            </button>
            <div className="w-10 h-10" />
          </div>
        </div>
      )}

      {/* Messages List */}
      <div 
        ref={scrollRef}
        onScroll={handleScroll}
        className="flex-1 overflow-y-auto p-6 space-y-8 no-scrollbar bg-[#fcfcfc]"
      >
        {messages.map((msg, idx) => {
          const isOwn = msg.senderId === user?.uid;
          const prevTimestamp = messages[idx-1].timestamp?.toDate?.()?.toDateString();
          const currentTimestamp = msg.timestamp?.toDate?.()?.toDateString();
          const showDate = idx === 0 || prevTimestamp !== currentTimestamp;

          return (
            <React.Fragment key={msg.id}>
              {showDate && currentTimestamp && (
                <div className="flex justify-center my-10">
                  <div className="px-5 py-1.5 bg-gray-100/50 rounded-full text-[10px] font-black text-gray-400 uppercase tracking-widest">
                    {msg.timestamp ? (
                      isToday(msg.timestamp.toDate()) ? 'Today' :
                      isYesterday(msg.timestamp.toDate()) ? 'Yesterday' :
                      format(msg.timestamp.toDate(), 'MMMM d, yyyy')
                    ) : 'Today'}
                  </div>
                </div>
              )}

              <div className={`flex flex-col ${isOwn ? 'items-end' : 'items-start'} group max-w-[85%] ${isOwn ? 'ml-auto' : ''}`}>
                {/* Sender Name */}
                {!isOwn && (
                  <span className="text-[10px] font-black text-gray-400 uppercase tracking-tighter mb-2 ml-1">
                    {msg.senderName}
                  </span>
                )}

                <div className={`flex items-end gap-2 ${isOwn ? 'flex-row-reverse' : ''}`}>
                  {/* Bubble */}
                  <div 
                    onClick={() => setMenuMsgId(menuMsgId === msg.id ? null : msg.id)}
                    className={`relative px-5 py-3.5 rounded-3xl text-[14px] font-medium leading-relaxed shadow-sm transition-all duration-300 ${
                      isOwn 
                        ? 'bg-primary text-white rounded-tr-sm' 
                        : 'bg-white border border-gray-100 text-gray-800 rounded-tl-sm hover:border-primary/20'
                    } ${menuMsgId === msg.id ? 'scale-[1.02] shadow-xl' : ''}`}
                  >
                    {/* Reply Context */}
                    {msg.replyTo && (
                      <div className={`mb-3 p-2 rounded-xl text-[11px] border-l-4 ${isOwn ? 'bg-white/10 border-white/30' : 'bg-gray-50 border-primary/30'}`}>
                        <div className="font-black uppercase tracking-tighter mb-0.5 opacity-60">Replied to Message</div>
                        <div className="line-clamp-1 opacity-80">{messages.find(m => m.id === msg.replyTo)?.text || 'Message not found'}</div>
                      </div>
                    )}

                    {msg.type === 'voice' ? (
                      <VoiceBubble url={msg.mediaUrl!} isOwn={isOwn} timestamp={formatTime(msg.timestamp)} />
                    ) : msg.type === 'image' ? (
                      <div className="overflow-hidden rounded-2xl -m-2" onClick={(e) => { e.stopPropagation(); setSelectedMedia({ url: msg.mediaUrl!, type: 'image' }); }}>
                        <img src={msg.mediaUrl} className="max-w-full max-h-[300px] object-cover hover:scale-105 transition-transform duration-500 cursor-zoom-in" />
                      </div>
                    ) : msg.type === 'video' ? (
                      <div className="overflow-hidden rounded-2xl -m-2 relative group cursor-pointer" onClick={(e) => { e.stopPropagation(); setSelectedMedia({ url: msg.mediaUrl!, type: 'video' }); }}>
                        <video src={msg.mediaUrl} className="max-w-full max-h-[300px] object-cover" />
                        <div className="absolute inset-0 bg-black/30 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                          <span className="material-symbols-outlined text-white text-4xl">play_circle</span>
                        </div>
                      </div>
                    ) : (
                      <p>{renderMessageText(msg.text)}</p>
                    )}

                    {/* Reactions */}
                    {msg.reactions && Object.keys(msg.reactions).length > 0 && (
                      <div className="absolute -bottom-3 left-2 flex gap-1">
                        {Object.entries(msg.reactions).map(([uid, emoji]) => (
                          <div key={uid} className="bg-white px-1.5 py-0.5 rounded-full shadow-sm text-[12px] border border-gray-50 animate-in zoom-in">
                            {emoji}
                          </div>
                        ))}
                      </div>
                    )}
                  </div>

                  {/* Meta (Time/Read) */}
                  <div className="flex flex-col gap-0.5 items-center justify-end pb-1">
                    {isOwn && (
                      <span className={`text-[10px] font-bold uppercase shrink-0 ${msg.readBy && msg.readBy.length > 0 ? 'text-primary' : 'text-gray-300'}`}>
                        {msg.readBy && msg.readBy.length > 0 ? 'Read' : 'Sent'}
                      </span>
                    )}
                    <span className="text-[10px] font-bold text-gray-300 uppercase shrink-0">
                      {formatTime(msg.timestamp)}
                    </span>
                  </div>
                </div>

                {/* Message Menu (Context Actions) */}
                <AnimatePresence>
                  {menuMsgId === msg.id && (
                    <motion.div 
                      initial={{ opacity: 0, y: 5 }}
                      animate={{ opacity: 1, y: 0 }}
                      exit={{ opacity: 0, y: 5 }}
                      className={`flex gap-1 mt-3 ${isOwn ? 'justify-end' : 'justify-start'}`}
                    >
                      {REACTION_EMOJIS.map(emoji => (
                        <button 
                          key={emoji}
                          onClick={() => {
                            chatService.toggleReaction(msg.id, user?.uid || '', emoji);
                            setMenuMsgId(null);
                          }}
                          className="w-8 h-8 rounded-full bg-white border border-gray-50 shadow-sm flex items-center justify-center hover:scale-125 transition-all text-[16px]"
                        >
                          {emoji}
                        </button>
                      ))}
                      <div className="w-px h-8 bg-gray-100 mx-1" />
                      <button 
                        onClick={() => { setReplyTo(msg); setMenuMsgId(null); }}
                        className="w-8 h-8 rounded-full bg-white border border-gray-50 shadow-sm flex items-center justify-center hover:bg-primary hover:text-white transition-all text-gray-400"
                      >
                        <span className="material-symbols-outlined text-[16px]">reply</span>
                      </button>
                      {isOwn && (
                        <button 
                          onClick={() => { chatService.updateMessage(msg.id, { isDeleted: true, text: 'Deleted message' }); setMenuMsgId(null); }}
                          className="w-8 h-8 rounded-full bg-white border border-gray-50 shadow-sm flex items-center justify-center hover:bg-red-500 hover:text-white transition-all text-gray-400"
                        >
                          <span className="material-symbols-outlined text-[16px]">delete</span>
                        </button>
                      )}
                    </motion.div>
                  )}
                </AnimatePresence>
              </div>
            </React.Fragment>
          );
        })}
      </div>
      
      {/* Typing Indicator */}
      <AnimatePresence>
        {isOtherTyping && (
          <motion.div 
            initial={{ opacity: 0, y: 10, height: 0 }}
            animate={{ opacity: 1, y: 0, height: 'auto' }}
            exit={{ opacity: 0, y: 10, height: 0 }}
            className="px-6 pb-2 flex items-center gap-2 text-gray-400 text-xs font-medium"
          >
            <div className="flex gap-1">
              <span className="w-1.5 h-1.5 rounded-full bg-gray-400 animate-bounce" style={{ animationDelay: '0ms' }} />
              <span className="w-1.5 h-1.5 rounded-full bg-gray-400 animate-bounce" style={{ animationDelay: '150ms' }} />
              <span className="w-1.5 h-1.5 rounded-full bg-gray-400 animate-bounce" style={{ animationDelay: '300ms' }} />
            </div>
            {otherUser?.displayName || 'Someone'} is typing...
          </motion.div>
        )}
      </AnimatePresence>

      {/* Input Area */}
      <div className="p-6 bg-white border-t border-gray-50 relative z-30">
        {/* Reply Preview */}
        <AnimatePresence>
          {replyTo && (
            <motion.div 
              initial={{ height: 0, opacity: 0 }}
              animate={{ height: 'auto', opacity: 1 }}
              exit={{ height: 0, opacity: 0 }}
              className="bg-gray-50 rounded-2xl mb-4 p-4 flex items-center justify-between border-l-4 border-primary"
            >
              <div className="flex flex-col">
                <span className="text-[10px] font-black text-primary uppercase tracking-widest mb-1">Replying to {replyTo.senderName}</span>
                <p className="text-[13px] font-medium text-gray-500 line-clamp-1">{replyTo.text}</p>
              </div>
              <button 
                onClick={() => setReplyTo(null)}
                className="w-8 h-8 rounded-full flex items-center justify-center hover:bg-gray-200 transition-all text-gray-400"
              >
                <span className="material-symbols-outlined text-[18px]">close</span>
              </button>
            </motion.div>
          )}
        </AnimatePresence>

        <div className="flex items-end gap-1 bg-[#f8f9fa] p-1.5 sm:p-2 rounded-[32px] border border-gray-200/50 focus-within:border-primary/20 focus-within:bg-white transition-all">
          <input 
            type="file" 
            ref={fileInputRef} 
            onChange={handleFileUpload} 
            className="hidden" 
            accept="image/*,video/*"
          />
          <button 
            disabled={isRecording}
            onClick={() => fileInputRef.current?.click()}
            className="w-10 h-10 sm:w-12 sm:h-12 shrink-0 rounded-full flex items-center justify-center text-gray-400 hover:text-primary transition-colors disabled:opacity-20"
          >
            <span className="material-symbols-outlined text-[20px] sm:text-[24px]">add_photo_alternate</span>
          </button>

          <textarea 
            value={inputText}
            onChange={(e) => {
              setInputText(e.target.value);
              if (user && roomId) {
                chatService.setTypingStatus(roomId, user.uid, true);
                if (typingTimeoutRef.current) clearTimeout(typingTimeoutRef.current);
                typingTimeoutRef.current = setTimeout(() => {
                  chatService.setTypingStatus(roomId, user.uid, false);
                }, 2000);
              }
            }}
            disabled={isRecording}
            placeholder={isRecording ? "Recording..." : "Type your message..."}
            rows={1}
            className="flex-1 min-w-0 min-h-[40px] sm:min-h-[48px] max-h-[120px] bg-transparent border-none focus:ring-0 text-[14px] sm:text-[15px] leading-[20px] sm:leading-[24px] font-medium placeholder:text-gray-300 text-gray-900 resize-none py-2.5 sm:py-3 px-1 sm:px-2 no-scrollbar disabled:opacity-50"
            onKeyDown={(e) => {
              if (e.key === 'Enter' && !e.shiftKey) {
                e.preventDefault();
                handleSend();
              }
            }}
          />

          <div className="flex items-center gap-0.5 shrink-0">
            {isRecording ? (
              <div className="flex items-center gap-2 px-2 sm:px-4 animate-in fade-in zoom-in">
                <span className="text-[13px] sm:text-[14px] font-black text-red-500 animate-pulse">{Math.floor(recordDuration/60)}:{(recordDuration%60).toString().padStart(2, '0')}</span>
                <button 
                  onClick={stopRecording}
                  className="w-8 h-8 sm:w-10 sm:h-10 shrink-0 rounded-full bg-red-500 text-white flex items-center justify-center shadow-lg shadow-red-500/30"
                >
                  <span className="material-symbols-outlined text-[18px] sm:text-[20px]">stop</span>
                </button>
              </div>
            ) : (
              <>
                <button 
                  onClick={startRecording}
                  className="w-10 h-10 sm:w-12 sm:h-12 shrink-0 rounded-full flex items-center justify-center text-gray-400 hover:text-primary transition-colors"
                >
                  <span className="material-symbols-outlined text-[20px] sm:text-[24px]">mic</span>
                </button>
                <button 
                  onClick={handleSend}
                  disabled={!inputText.trim()}
                  className={`w-10 h-10 sm:w-12 sm:h-12 shrink-0 rounded-full flex items-center justify-center transition-all ${
                    inputText.trim() ? 'bg-primary text-white shadow-lg shadow-primary/30' : 'bg-gray-100 text-gray-300'
                  }`}
                >
                  <span className="material-symbols-outlined text-[18px] sm:text-[22px]">send</span>
                </button>
              </>
            )}
          </div>
        </div>

        {/* Upload Status */}
        <AnimatePresence>
          {isUploading && (
            <motion.div 
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, y: 20 }}
              className="absolute -top-12 left-1/2 -translate-x-1/2 bg-white px-6 py-2 rounded-full shadow-2xl border border-gray-50 flex items-center gap-3"
            >
              <div className="w-4 h-4 rounded-full border-2 border-primary border-t-transparent animate-spin" />
              <span className="text-[12px] font-black text-gray-800 uppercase tracking-widest">
                Uploading {uploadProgress}%
              </span>
            </motion.div>
          )}
        </AnimatePresence>
      </div>

      <AnimatePresence>
        {isGroupMembersOpen && (
          <GroupMembersPopup
            roomId={roomId}
            onClose={() => setIsGroupMembersOpen(false)}
          />
        )}
      </AnimatePresence>

      {/* Media Fullscreen Viewer */}
      <AnimatePresence>
        {selectedMedia && (
          <motion.div 
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 z-[100] bg-black/95 backdrop-blur-md flex items-center justify-center"
            onClick={() => setSelectedMedia(null)}
          >
            <button 
              className="absolute top-6 right-6 w-12 h-12 rounded-full bg-white/10 text-white flex items-center justify-center hover:bg-white/20 transition-colors z-[110]"
              onClick={(e) => { e.stopPropagation(); setSelectedMedia(null); }}
            >
              <span className="material-symbols-outlined text-2xl">close</span>
            </button>
            <motion.div 
              initial={{ scale: 0.9, opacity: 0 }}
              animate={{ scale: 1, opacity: 1 }}
              exit={{ scale: 0.9, opacity: 0 }}
              transition={{ type: "spring", damping: 25, stiffness: 300 }}
              className="max-w-[90vw] max-h-[90vh] relative"
              onClick={(e) => e.stopPropagation()}
            >
              {selectedMedia.type === 'image' ? (
                <img src={selectedMedia.url} className="max-w-full max-h-[90vh] object-contain rounded-xl shadow-2xl" />
              ) : (
                <video src={selectedMedia.url} controls autoPlay className="max-w-full max-h-[90vh] rounded-xl shadow-2xl" />
              )}
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { doc, getDoc } from 'firebase/firestore';
import { db } from '@/lib/firebase/config';

interface GroupMembersPopupProps {
  roomId: string;
  onClose: () => void;
}

export default function GroupMembersPopup({ roomId, onClose }: GroupMembersPopupProps) {
  const [members, setMembers] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [room, setRoom] = useState<any>(null);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const roomDoc = await getDoc(doc(db, 'chat_rooms', roomId));
        if (roomDoc.exists()) {
          const roomData = roomDoc.data();
          setRoom(roomData);

          const memberPromises = (roomData.participants || []).map(async (uid: string) => {
            const userDoc = await getDoc(doc(db, 'users', uid));
            if (userDoc.exists()) {
              return { id: uid, ...userDoc.data() };
            }
            return { id: uid, nickname: 'Unknown' };
          });

          const membersData = await Promise.all(memberPromises);
          setMembers(membersData);
        }
      } catch (err) {
        console.error(err);
      } finally {
        setLoading(false);
      }
    };

    fetchData();
  }, [roomId]);

  return (
    <div className="fixed inset-0 z-[10000] bg-[#f9f9ff] text-[#191b22] flex flex-col items-center overflow-y-auto">
      {/* TopAppBar */}
      <header className="bg-white/80 dark:bg-slate-950/80 backdrop-blur-xl docked full-width top-0 z-50 border-b border-slate-100 dark:border-slate-800 shadow-sm flex justify-between items-center w-full px-4 h-16 max-w-[896px] mx-auto fixed">
        <button 
          onClick={onClose}
          className="text-blue-600 dark:text-blue-400 hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors active:scale-95 transition-transform p-2 rounded-full flex items-center justify-center"
        >
          <span className="material-symbols-outlined">arrow_back</span>
        </button>
        <h1 className="font-['Plus_Jakarta_Sans'] font-bold text-lg text-slate-900 dark:text-slate-50">Group Members</h1>
        {/* Removed more_vert icon to balance header spacing */}
        <div className="w-10 h-10" />
      </header>

      <main className="w-full max-w-[896px] mt-16 px-6 py-8 flex flex-col space-y-10">
        {/* Invite Section */}
        <section>
          <button className="w-full flex items-center justify-center space-x-3 bg-[#0057bd] text-[#c2d3ff] rounded-xl p-4 shadow-sm hover:shadow-md hover:bg-[#0b5ac0] active:scale-95 transition-all duration-200">
            <span className="material-symbols-outlined">person_add</span>
            <span className="font-['Plus_Jakarta_Sans'] font-bold text-[1.125rem] leading-[1.5rem]">Invite New Member</span>
          </button>
        </section>

        {/* Member List */}
        <section className="flex flex-col space-y-2">
          {loading ? (
            <div className="animate-pulse flex flex-col gap-2">
              {[1, 2, 3].map(i => (
                <div key={i} className="flex items-center space-x-4 p-4 bg-white rounded-lg">
                  <div className="w-12 h-12 bg-gray-200 rounded-full"></div>
                  <div className="flex-1 space-y-2">
                    <div className="h-4 bg-gray-200 rounded w-1/3"></div>
                    <div className="h-3 bg-gray-200 rounded w-1/4"></div>
                  </div>
                </div>
              ))}
            </div>
          ) : (
            <>
              <h2 className="font-['Inter'] font-semibold text-[0.75rem] leading-[1rem] text-[#424753] uppercase tracking-wider mb-2">
                {members.length} Members
              </h2>

              {members.map(member => {
                const isOwner = room?.createdBy === member.id;
                const displayName = member.nickname || member.nativeNickname || member.displayName || 'Unknown';

                return (
                  <div key={member.id} className="flex items-center justify-between p-4 bg-[#ffffff] rounded-lg shadow-sm hover:shadow-md hover:outline-[#c2c6d5] hover:outline transition-all group">
                    <div className="flex items-center space-x-4">
                      {member.photoURL ? (
                        <img 
                          alt="Avatar" 
                          className="w-12 h-12 rounded-full object-cover" 
                          src={member.photoURL} 
                        />
                      ) : (
                        <div className="w-12 h-12 rounded-full bg-blue-100 text-blue-600 flex items-center justify-center font-bold text-lg">
                          {displayName[0]?.toUpperCase()}
                        </div>
                      )}
                      <div className="flex flex-col">
                        <span className="font-['Inter'] font-medium text-[0.875rem] leading-[1.25rem] text-[#191b22]">{displayName}</span>
                        {isOwner ? (
                          <span className="font-['Inter'] font-bold text-[10px] leading-[1rem] text-[#004190] bg-[#d8e2ff] px-2 py-0.5 rounded-full mt-1 w-max">Owner</span>
                        ) : (
                          <span className="font-['Inter'] font-bold text-[10px] leading-[1rem] text-[#424753] bg-[#e1e2eb] px-2 py-0.5 rounded-full mt-1 w-max">Member</span>
                        )}
                      </div>
                    </div>
                  </div>
                );
              })}
            </>
          )}
        </section>
      </main>
    </div>
  );
}

'use client';

import React, { useState } from 'react';
import { GroupClass } from '@/types/group';
import { toast } from 'sonner';
import { useAuth } from '@/components/providers/AuthProvider';
import { classRegistrationService } from '@/lib/firebase/classRegistrationService';

interface ClassCheckoutModalProps {
  isOpen: boolean;
  onClose: () => void;
  cls: (GroupClass & { groupId: string; groupName: string }) | null;
}

const ClassCheckoutModal: React.FC<ClassCheckoutModalProps> = ({ isOpen, onClose, cls }) => {
  const [loading, setLoading] = useState(false);
  const [role, setRole] = useState<'Leader' | 'Follower' | 'Solo'>('Solo');
  const { user, profile } = useAuth();

  if (!isOpen || !cls) return null;

  const handleRegister = async () => {
    if (!user || !profile) {
      toast.error("로그인이 필요합니다.");
      return;
    }

    setLoading(true);
    try {
      await classRegistrationService.addRegistration({
        classId: cls.id,
        groupId: cls.groupId,
        userId: user.uid,
        classTitle: cls.title,
        applicantName: profile.nickname || profile.nativeNickname || '이름 없음',
        userAvatar: profile.photoURL || undefined,
        role: role === 'Solo' ? undefined : role,
        status: 'PAYMENT_PENDING',
        amount: cls.amount || 0,
        currency: cls.currency || 'KRW',
        itemType: 'class',
        groupName: cls.groupName,
        contactNumber: profile.phoneNumber || undefined,
      });

      toast.success("클래스 신청이 완료되었습니다!");
      onClose();
    } catch (error) {
      console.error("클래스 신청 오류:", error);
      toast.error("클래스 신청에 실패했습니다.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="fixed inset-0 z-[300] bg-black/60 backdrop-blur-sm flex items-end sm:items-center justify-center animate-in fade-in duration-200">
      <div className="bg-surface w-full max-w-md sm:rounded-2xl rounded-t-3xl shadow-2xl flex flex-col max-h-[90vh] animate-in slide-in-from-bottom-8 duration-300">

        {/* Header */}
        <div className="flex items-center justify-between p-6 border-b border-outline/10">
          <h2 className="font-headline font-extrabold text-xl text-on-surface">클래스 신청</h2>
          <button onClick={onClose} className="p-2 rounded-full hover:bg-surface-variant text-on-surface-variant transition-colors">
            <span className="material-symbols-outlined">close</span>
          </button>
        </div>

        {/* Content */}
        <div className="p-6 overflow-y-auto custom-scrollbar flex-1 space-y-6">
          {/* Class Summary */}
          <div className="flex gap-4">
            <div className="w-20 h-20 rounded-xl overflow-hidden shrink-0 bg-surface-variant">
              {(cls.imageUrl || (cls as any).image) ? (
                <img src={cls.imageUrl || (cls as any).image} alt={cls.title} className="w-full h-full object-cover" />
              ) : (
                <div className="w-full h-full flex items-center justify-center">
                  <span className="material-symbols-outlined text-outline/50 text-2xl">image</span>
                </div>
              )}
            </div>
            <div>
              <p className="text-xs font-bold text-primary mb-1">{cls.groupName}</p>
              <h3 className="font-headline font-bold text-base leading-tight mb-2 text-on-surface">{cls.title}</h3>
              <p className="text-xs text-on-surface-variant flex items-center gap-1">
                <span className="material-symbols-outlined text-[14px]">calendar_month</span>
                {cls.schedule?.[0]?.date || 'TBA'} {cls.schedule?.[0]?.timeSlot || ''}
              </p>
            </div>
          </div>

          {/* Registration Options */}
          <div>
            <h4 className="font-bold text-sm text-on-surface mb-3">역할 선택 (Role)</h4>
            <div className="grid grid-cols-3 gap-2">
              {['Leader', 'Follower', 'Solo'].map(r => (
                <button
                  key={r}
                  onClick={() => setRole(r as any)}
                  className={`py-3 rounded-xl border font-bold text-sm transition-all ${role === r ? 'border-primary bg-primary/10 text-primary' : 'border-outline/20 text-on-surface-variant hover:bg-surface-variant/50'}`}
                >
                  {r}
                </button>
              ))}
            </div>
          </div>

          {/* Payment Info */}
          <div className="bg-surface-container-lowest border border-outline/20 rounded-xl p-4 space-y-3">
            <h4 className="font-bold text-sm text-on-surface border-b border-outline/10 pb-2">결제 정보</h4>
            <div className="flex justify-between text-sm">
              <span className="text-on-surface-variant">상품 금액</span>
              <span className="font-medium text-on-surface">{(cls.amount || 0).toLocaleString()} {cls.currency || 'KRW'}</span>
            </div>
            <div className="flex justify-between text-sm">
              <span className="text-on-surface-variant">할인 금액</span>
              <span className="font-medium text-rose-500">- 0 {cls.currency || 'KRW'}</span>
            </div>
            <div className="flex justify-between items-end pt-2 border-t border-outline/10">
              <span className="font-bold text-on-surface">총 결제 금액</span>
              <span className="font-headline font-black text-xl text-primary">{(cls.amount || 0).toLocaleString()} {cls.currency || 'KRW'}</span>
            </div>
          </div>
        </div>

        {/* Footer Actions */}
        <div className="p-6 border-t border-outline/10 bg-surface">
          <button
            onClick={handleRegister}
            disabled={loading}
            className="w-full bg-primary text-on-primary font-bold py-4 rounded-xl shadow-md hover:shadow-lg transition-all flex justify-center items-center gap-2 disabled:opacity-50"
          >
            {loading && <span className="material-symbols-outlined animate-spin text-sm">progress_activity</span>}
            결제 및 신청하기
          </button>
        </div>

      </div>
    </div>
  );
};

export default ClassCheckoutModal;

