import React, { useState, useEffect, useMemo } from 'react';
import { classRegistrationService } from '@/lib/firebase/classRegistrationService';
import { ClassRegistration, Group } from '@/types/group';
import { format, addMonths, subMonths, isSameMonth } from 'date-fns';

interface GroupClassRegistrationsProps {
  group: Group;
  currentMonth: Date;
}

export function GroupClassRegistrations({ group, currentMonth }: GroupClassRegistrationsProps) {
  const [registrations, setRegistrations] = useState<ClassRegistration[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    if (!group?.id) return;

    setIsLoading(true);
    const unsubscribe = classRegistrationService.subscribeToGroupRegistrations(group.id, (data) => {
      setRegistrations(data);
      setIsLoading(false);
    });

    return () => unsubscribe();
  }, [group?.id]);

  // Filter and group registrations
  const groupedRegistrations = useMemo(() => {
    // 1. Filter by current month
    const filtered = registrations.filter(reg => {
      if (!reg.appliedAt) return false;
      // Convert Firestore Timestamp or Date or string to Date
      const date = reg.appliedAt?.toDate ? reg.appliedAt.toDate() : new Date(reg.appliedAt);
      return isSameMonth(date, currentMonth);
    });

    // 2. Group by user
    const grouped = new Map<string, {
      userId: string;
      applicantName: string;
      userAvatar: string;
      joinedAt: Date | null; // We might not have joinedAt in registration, but we can fake it or find from group.members
      items: ClassRegistration[];
    }>();

    filtered.forEach(reg => {
      // Use userId as key, or applicantName + contactNumber if no userId
      const key = reg.userId || `${reg.applicantName}-${reg.contactNumber}`;

      if (!grouped.has(key)) {
        // Try to find member in group to get 'joinedAt'
        const member = group.members?.find(m => m.id === reg.userId);
        let joinedAtDate = null;
        if (member?.joinedAt) {
           joinedAtDate = member.joinedAt?.toDate ? member.joinedAt.toDate() : new Date(member.joinedAt);
        }

        grouped.set(key, {
          userId: reg.userId,
          applicantName: reg.applicantName || 'Unknown User',
          userAvatar: reg.userAvatar || member?.avatar || '',
          joinedAt: joinedAtDate,
          items: []
        });
      }
      grouped.get(key)!.items.push(reg);
    });

    return Array.from(grouped.values());
  }, [registrations, currentMonth, group.members]);

  const getItemTypeDetails = (type?: string) => {
    switch (type) {
      case 'discount':
        return { label: 'BUNDLE', bgClass: 'bg-secondary-container text-on-secondary-container' };
      case 'monthlyPass':
        return { label: 'PASS', bgClass: 'bg-tertiary-container text-on-tertiary-container' };
      case 'class':
      default:
        return { label: 'CLASS', bgClass: 'bg-primary-container text-on-primary-container' };
    }
  };

  return (
    <div className="w-full">
      {/* Registration List */}
            {isLoading ? (
              <div className="flex justify-center items-center py-12">
                <span className="material-symbols-outlined animate-spin text-primary text-4xl">sync</span>
              </div>
            ) : groupedRegistrations.length === 0 ? (
              <div className="text-center py-12 bg-surface-container-lowest rounded-xl border border-outline-variant/20">
                <span className="material-symbols-outlined text-4xl text-outline mb-2">inbox</span>
                <p className="text-on-surface-variant">No registrations found for this month.</p>
              </div>
            ) : (
              <div className="space-y-4">
                {groupedRegistrations.map((userGroup, idx) => (
                  <div key={userGroup.userId || idx} className="bg-surface-container-lowest rounded-xl p-5 shadow-sm border border-outline-variant/20 hover:shadow-md transition-shadow duration-300">
                    <div className="flex items-center gap-4 mb-4">
                      {userGroup.userAvatar ? (
                        <img 
                          src={userGroup.userAvatar} 
                          alt={userGroup.applicantName} 
                          className="w-12 h-12 rounded-full object-cover ring-2 ring-primary-container/20" 
                        />
                      ) : (
                        <div className="w-12 h-12 rounded-full bg-surface-container flex items-center justify-center ring-2 ring-primary-container/20">
                          <span className="material-symbols-outlined text-outline">person</span>
                        </div>
                      )}
                      <div>
                        <h3 className="font-title-md text-title-md text-on-surface">{userGroup.applicantName}</h3>
                        <p className="font-label-sm text-label-sm text-on-surface-variant">
                          Member since {userGroup.joinedAt ? format(userGroup.joinedAt, 'MMM yyyy') : 'Unknown'}
                        </p>
                      </div>
                    </div>

                    <div className="bg-surface-container-low rounded-lg p-2 space-y-1">
                      {userGroup.items.map(item => {
                        const typeInfo = getItemTypeDetails(item.itemType);
                        const appliedDate = item.appliedAt?.toDate ? item.appliedAt.toDate() : new Date(item.appliedAt || Date.now());

                        return (
                          <div key={item.id} className="flex items-center justify-between p-2 rounded hover:bg-surface-variant/50 transition-colors">
                            <div className="flex items-center gap-3">
                              <span className={`px-2 py-0.5 rounded text-[10px] font-bold tracking-wide ${typeInfo.bgClass}`}>
                                {typeInfo.label}
                              </span>
                              <span className="font-body-md text-sm text-on-surface font-semibold">
                                {item.classTitle}
                              </span>
                            </div>
                            <span className="font-label-sm text-xs text-on-surface-variant">
                              {format(appliedDate, 'MMM dd, hh:mm a')}
                            </span>
                          </div>
                        );
                      })}
                    </div>
                  </div>
                ))}
              </div>
            )}
    </div>
  );
}

