// ─────────────────────────────────────────────
// Class Manager Panel (Firestore 실시간 바인딩)
// ─────────────────────────────────────────────
type ManagerTab = 'todo' | 'register' | 'stats';

function getBadgeStyle(itemType?: string): { cls: string; label: string } {
  switch (itemType) {
    case 'monthlyPass': return { cls: 'bg-surface-container-highest text-on-surface', label: 'MONTHLY PASS' };
    case 'discount':    return { cls: 'bg-secondary-container text-on-secondary-container', label: 'BUNDLE' };
    default:            return { cls: 'bg-tertiary-container text-on-tertiary-container', label: 'CLASS' };
  }
}

function ClassManagerPanel({ group }: { group: Group }) {
  const [activeManagerTab, setActiveManagerTab] = useState<ManagerTab>('todo');
  const [currentMonth, setCurrentMonth] = useState(new Date());
  const [pendingList, setPendingList] = useState<ClassRegistration[]>([]);
  const [loadingRegs, setLoadingRegs] = useState(true);
  const [confirmingId, setConfirmingId] = useState<string | null>(null);

  const monthLabel = currentMonth.toLocaleString('en-US', { month: 'long', year: 'numeric' });
  const prevMonth = () => setCurrentMonth(d => new Date(d.getFullYear(), d.getMonth() - 1, 1));
  const nextMonth = () => setCurrentMonth(d => new Date(d.getFullYear(), d.getMonth() + 1, 1));

  // Firestore 실시간 구독 — PAYMENT_REPORTED 전체 (월 무관)
  useEffect(() => {
    if (!group.id) return;
    setLoadingRegs(true);
    const unsub = classRegistrationService.subscribeToGroupRegistrations(
      group.id,
      (registrations) => {
        const pending = registrations
          .filter(r => r.status === 'PAYMENT_REPORTED')
          .sort((a, b) => {
            const tA = a.appliedAt?.toMillis?.() ?? 0;
            const tB = b.appliedAt?.toMillis?.() ?? 0;
            return tA - tB; // 신청일 오름차순
          });
        setPendingList(pending);
        setLoadingRegs(false);
      }
    );
    return () => unsub();
  }, [group.id]);

  const handleConfirm = async (reg: ClassRegistration) => {
    setConfirmingId(reg.id);
    try {
      await classRegistrationService.updateRegistration(reg.id, {
        status: 'PAYMENT_COMPLETED',
      });
      toast.success(`${reg.applicantName} 입금 확인 처리되었습니다.`);
    } catch (e) {
      toast.error('처리 중 오류가 발생했습니다.');
    } finally {
      setConfirmingId(null);
    }
  };

  // Register / Stats 탭에서 사용할 월별 필터
  const monthStart = new Date(currentMonth.getFullYear(), currentMonth.getMonth(), 1).getTime();
  const monthEnd   = new Date(currentMonth.getFullYear(), currentMonth.getMonth() + 1, 0, 23, 59, 59).getTime();

  return (
    <div className="animate-in fade-in slide-in-from-bottom-4 duration-500 p-page-margin max-w-container-max mx-auto w-full">
      {/* Main Tab Menu */}
      <div className="mb-6 flex justify-center sm:justify-start">
        <div className="bg-surface-container-high rounded-lg p-1 inline-flex gap-1 shadow-inner">
          {(['todo', 'register', 'stats'] as ManagerTab[]).map((tab) => (
            <button
              key={tab}
              onClick={() => setActiveManagerTab(tab)}
              className={`px-6 py-2 rounded-md font-body-md text-body-md transition-all font-semibold capitalize ${
                activeManagerTab === tab
                  ? 'bg-primary text-on-primary shadow-sm'
                  : 'text-on-surface-variant hover:bg-surface-container-highest hover:text-on-surface'
              }`}
            >
              {tab === 'todo'
                ? `Todo${pendingList.length > 0 ? ` (${pendingList.length})` : ''}`
                : tab.charAt(0).toUpperCase() + tab.slice(1)}
            </button>
          ))}
        </div>
      </div>

      {/* Calendar Navigation — Todo 탭에서는 숨김 */}
      {activeManagerTab !== 'todo' && (
        <div className="mb-6 flex items-center justify-center">
          <div className="bg-surface-container-lowest rounded-xl shadow-sm border border-outline-variant px-4 py-2 flex items-center gap-4">
            <button
              onClick={prevMonth}
              className="text-on-surface-variant hover:text-primary transition-colors p-1 rounded-full hover:bg-surface-container-low"
            >
              <span className="material-symbols-outlined text-lg">chevron_left</span>
            </button>
            <span className="font-title-md text-title-md text-on-surface">{monthLabel}</span>
            <button
              onClick={nextMonth}
              className="text-on-surface-variant hover:text-primary transition-colors p-1 rounded-full hover:bg-surface-container-low"
            >
              <span className="material-symbols-outlined text-lg">chevron_right</span>
            </button>
          </div>
        </div>
      )}

      {/* ── TODO 탭: 입금확인대기 목록 ── */}
      {activeManagerTab === 'todo' && (
        <div className="flex flex-col gap-3">
          {loadingRegs ? (
            /* 로딩 스켈레톤 */
            [1, 2, 3].map(i => (
              <div key={i} className="bg-surface-container-lowest rounded-xl shadow-sm border border-transparent p-3 sm:px-5 flex items-center gap-4 animate-pulse">
                <div className="w-8 h-8 rounded-full bg-surface-container shrink-0" />
                <div className="flex-1 flex flex-col gap-2">
                  <div className="h-4 bg-surface-container rounded w-1/3" />
                  <div className="h-3 bg-surface-container-low rounded w-1/4" />
                </div>
                <div className="h-9 w-24 bg-surface-container rounded-lg" />
              </div>
            ))
          ) : pendingList.length === 0 ? (
            /* 빈 상태 */
            <div className="flex flex-col items-center justify-center py-16 gap-3 text-on-surface-variant">
              <span className="material-symbols-outlined text-5xl opacity-30">inbox</span>
              <p className="font-body-md text-[14px]">입금 확인 대기 중인 신청이 없습니다.</p>
            </div>
          ) : (
            pendingList.map((reg) => {
              const badge = getBadgeStyle(reg.itemType);
              const appliedDate = reg.appliedAt?.toDate
                ? reg.appliedAt.toDate().toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' })
                : reg.depositDate ?? '';
              const isConfirming = confirmingId === reg.id;
              return (
                <div
                  key={reg.id}
                  className="bg-surface-container-lowest rounded-xl shadow-sm border border-transparent hover:border-outline-variant transition-all duration-200 p-3 sm:px-5 flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4 group"
                >
                  <div className="flex items-center gap-3 sm:min-w-[200px]">
                    {reg.userAvatar ? (
                      <img alt={reg.applicantName} className="w-8 h-8 rounded-full object-cover shrink-0" src={reg.userAvatar} />
                    ) : (
                      <div className="w-8 h-8 rounded-full bg-surface-container flex items-center justify-center shrink-0">
                        <span className="material-symbols-outlined text-[18px] text-on-surface-variant">person</span>
                      </div>
                    )}
                    <div className="flex flex-col">
                      <span className="font-title-md text-[15px] leading-tight text-on-surface font-bold">{reg.applicantName}</span>
                      <span className="font-body-md text-[12px] text-on-surface-variant">{appliedDate}</span>
                      {reg.depositorName && (
                        <span className="font-body-md text-[11px] text-on-surface-variant/70">입금자: {reg.depositorName}</span>
                      )}
                    </div>
                  </div>
                  <div className="flex-1 flex flex-row items-center gap-3">
                    <span className="font-body-md text-[14px] text-on-surface font-medium truncate">{reg.classTitle}</span>
                    <div className={`${badge.cls} px-2 py-0.5 rounded text-[10px] font-bold uppercase tracking-wider inline-block shrink-0`}>
                      {badge.label}
                    </div>
                  </div>
                  <button
                    disabled={isConfirming}
                    onClick={() => handleConfirm(reg)}
                    className="w-full sm:w-auto px-4 py-2 bg-primary hover:bg-on-primary-fixed-variant disabled:opacity-50 text-on-primary rounded-lg font-body-md text-[13px] font-semibold transition-colors flex items-center justify-center gap-1.5 shadow-sm shrink-0"
                  >
                    {isConfirming ? (
                      <span className="material-symbols-outlined text-[16px] animate-spin">progress_activity</span>
                    ) : (
                      <>
                        Confirm
                        <span className="material-symbols-outlined text-[16px]">check_circle</span>
                      </>
                    )}
                  </button>
                </div>
              );
            })
          )}
        </div>
      )}

      {/* ── REGISTER 탭 ── */}
      {activeManagerTab === 'register' && (
        <GroupClassRegistrations group={group} currentMonth={currentMonth} />
      )}

      {/* ── STATS 탭 ── */}
      {activeManagerTab === 'stats' && (
        <GroupClassStats group={group} currentMonth={currentMonth} />
      )}
    </div>
  );
}

export default function GroupHome({ group, isModal }: { group: Group, isModal?: boolean }) {
  const router = useRouter();
  const { user, profile } = useAuth();
  const [isJoining, setIsJoining] = useState(false);
  const [activeTab, setActiveTab] = useState<TabType>('home');
  const [showJoinModal, setShowJoinModal] = useState(false);
  const [memberStatus, setMemberStatus] = useState<'active' | 'pending' | 'rejected' | 'none'>('none');
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [isExiting, setIsExiting] = useState(false);
  const [selectedAdminIndex, setSelectedAdminIndex] = useState(0);
  const [isAdminDropdownOpen, setIsAdminDropdownOpen] = useState(false);

  const handleExit = () => {
    router.push('/groups');
  };

  // 데이터 바인딩용 상태
  const [members, setMembers] = useState<Member[]>([]);
  const [noticePost, setNoticePost] = useState<Post | null>(null);
  const [moments, setMoments] = useState<Post[]>([]);
  const [upcomingEvents, setUpcomingEvents] = useState<any[]>([]);

  const { isLoaded } = useJsApiLoader({
    id: 'google-map-script',
    googleMapsApiKey: process.env.NEXT_PUBLIC_GOOGLE_MAPS_API_KEY || "",
    libraries: ["places"]
  });

  // 실시간 멤버 상태 확인
  useEffect(() => {
    if (!user || !group.id) {
      setMemberStatus('none');
      return;
    }

    const unsubscribe = groupService.subscribeMembers(group.id, (fetchedMembers) => {
      setMembers(fetchedMembers);
      const myMemberInfo = fetchedMembers.find(m => m.id === user.uid);
      if (myMemberInfo) {
        setMemberStatus(myMemberInfo.status || 'active');
      } else {
        setMemberStatus('none');
      }
    });

    return () => unsubscribe();
  }, [user, group.id]);

  // 대시보드 데이터 연동
  useEffect(() => {
    if (!group.id) return;

    const unsubscribePosts = groupService.subscribePosts(group.id, (posts) => {
      const notice = posts.find(p => p.category?.toLowerCase() === 'notice') || posts[0] || null;
      setNoticePost(notice);

      const momentsPosts = posts.filter(p => !!p.image).slice(0, 5);
      setMoments(momentsPosts);
    });

    const unsubscribeEvents = groupService.subscribeCalendarEvents(group.id, (events) => {
      const today = new Date();
      today.setHours(0, 0, 0, 0);

      const upcoming = events
        .filter(e => {
          const startTime = typeof e.startDate === 'number' ? e.startDate : new Date(e.startDate || 0).getTime();
          return startTime >= today.getTime();
        })
        .sort((a, b) => {
          const timeA = typeof a.startDate === 'number' ? a.startDate : new Date(a.startDate || 0).getTime();
          const timeB = typeof b.startDate === 'number' ? b.startDate : new Date(b.startDate || 0).getTime();
          return timeA - timeB;
        })
        .slice(0, 3);
      setUpcomingEvents(upcoming);
    });

    return () => {
      unsubscribePosts();
      unsubscribeEvents();
    };
  }, [group.id]);

  const genderStats = React.useMemo(() => {
    let male = 0;
    let female = 0;
    members.forEach((m: any) => {
      if (m.gender === 'male' || m.gender === 'M') male++;
      else if (m.gender === 'female' || m.gender === 'F') female++;
    });
    const total = male + female;
    if (total === 0) return { male: 45, female: 55 }; // 기본 비율 (데이터 없을 시)
    return {
      male: Math.round((male / total) * 100),
      female: Math.round((female / total) * 100)
    };
  }, [members]);

  const isFullMember = memberStatus === 'active';

  // Profile Setting completion states
  const profileCompleted = !!(group.name && group.coverImage);
  const membershipCompleted = !!group.membershipPolicy;
  const contactCompleted = !!(group.address || group.representative);
  const galleryCompleted = !!(group.gallery && group.gallery.length > 0);
  const boardCompleted = !!(group.boards && group.boards.length > 0);
  const settingsCompletedCount = [profileCompleted, membershipCompleted, contactCompleted, galleryCompleted, boardCompleted].filter(Boolean).length;
  const settingsProgressPercent = Math.round((settingsCompletedCount / 5) * 100);
  const canGoLive = settingsProgressPercent >= 30 || !!(group.coverImage && group.description);
  const [isPublishing, setIsPublishing] = useState(false);

  const [isClaiming, setIsClaiming] = useState(false);
  const isOwner = group.ownerId && user && group.ownerId === user.uid;
  const isLocked = group.isPublished === false && !isOwner;

  const admins = React.useMemo(() => {
    const adminMembers = members.filter(m => m.role === 'admin' || m.id === group.ownerId);
    if (adminMembers.length > 0) return adminMembers;
    if (group.representative) {
      return [{ id: 'rep', name: group.representative.name, avatar: group.representative.avatar, role: 'admin' }];
    }
    return [{ id: 'admin', name: 'Admin', avatar: '', role: 'admin' }];
  }, [members, group.ownerId, group.representative]);

  const currentAdmin = admins[selectedAdminIndex] || admins[0];

  const handleClaimAdmin = async () => {
    if (!user) {
      toast.error("로그인이 필요한 서비스입니다.", { description: "가입 요청 팝업으로 이동합니다.", duration: 3000 });
      setTimeout(() => setShowJoinModal(true), 1000);
      return;
    }

    setIsClaiming(true);
    try {
      const memberData = {
        name: profile?.nickname || user.displayName || 'Admin',
        avatar: profile?.photoURL || user.photoURL || '',
      };

      await groupService.claimGroupAdmin(group.id, user.uid, memberData);
      toast.success("어드민 권한을 획득했습니다!", { description: "그룹 세팅을 시작해 주세요." });

      // Auto reload to refresh server component / permissions
      window.location.reload();
    } catch (error) {
      console.error("Error claiming admin:", error);
      toast.error("어드민 권한 획득 중 오류가 발생했습니다.");
    } finally {
      setIsClaiming(false);
    }
  };

  const handleJoinAction = async () => {
    if (!user) {
      toast.error("로그인이 필요한 서비스입니다.");
      return;
    }

    const strategy = group.membershipPolicy?.joinStrategy || 'open';

    if (strategy === 'invite') {
      setShowJoinModal(true);
      return;
    }

    setIsJoining(true);
    try {
      const memberData = {
        name: profile?.nickname || 'Anonymous',
        avatar: profile?.photoURL || '',
        role: 'member',
        joinedAt: Date.now()
      };

      if (strategy === 'open') {
        await groupService.joinGroup(group.id, user.uid, memberData);
        setShowJoinModal(true); // "환영합니다" 팝업
      } else if (strategy === 'approval') {
        await groupService.requestJoinGroup(group.id, user.uid, memberData);
        setShowJoinModal(true); // "신청 완료" 팝업
      }
    } catch (error) {
      console.error("Error joining group:", error);
      toast.error("가입 처리 중 오류가 발생했습니다.");
    } finally {
      setIsJoining(false);
    }
  };

  const handleTabClick = (tab: TabType) => {
    // 메인(home)과 인포(info)는 누구나 접근 가능
    if (tab === 'home' || tab === 'info') {
      setActiveTab(tab);
      return;
    }

    // 그 외 메뉴는 정회원만 가능
    if (!isFullMember) {
      toast.error("가입 멤버만 이용 가능한 메뉴입니다.", {
        description: "가입 요청 팝업으로 이동합니다.",
        duration: 3000,
      });
      setTimeout(() => {
        setShowJoinModal(true);
      }, 1000);
      return;
    }

    if (tab === 'class' || tab === 'class-manager') {
      const isAdminUser = admins.some(a => a.id === user?.uid) || group.ownerId === user?.uid;
      if (!isAdminUser) {
        toast.error("클래스 관리는 관리자 전용 메뉴입니다.", { duration: 3000 });
        return;
      }
      setActiveTab(tab);
      return;
    }

    if (tab === 'board') {
      setActiveTab('board');
      return;
    }

    setActiveTab(tab);
  };

  const handleMenuClick = (tab: TabType) => {
    handleTabClick(tab);
    setIsMenuOpen(false);
  };

  const handleGoLive = async () => {
    if (!canGoLive || isPublishing) return;
    setIsPublishing(true);
    try {
      await groupService.publishGroup(group.id);
      toast.success("Group is now live!");
      // Optionally router.push to the main platform directory or refresh
      router.push('/groups');
    } catch (error) {
      console.error("Error publishing group:", error);
      toast.error("Failed to publish the group.");
    } finally {
      setIsPublishing(false);
    }
  };

  return (
    <div className="bg-[#F1F5F9] text-[#242c51] min-h-screen font-body relative pb-24">
      <style jsx global>{`
        @import url('https://fonts.googleapis.com/css2?family=Plus+Jakarta+Sans:wght@400;500;700;800&family=Inter:wght@400;500;600;700&display=swap');

        .font-headline { font-family: 'Plus Jakarta Sans', sans-serif; }
        .font-body { font-family: 'Inter', sans-serif; }

        .bg-blur-primary {
            background-image: radial-gradient(circle at top left, rgba(59, 130, 246, 0.08), transparent 45%);
        }

        .bg-blur-tertiary {
            background-image: radial-gradient(circle at bottom right, rgba(137, 60, 146, 0.08), transparent 45%);
        }

        .hide-scrollbar::-webkit-scrollbar {
