export default function PostDetailModal({ groupId, post, isOpen, onClose, onEdit }: PostDetailModalProps) {
  const { user, profile, setShowLogin } = useAuth();
  const [comments, setComments] = useState<Comment[]>([]);
  const [newComment, setNewComment] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);

  useEffect(() => {
    if (!isOpen || !post) return;

    const unsubscribe = groupService.subscribeComments(groupId, post.id, (fetchedComments) => {
      setComments(fetchedComments as Comment[]);
    });

    return () => unsubscribe();
  }, [isOpen, post, groupId]);

  if (!post) return null;

  const formatDate = (date: any) => {
    if (!date) return '';
    try {
      const d = date.toDate ? date.toDate() : new Date(date);
      return formatDistanceToNow(d, { addSuffix: true });
    } catch (e) {
      return '';
    }
  };

  const handleAddComment = async () => {
    if (!user) {
      setShowLogin(true);
      return;
    }

    if (!newComment.trim()) return;

    setIsSubmitting(true);
    try {
      await groupService.addComment(groupId, post.id, {
        content: newComment.trim(),
        author: {
          id: user.uid,
          name: profile?.nickname || user.displayName || 'Anonymous',
          avatar: profile?.photoURL || user.photoURL || `https://api.dicebear.com/7.x/avataaars/svg?seed=${user.uid}`
        }
      });
      setNewComment('');
    } catch (error) {
      console.error('Failed to add comment:', error);
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleDeleteComment = async (commentId: string) => {
    if (!confirm('Delete this comment?')) return;
    try {
      await groupService.deleteComment(groupId, post.id, commentId);
    } catch (error) {
      console.error('Failed to delete comment:', error);
    }
  };

  const handleDeletePost = async () => {
    if (!confirm('Are you sure you want to delete this post?')) return;
    try {
      await groupService.deletePost(groupId, post.id);
      onClose();
    } catch (error) {
      console.error('Failed to delete post:', error);
    }
  };

  const isAuthor = user?.uid === post.author.id;

  return (
    <AnimatePresence>
      {isOpen && (
        <div className="fixed inset-0 z-[120] flex items-center justify-center px-4 sm:px-6">
          <motion.div 
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            onClick={onClose}
            className="absolute inset-0 bg-black/80 backdrop-blur-md"
          />
          
          <motion.div 
            initial={{ opacity: 0, scale: 0.95, y: 20 }}
            animate={{ opacity: 1, scale: 1, y: 0 }}
            exit={{ opacity: 0, scale: 0.95, y: 20 }}
            className="relative w-full max-w-5xl bg-[#fcfaff] rounded-[2.5rem] overflow-hidden shadow-2xl flex flex-col md:flex-row max-h-[90vh]"
          >
            {/* Close Button */}
            <button 
              onClick={onClose}
              className="absolute top-6 right-6 z-20 w-10 h-10 rounded-full bg-black/10 hover:bg-black/20 text-[#242c51] flex items-center justify-center transition-colors backdrop-blur-md"
            >
              <span className="material-symbols-outlined">close</span>
            </button>

            {/* Media Side */}
            {(post.image || post.video) && (
              <div className="w-full md:w-3/5 bg-black flex items-center justify-center overflow-hidden h-64 md:h-auto relative">
                {post.video ? (
                  <video 
                    src={post.video} 
                    controls 
                    autoPlay 
                    className="w-full h-full object-contain"
                  />
                ) : (
                  <img 
                    src={post.image} 
                    alt="" 
                    className="w-full h-full object-contain"
                  />
                )}
                <div className="absolute top-6 left-6 px-4 py-2 bg-black/20 backdrop-blur-md rounded-full text-white text-[10px] font-black uppercase tracking-widest">
                  {post.type}
                </div>
              </div>
            )}

            {/* Content Side */}
            <div className={`flex flex-col flex-1 ${post.image || post.video ? 'md:w-2/5' : 'w-full'} bg-white overflow-hidden`}>
              {/* Header */}
              <div className="p-8 border-b border-[#a3abd7]/10 flex items-center justify-between">
                <div className="flex items-center gap-4">
                  <img 
                    src={post.author.avatar} 
                    alt={post.author.name} 
                    className="w-12 h-12 rounded-2xl object-cover ring-4 ring-[#efefff]" 
                  />
                  <div>
                    <h3 className="font-headline font-black text-[#242c51]">@{post.author.name}</h3>
                    <p className="text-[10px] text-[#515981]/50 font-black uppercase tracking-widest">
                      {formatDate(post.createdAt)}
                    </p>
                  </div>
                </div>

                {isAuthor && (
                  <div className="flex items-center gap-2">
                    <button 
                      onClick={() => onEdit(post)}
                      className="w-9 h-9 rounded-xl bg-primary/5 text-primary flex items-center justify-center hover:bg-primary hover:text-white transition-all"
                    >
                      <span className="material-symbols-outlined text-lg">edit</span>
                    </button>
                    <button 
                      onClick={handleDeletePost}
                      className="w-9 h-9 rounded-xl bg-error/5 text-error flex items-center justify-center hover:bg-error hover:text-white transition-all"
                    >
                      <span className="material-symbols-outlined text-lg">delete</span>
                    </button>
                  </div>
                )}
              </div>

              {/* Scrollable Content */}
              <div className="flex-1 overflow-y-auto no-scrollbar p-8">
                <div className="space-y-6">
                  {post.title && (
                    <h2 className="text-2xl font-headline font-black leading-tight text-[#242c51]">
                      {post.title}
                    </h2>
                  )}
                  <p className="text-lg text-[#515981] leading-relaxed font-medium whitespace-pre-wrap">
                    {post.content}
                  </p>
                </div>

                {/* Stats */}
                <div className="flex items-center gap-6 mt-10 pt-8 border-t border-[#a3abd7]/10">
                  <div className="flex items-center gap-2">
                    <span className="material-symbols-outlined text-primary fill-1">favorite</span>
                    <span className="font-black text-sm text-[#242c51]">{post.likes}</span>
                  </div>
                  <div className="flex items-center gap-2">
                    <span className="material-symbols-outlined text-[#515981]/40">visibility</span>
                    <span className="font-black text-sm text-[#242c51]">{post.views}</span>
                  </div>
                  <div className="flex items-center gap-2 ml-auto">
                    <span className="material-symbols-outlined text-tertiary">chat_bubble</span>
                    <span className="font-black text-sm text-[#242c51]">{comments.length}</span>
                  </div>
                </div>

                {/* Comments List */}
                <div className="mt-12 space-y-8 pb-10">
                  <h4 className="text-[10px] font-black uppercase tracking-[0.2em] text-[#515981]/40">Comments</h4>
                  
                  {comments.length === 0 ? (
                    <div className="py-10 text-center">
                      <p className="text-sm font-bold text-[#515981]/30">No comments yet. Be the first!</p>
                    </div>
                  ) : (
                    <div className="space-y-8">
                      {comments.map((comment) => (
                        <div key={comment.id} className="flex gap-4 group/comment">
                          <img 
                            src={comment.author.avatar} 
                            className="w-10 h-10 rounded-xl object-cover shrink-0"
                            alt=""
                          />
                          <div className="flex-1 space-y-1.5">
                            <div className="flex items-center justify-between">
                              <div className="flex items-center gap-2">
                                <span className="text-xs font-black text-[#242c51]">{comment.author.name}</span>
                                <span className="text-[10px] font-bold text-[#515981]/30">{formatDate(comment.createdAt)}</span>
                              </div>
                              {user?.uid === comment.author.id && (
                                <button 
                                  onClick={() => handleDeleteComment(comment.id)}
                                  className="opacity-0 group-hover/comment:opacity-100 transition-opacity text-error hover:scale-110"
                                >
                                  <span className="material-symbols-outlined text-sm">delete</span>
                                </button>
                              )}
                            </div>
                            <p className="text-sm text-[#515981] leading-relaxed font-medium">
                              {comment.content}
                            </p>
                          </div>
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              </div>

              {/* Comment Input */}
              <div className="p-8 bg-white border-t border-[#a3abd7]/10">
                <div className="flex gap-4 items-center bg-[#f7f5ff] rounded-[1.5rem] p-2 pl-6 focus-within:ring-2 focus-within:ring-primary transition-all">
                  <input 
                    type="text" 
                    value={newComment}
                    onChange={(e) => setNewComment(e.target.value)}
                    onKeyDown={(e) => e.key === 'Enter' && handleAddComment()}
                    placeholder="Write a premium comment..." 
                    disabled={isSubmitting}
                    className="bg-transparent border-none focus:ring-0 text-sm font-bold flex-1 text-[#242c51] placeholder:text-slate-300"
                  />
                  <button 
                    onClick={handleAddComment}
                    disabled={isSubmitting || !newComment.trim()}
                    className="w-10 h-10 rounded-xl bg-primary text-on-primary flex items-center justify-center shadow-lg shadow-primary/20 hover:scale-105 active:scale-95 transition-all disabled:opacity-50 disabled:scale-100"
                  >
                    <span className="material-symbols-outlined text-lg">send</span>
                  </button>
                </div>
              </div>
            </div>
          </motion.div>
        </div>
      )}
    </AnimatePresence>
  );
}

'use client';

import React, { useState, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { groupService } from '@/lib/firebase/groupService';
import { storageService } from '@/lib/firebase/storageService';
import { useAuth } from '@/components/providers/AuthProvider';
import { Group, Post, GroupBoard as GroupBoardType, DEFAULT_BOARDS } from '@/types/group';

interface PostEditorModalProps {
  group: Group;
  post?: Post | null;
  isOpen: boolean;
  onClose: () => void;
}

export default function PostEditorModal({ group, post, isOpen, onClose }: PostEditorModalProps) {
  const { user, profile, setShowLogin } = useAuth();
  const boards = (group.boards && group.boards.length > 0) ? group.boards : DEFAULT_BOARDS;
  const [title, setTitle] = useState('');
  const [content, setContent] = useState('');
  const [category, setCategory] = useState(boards[0]?.id || 'notice');
  const [bgTheme, setBgTheme] = useState<string | null>(null);
  const [showThemePicker, setShowThemePicker] = useState(false);
  const [type, setType] = useState<Post['type']>('text');
  const [mediaFile, setMediaFile] = useState<File | null>(null);
  const [mediaPreview, setMediaPreview] = useState<string | null>(null);
  const [isUploading, setIsUploading] = useState(false);
  const [uploadProgress, setUploadProgress] = useState(0);
  
  const themes = [
    { id: 'blue-gradient', class: 'bg-gradient-to-br from-[#60a5fa] to-[#3b82f6]' },
    { id: 'purple-gradient', class: 'bg-gradient-to-br from-[#a78bfa] to-[#8b5cf6]' },
    { id: 'pink-gradient', class: 'bg-gradient-to-br from-[#f472b6] to-[#ec4899]' },
    { id: 'orange-gradient', class: 'bg-gradient-to-br from-[#fb923c] to-[#f97316]' },
    { id: 'green-gradient', class: 'bg-gradient-to-br from-[#4ade80] to-[#22c55e]' },
    { id: 'dark-gradient', class: 'bg-gradient-to-br from-[#475569] to-[#1e293b]' },
  ];

  const fileInputRef = useRef<HTMLInputElement>(null);
  const isEditing = !!post;

  useEffect(() => {
    if (post) {
      setTitle(post.title || '');
      setContent(post.content);
      setCategory(post.category || boards[0]?.id || 'notice');
      setType(post.type);
      setMediaPreview(post.image || post.video || null);
      setBgTheme(post.bgTheme || null);
    } else {
      setTitle('');
      setContent('');
      setCategory(boards[0]?.id || 'notice');
      setType('text');
      setMediaPreview(null);
      setBgTheme(null);
    }
  }, [post, boards]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setMediaFile(file);
      setBgTheme(null); // 테마 해제
      const isVideo = file.type.startsWith('video/');
      setType(isVideo ? 'video' : 'image');
      
      const reader = new FileReader();
      reader.onloadend = () => {
        setMediaPreview(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const toggleTheme = (themeId: string) => {
    if (bgTheme === themeId) {
      setBgTheme(null);
      setType('text');
    } else {
      setBgTheme(themeId);
      setType('text-card');
      setMediaPreview(null); // 이미지 제거
      setMediaFile(null);
    }
  };

  const handleSubmit = async () => {
    if (!user) {
      setShowLogin(true);
      return;
    }

    if (!content.trim()) {
      alert('Content is required');
      return;
    }

    setIsUploading(true);
    try {
      let mediaUrl = mediaPreview || '';
      
      if (mediaFile) {
        const path = `groups/${group.id}/posts/${Date.now()}_${mediaFile.name}`;
        mediaUrl = await storageService.uploadFile(mediaFile, path, (progress) => {
          setUploadProgress(progress);
        });
      }

      const postData: Partial<Post> = {
        title,
        content,
        category,
        type,
        bgTheme: bgTheme || undefined,
        [type === 'video' ? 'video' : 'image']: mediaUrl,
        author: {
          id: user.uid,
          name: profile?.nickname || user.displayName || 'Anonymous',
          avatar: profile?.photoURL || user.photoURL || `https://api.dicebear.com/7.x/avataaars/svg?seed=${user.uid}`,
          role: profile?.isInstructor ? 'Instructor' : 'Curator'
        }
      };

      if (isEditing && post) {
        await groupService.updatePost(group.id, post.id, postData);
      } else {
        await groupService.createPost(group.id, postData);
      }

      onClose();
    } catch (error) {
      console.error('Failed to save post:', error);
      alert('Failed to save post. Please try again.');
    } finally {
      setIsUploading(false);
      setUploadProgress(0);
    }
  };

  if (!isOpen) return null;

  return (
    <AnimatePresence>
      <div className="fixed inset-0 z-[110] flex items-center justify-center sm:p-6">
        <motion.div 
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          exit={{ opacity: 0 }}
          onClick={onClose}
          className="absolute inset-0 bg-black/60 backdrop-blur-md"
        />
        
        <motion.div 
          initial={{ opacity: 0, scale: 0.9, y: 20 }}
          animate={{ opacity: 1, scale: 1, y: 0 }}
          exit={{ opacity: 0, scale: 0.9, y: 20 }}
          className="relative w-full max-w-2xl bg-[#f7f5ff] sm:rounded-[2.5rem] overflow-hidden shadow-2xl flex flex-col max-h-[100dvh] sm:max-h-[90vh]"
        >
          {/* Header */}
          <div className="px-8 py-6 flex items-center justify-between bg-white/50 backdrop-blur-sm border-b border-[#a3abd7]/10">
            <div className="flex items-center gap-4">
               <button 
                onClick={onClose}
                className="w-10 h-10 rounded-full hover:bg-slate-100 flex items-center justify-center transition-colors"
               >
                  <span className="material-symbols-outlined text-[#515981]">close</span>
               </button>
               <h2 className="text-xl font-headline font-black text-[#242c51]">
                 {isEditing ? 'Edit Post' : 'Create New Post'}
               </h2>
            </div>
            <button 
              onClick={handleSubmit}
              disabled={isUploading}
              className="px-6 py-2.5 bg-primary text-on-primary font-black rounded-xl shadow-lg shadow-primary/20 active:scale-95 transition-all disabled:opacity-50"
            >
              {isUploading ? `${Math.round(uploadProgress)}%` : (isEditing ? 'Save' : 'Post')}
            </button>
          </div>

          {/* Content Area */}
          <div className="flex-1 overflow-y-auto p-8 no-scrollbar">
            <div className="space-y-8">
              {/* Category & Type Selectors */}
              <div className="flex flex-wrap gap-4">
                <div className="flex-1 min-w-[200px]">
                  <label className="block text-[10px] font-black uppercase tracking-widest text-[#515981] mb-2 px-1">Board Category</label>
                  <select 
                    value={category}
                    onChange={(e) => setCategory(e.target.value)}
                    className="w-full bg-white border-none rounded-xl px-4 py-3 text-sm font-bold text-[#242c51] shadow-sm ring-1 ring-[#a3abd7]/10 focus:ring-2 focus:ring-primary outline-none"
                  >
                    {boards.map((board) => (
                      <option key={board.id} value={board.id}>{board.title}</option>
                    ))}
                  </select>
                </div>
              </div>

              {/* Title */}
              <div>
                <label className="block text-[10px] font-black uppercase tracking-widest text-[#515981] mb-2 px-1">Title (Optional)</label>
                <input 
                  type="text" 
                  value={title}
                  onChange={(e) => setTitle(e.target.value)}
                  placeholder="Give your post a title..."
                  className="w-full bg-white border-none rounded-2xl px-6 py-4 text-lg font-headline font-bold text-[#242c51] shadow-sm ring-1 ring-[#a3abd7]/10 focus:ring-2 focus:ring-primary outline-none placeholder:text-slate-300"
                />
              </div>

              {/* Body */}
              <div className="relative">
                <div className={`relative w-full rounded-[2rem] shadow-sm ring-1 ring-[#a3abd7]/10 overflow-hidden min-h-[250px] ${bgTheme ? themes.find(t => t.id === bgTheme)?.class : 'bg-white'}`}>
                  <textarea 
                    value={content}
                    onChange={(e) => setContent(e.target.value)}
                    placeholder="What's happening in the community?"
                    className={`w-full h-full bg-transparent border-none px-8 py-8 text-lg font-medium outline-none placeholder:text-slate-300 min-h-[250px] resize-none transition-all duration-500 ${bgTheme ? 'text-white text-center flex items-center justify-center placeholder:text-white/50' : 'text-[#242c51]'}`}
                    style={bgTheme ? { display: 'flex', alignItems: 'center', justifyContent: 'center' } : {}}
                  />
                </div>
                
                {/* Media Preview inside textarea overlay or below */}
                {mediaPreview && (
                  <div className="mt-4 relative rounded-3xl overflow-hidden aspect-video bg-black group">
                    {type === 'video' ? (
                      <video src={mediaPreview} controls className="w-full h-full object-contain" />
                    ) : (
                      <img src={mediaPreview} className="w-full h-full object-contain" alt="Preview" />
                    )}
                    <button 
                      onClick={() => { setMediaPreview(null); setMediaFile(null); setType('text'); }}
                      className="absolute top-4 right-4 w-10 h-10 rounded-full bg-black/40 text-white backdrop-blur-md opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center"
                    >
                      <span className="material-symbols-outlined">close</span>
                    </button>
                  </div>
                )}
              </div>
            </div>
          </div>

          {/* Bottom Bar Tools */}
          <div className="px-8 py-6 bg-white border-t border-[#a3abd7]/10 flex flex-col gap-4">
             {showThemePicker && (
               <motion.div 
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                className="flex items-center gap-3 overflow-x-auto pb-2 no-scrollbar"
               >
                 {themes.map((theme) => (
                   <button
                    key={theme.id}
                    onClick={() => toggleTheme(theme.id)}
                    className={`w-10 h-10 rounded-full flex-shrink-0 border-2 transition-all ${theme.class} ${bgTheme === theme.id ? 'border-primary scale-110' : 'border-transparent'}`}
                   />
                 ))}
                 <button
                  onClick={() => { setBgTheme(null); setType('text'); }}
                  className="w-10 h-10 rounded-full flex-shrink-0 bg-slate-100 border-2 border-transparent flex items-center justify-center"
                 >
                   <span className="material-symbols-outlined text-slate-400 text-sm">block</span>
                 </button>
               </motion.div>
             )}

             <div className="flex items-center gap-4">
               <button 
                onClick={() => {
                  fileInputRef.current?.click();
                  setShowThemePicker(false);
                }}
                className={`w-12 h-12 rounded-2xl transition-all flex items-center justify-center shadow-sm ${mediaPreview ? 'bg-primary text-white' : 'bg-[#efefff] text-primary hover:bg-primary hover:text-white'}`}
               >
                  <span className="material-symbols-outlined">image</span>
               </button>
               <button 
                onClick={() => setShowThemePicker(!showThemePicker)}
                className={`w-12 h-12 rounded-2xl transition-all flex items-center justify-center shadow-sm ${bgTheme ? 'bg-primary text-white' : 'bg-[#efefff] text-[#515981] hover:bg-slate-200'}`}
               >
                  <span className="material-symbols-outlined">title</span>
               </button>
               
               <input 
                 type="file" 
                 hidden 
                 ref={fileInputRef} 
                 accept="image/*,video/*"
                 onChange={handleFileChange}
               />
               
               <div className="ml-auto text-xs font-bold text-[#515981]/40">
                 {content.length} characters
               </div>
             </div>
          </div>
        </motion.div>
      </div>
    </AnimatePresence>
  );
}

'use client';

import React, { useState } from 'react';

interface AppSettingsPopupProps {
  isOpen: boolean;
  onClose: () => void;
}

const INSTRUCTIONS = [
  {
    id: 'chrome',
    icon: 'browser_updated',
    title: 'Chrome / Android',
    browser: 'Google Chrome',
    image: 'chrome_guide.png',
    steps: [
      'Tap the three dots (⋮) in the top right corner.',
      'Select "Install App" or "Add to Home screen".',
      'Confirm the installation when prompted.'
    ]
  },
  {
    id: 'samsung',
    icon: 'language_korean_latin',
    title: 'Samsung Internet',
    browser: 'Samsung Internet',
    image: 'samsung_guide.png',
    steps: [
      'Tap the menu (≡) in the bottom right corner.',
      'Tap on the "Add page to" icon.',
      'Select "Home screen" from the menu.'
    ]
  },
  {
    id: 'safari',
    icon: 'apple',
    title: 'Safari (iPhone / iPad)',
    browser: 'Safari (iOS)',
    image: 'safari_guide.png',
    steps: [
      'Tap the "Share" button (the square with an arrow) at the bottom.',
      'Scroll down and select "Add to Home Screen".',
      'Tap "Add" in the top right corner.'
    ]
  }
];

export default function AppSettingsPopup({ isOpen, onClose }: AppSettingsPopupProps) {
  const [activeTab, setActiveTab] = useState('chrome');

  if (!isOpen) return null;

  const currentTab = INSTRUCTIONS.find(i => i.id === activeTab) || INSTRUCTIONS[0];

  return (
    <div className="fixed inset-0 z-[10000] bg-white flex flex-col animate-in slide-in-from-bottom duration-500 overflow-hidden">
      {/* Header */}
      <header className="px-6 pt-10 pb-0 flex flex-col border-b border-outline-variant/10 shrink-0">
        <div className="flex items-center justify-between mb-8">
          <div>
            <span className="font-label text-[10px] font-black text-primary tracking-[0.25em] uppercase mb-1 block">Settings</span>
            <h2 className="font-display text-2xl font-black tracking-tight text-on-surface uppercase">App Setting</h2>
          </div>
          <button 
            onClick={onClose}
            className="w-10 h-10 flex items-center justify-center rounded-full bg-on-surface/[0.04] text-on-surface/40 hover:bg-on-surface/[0.08]"
          >
            <span className="material-symbols-outlined text-2xl">close</span>
          </button>
        </div>

        {/* Browser Tabs */}
        <div className="flex gap-8 overflow-x-auto no-scrollbar">
          {INSTRUCTIONS.map((tab) => (
            <button 
              key={tab.id}
              onClick={() => setActiveTab(tab.id)}
              className={`shrink-0 pb-4 text-[10px] font-black tracking-[0.2em] uppercase transition-all relative ${
                activeTab === tab.id ? 'text-primary scale-105' : 'text-on-surface/30 hover:text-on-surface/50'
              }`}
            >
              {tab.id.toUpperCase()}
              {activeTab === tab.id && (
                <div className="absolute bottom-0 left-0 right-0 h-1 bg-primary rounded-t-full"></div>
              )}
            </button>
          ))}
        </div>
      </header>

      {/* Content Area */}
      <main className="flex-1 overflow-y-auto no-scrollbar px-6 py-10">
        <div className="max-w-md mx-auto">
          
          {/* Instruction Card */}
          <div className="animate-in fade-in duration-300">
            {/* Guide Image */}
            <div className="mb-10 rounded-[40px] overflow-hidden bg-on-surface/[0.03] p-1 border border-outline-variant/10 shadow-lg">
              <img 
                src={`/${currentTab.image}`} 
                alt={currentTab.browser}
                className="w-full h-auto object-cover rounded-[39px]"
              />
            </div>

            {/* Title & Info */}
            <div className="px-2 mb-10">
              <h3 className="text-xl font-black tracking-tight text-on-surface mb-3 uppercase">{currentTab.title}</h3>
              <p className="text-sm font-medium text-on-surface/50 leading-relaxed">
                Follow these simple steps in {currentTab.browser} to install WoC on your home screen.
              </p>
            </div>

            {/* Steps List */}
            <div className="space-y-4 px-2">
              {currentTab.steps.map((step, idx) => (
                <div key={idx} className="flex gap-5 p-5 rounded-3xl bg-on-surface/[0.03] border border-outline-variant/10 group active:scale-[0.98] transition-all">
                  <div className="w-8 h-8 rounded-full bg-primary/10 flex items-center justify-center shrink-0">
                    <span className="text-[12px] font-black text-primary">{idx + 1}</span>
                  </div>
                  <p className="text-sm font-bold text-on-surface/70 leading-snug">{step}</p>
                </div>
              ))}
            </div>
          </div>

          {/* Footer Note */}
          <div className="mt-16 mb-12 text-center opacity-40">
            <p className="text-[9px] font-black tracking-[0.3em] uppercase">World of Group · Home Screen Setup</p>
          </div>
        </div>
      </main>
    </div>
  );
}

'use client';

import React, { useState } from 'react';
import Link from 'next/link';
import { useRouter } from 'next/navigation';
import { useNavigation } from '@/components/providers/NavigationProvider';
import { useAuth } from '@/components/providers/AuthProvider';
import AppSettingsPopup from './AppSettingsPopup';

const LANGUAGES = [
  { code: 'en', name: 'English', native: 'English', active: true },
  { code: 'ko', name: 'Korean', native: '한국어', active: false },
  { code: 'es', name: 'Spanish', native: 'Español', active: false },
  { code: 'fr', name: 'French', native: 'Français', active: false },
  { code: 'de', name: 'German', native: 'Deutsch', active: false },
  { code: 'it', name: 'Italian', native: 'Italiano', active: false },
  { code: 'pt', name: 'Portuguese', native: 'Português', active: false },
  { code: 'zh', name: 'Chinese', native: '中文', active: false },
  { code: 'ja', name: 'Japanese', native: '日本語', active: false },
  { code: 'ru', name: 'Russian', native: 'Русский', active: false },
];

export default function NavigationDrawer() {
  const { isDrawerOpen, closeDrawer } = useNavigation();
  const { profile, user, signOut } = useAuth();
  const router = useRouter();
  
  const [isLangOpen, setIsLangOpen] = useState(false);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);

  const handleLogout = async () => {
    closeDrawer();
    router.push('/');
    await signOut();
  };

  const displayName = profile?.nickname || user?.displayName || 'User';
  const photoURL = profile?.photoURL || user?.photoURL || 'https://images.unsplash.com/photo-1472099645785-5658abf4ff4e?w=100&h=100&fit=crop';
  
  // Collect Roles
  const roles = [];
  if (profile?.isInstructor) roles.push('Instructor');
  if (profile?.isSeller) roles.push('Seller');
  if (profile?.isServiceProvider) roles.push('Service');
  if (!profile?.isRegistered) roles.push('Guest');
  else if (roles.length === 0) roles.push('Member');

  return (
    <>
      <AppSettingsPopup isOpen={isSettingsOpen} onClose={() => setIsSettingsOpen(false)} />

      {/* Backdrop */}
      <div 
        className={`fixed inset-0 z-[9998] bg-black/40 backdrop-blur-sm transition-opacity duration-300 ease-out ${
          isDrawerOpen ? 'opacity-100 pointer-events-auto' : 'opacity-0 pointer-events-none'
