      <div 
        className={`fixed inset-y-0 left-0 z-[9999] w-[85%] max-w-[340px] flex flex-col bg-surface shadow-2xl transition-transform duration-300 ease-out ${
          isDrawerOpen ? 'translate-x-0' : '-translate-x-full'
