const REGIONS = ['전체', '서울', '경기/인천', '부산/경남', '대구/경북', '광주/전라', '대전/충청', '강원', '제주'];
const CATEGORIES = ['전체', '스튜디오', '밀롱가 전용', '기타'];

const MOCK_PLACES = [
  {
