                ))}
              </div>

              <div className="pt-2 flex gap-2">
                <button className="flex-1 bg-primary/5 text-primary text-xs font-bold py-2.5 rounded-xl flex items-center justify-center gap-1.5 hover:bg-primary/10 transition-colors">
