            <span className="material-symbols-outlined text-[20px]">close</span>
          </button>
        </div>

        {/* Content Area */}
        <div className="flex-1 overflow-y-auto no-scrollbar scroll-smooth">
          {/* Hero Image */}
          <div className="w-full h-80 relative bg-surface-container">
