'use client';

import React, { useState, useRef } from 'react';
import { useAuth } from '@/components/providers/AuthProvider';
import { stayService } from '@/lib/firebase/stayService';
import { plazaService } from '@/lib/firebase/plazaService';
import { StayType } from '@/types/stay';

interface CreateStayProps {
  onClose: () => void;
  onSuccess?: () => void;
}

export default function CreateStay({ onClose, onSuccess }: CreateStayProps) {
  const { user } = useAuth();
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [uploadProgress, setUploadProgress] = useState(0);
  
  const [title, setTitle] = useState('');
  const [type, setType] = useState<StayType>('1-Room');
  const [location, setLocation] = useState('');
  const [price, setPrice] = useState('');
  const [description, setDescription] = useState('');
  const [mediaFile, setMediaFile] = useState<File | null>(null);
  const [previewUrl, setPreviewUrl] = useState('');

  const [amenities, setAmenities] = useState<string[]>([]);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const stayTypes: StayType[] = ['Couchsurfing', 'Dormitory', '1-Room', '2-Room', '3-Room', 'Pension'];
  const amenityOptions = ['wifi', 'desk', 'coffee', 'studio', 'gym', 'kitchen'];

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setMediaFile(file);
      setPreviewUrl(URL.createObjectURL(file));
    }
  };

  const toggleAmenity = (amenity: string) => {
    setAmenities(prev => 
      prev.includes(amenity) ? prev.filter(a => a !== amenity) : [...prev, amenity]
    );
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!user || !title || !price || !mediaFile) return;

    setIsSubmitting(true);
    setUploadProgress(0);
    
    try {
      const imageUrl = await plazaService.uploadMedia(mediaFile, (p) => setUploadProgress(Math.round(p)));

      await stayService.registerStay({
        title,
        type,
        location,
        description,
        pricePerNight: parseInt(price),
        imageUrl,
        hostId: user.uid,
        hostName: user.displayName || 'Anonymous',
        hostPhoto: user.photoURL || '',
        hostRole: 'Hobbyist', // Default or could be input
        amenities,
        isNewlyListed: true,
      });

      onSuccess?.();
      onClose();
    } catch (error) {
      console.error("Error creating stay:", error);
      alert("Failed to register stay. Please try again.");
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-end sm:items-center justify-center p-0 sm:p-4 animate-in fade-in duration-200">
      <div className="absolute inset-0 bg-black/60 backdrop-blur-sm" onClick={onClose} />
      
      <div className="relative bg-white w-full max-w-xl rounded-t-[32px] sm:rounded-[32px] shadow-2xl overflow-hidden animate-in slide-in-from-bottom duration-300 flex flex-col max-h-[95vh]">
        {/* Header */}
        <div className="p-6 border-b border-gray-50 flex items-center justify-between bg-white/80 backdrop-blur-md sticky top-0 z-10 font-manrope">
          <div className="flex flex-col">
            <span className="text-[10px] font-black text-primary tracking-[0.25em] uppercase mb-1">Accommodation</span>
            <h3 className="text-[20px] font-black text-gray-900 uppercase tracking-tighter">Host a Stay</h3>
          </div>
          <button onClick={onClose} className="w-10 h-10 rounded-full flex items-center justify-center bg-gray-50 hover:bg-gray-100 transition-all text-gray-400">
            <span className="material-symbols-outlined text-[20px]">close</span>
          </button>
        </div>

        <form onSubmit={handleSubmit} className="flex-1 overflow-y-auto p-8 space-y-8 no-scrollbar scroll-smooth">
          {/* Main Photo Upload */}
          <div 
            onClick={() => fileInputRef.current?.click()}
            className="relative h-64 w-full rounded-[24px] bg-gray-50 border-2 border-dashed border-gray-100 flex flex-col items-center justify-center cursor-pointer overflow-hidden group hover:border-primary/20 transition-all"
          >
            {previewUrl ? (
              <img src={previewUrl} className="w-full h-full object-cover" alt="preview" />
            ) : (
              <>
                <div className="w-14 h-14 rounded-full bg-white shadow-sm flex items-center justify-center mb-4 group-hover:scale-110 transition-transform">
                  <span className="material-symbols-outlined text-gray-300 text-[28px]">add_a_photo</span>
                </div>
                <span className="text-[10px] font-black text-gray-300 uppercase tracking-widest">Main Lobby Photo</span>
              </>
            )}
            <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleFileChange} />
          </div>

          {/* Basic Info */}
          <div className="space-y-6">
            <div className="space-y-2">
              <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">Stay Title</label>
              <input
                value={title}
                onChange={(e) => setTitle(e.target.value)}
                placeholder="Ex. The Creative Nomad Loft"
                className="w-full text-[24px] font-black tracking-tighter border-none focus:ring-0 placeholder:text-gray-200 p-0"
                required
              />
            </div>

            <div className="grid grid-cols-2 gap-8">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">Type</label>
                <select 
                  value={type}
                  onChange={(e) => setType(e.target.value as StayType)}
                  className="w-full bg-gray-50 border-none rounded-2xl px-4 py-3.5 text-sm font-bold focus:ring-2 focus:ring-primary/10"
                >
                  {stayTypes.map(t => <option key={t} value={t}>{t}</option>)}
                </select>
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">Price / Night ($)</label>
                <input
                  type="number"
                  value={price}
                  onChange={(e) => setPrice(e.target.value)}
                  placeholder="0"
                  className="w-full bg-gray-50 border-none rounded-2xl px-4 py-3.5 text-sm font-bold focus:ring-2 focus:ring-primary/10"
                  required
                />
              </div>
            </div>
          </div>

          {/* Location */}
          <div className="space-y-2">
            <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">Location Address</label>
            <input
              value={location}
              onChange={(e) => setLocation(e.target.value)}
              placeholder="Ex. Berlin, Germany or Specific Avenue"
              className="w-full bg-gray-50 border-none rounded-2xl px-5 py-3.5 text-sm font-bold focus:ring-2 focus:ring-primary/10"
              required
            />
          </div>

          {/* Amenities */}
          <div className="space-y-4">
            <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">Amenities</label>
            <div className="flex flex-wrap gap-2">
              {amenityOptions.map(opt => (
                <button
                  key={opt}
                  type="button"
                  onClick={() => toggleAmenity(opt)}
                  className={`px-4 py-2 rounded-full text-[11px] font-black transition-all flex items-center gap-1.5 uppercase ${
                    amenities.includes(opt) ? 'bg-primary text-white scale-105' : 'bg-gray-50 text-gray-400 hover:bg-gray-100'
                  }`}
                >
                  <span className="material-symbols-outlined text-[16px]">{opt}</span>
                  {opt}
                </button>
              ))}
            </div>
          </div>

          {/* Description */}
          <div className="space-y-2 pb-4">
            <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">The Experience</label>
            <textarea
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              placeholder="Describe what makes your stay special for hobbyists..."
              className="w-full min-h-[140px] bg-gray-50 border-none rounded-[28px] px-5 py-4 text-sm font-medium focus:ring-2 focus:ring-primary/10 resize-none"
            />
          </div>
        </form>

        {/* Footer */}
        <div className="p-6 border-t border-gray-50 bg-white">
          <button
            onClick={handleSubmit}
            disabled={isSubmitting || !title || !price || !mediaFile}
            className={`w-full h-14 rounded-full font-black text-[15px] transition-all flex items-center justify-center gap-2 uppercase tracking-widest shadow-xl ${
              (isSubmitting || !title || !price || !mediaFile)
                ? 'bg-gray-100 text-gray-300'
                : 'bg-primary text-white shadow-primary/30 hover:scale-[1.02] active:scale-[0.98]'
            }`}
          >
            {isSubmitting ? (
              <>
                <div className="w-5 h-5 border-3 border-white/30 border-t-white rounded-full animate-spin" />
                <span>Launching Stay {uploadProgress}%</span>
              </>
            ) : (
              <span>Open for Bookings</span>
            )}
          </button>
        </div>
      </div>
    </div>
  );
}

"use client";

import React, { useState, useRef, useEffect } from 'react';
import { db } from '@/lib/firebase/clientApp';
import { collection, addDoc, serverTimestamp, doc, updateDoc } from 'firebase/firestore';
import { useLocation } from '@/components/providers/LocationProvider';
import { GoogleMap, Autocomplete, Marker } from '@react-google-maps/api';
import { venueService } from '@/lib/firebase/venueService';
import { Venue } from '@/types/venue';

interface ManageEntryProps {
  isOpen: boolean;
  onClose: () => void;
  isLoaded: boolean;
  initialData?: Venue | null;
  mode?: 'edit' | 'geo';
}

const mapContainerStyle = {
  width: '100%',
  height: '220px',
  borderRadius: '16px',
};

const CIRCLE_PATH = 0;

export default function ManageEntry({ isOpen, onClose, isLoaded, initialData, mode = 'edit' }: ManageEntryProps) {
  const { location } = useLocation();
  const [autocomplete, setAutocomplete] = useState<google.maps.places.Autocomplete | null>(null);
  const [map, setMap] = useState<google.maps.Map | null>(null);
  const detailAddressRef = useRef<HTMLInputElement>(null);
  
  const [formData, setFormData] = useState({
    name: '',
    nameKo: '',
    categories: [] as string[],
    address: '',
    detailAddress: '',
    city: '',
    country: '',
    zone: '',
    latitude: 37.5575,
    longitude: 126.9244,
    images: [] as File[],
  });

  const [saving, setSaving] = useState(false);

  useEffect(() => {
    if (initialData) {
      setFormData({
        name: initialData.name,
        nameKo: initialData.nameKo || '',
        categories: initialData.types || [initialData.category],
        address: initialData.address,
        detailAddress: (initialData as any).detailAddress || '',
        city: initialData.city,
        country: (initialData as any).country || '',
        zone: (initialData as any).zone || '',
        latitude: initialData.coordinates.latitude,
        longitude: initialData.coordinates.longitude,
        images: [], // Images are tricky, usually we handle them separately or keep existing ones
      });
    } else {
      setFormData({
        name: '',
        nameKo: '',
        categories: [],
        address: '',
        detailAddress: '',
        city: '',
        country: '',
        zone: '',
        latitude: 37.5575,
        longitude: 126.9244,
        images: [],
      });
    }
  }, [initialData, isOpen]);

  const categoriesList = [
    { id: 'Studio', label: 'Studio', icon: 'workspaces' },
    { id: 'Academy', label: 'Academy', icon: 'school' },
    { id: 'Club', label: 'Club', icon: 'groups' },
    { id: 'Shop', label: 'Shop', icon: 'shopping_bag' },
    { id: 'Cafe', label: 'Cafe', icon: 'coffee' },
    { id: 'Eats', label: 'Eats', icon: 'restaurant' },
    { id: 'Beauty', label: 'Beauty', icon: 'content_cut' },
    { id: 'Stay', label: 'Stay', icon: 'bed' },
    { id: 'Other', label: 'Other', icon: 'more_horiz' },
  ];

  const updateWithPlace = (place: any) => {
    const geometry = place.geometry;
    if (!geometry || !geometry.location) return;

    const lat = geometry.location.lat();
    const lng = geometry.location.lng();
    
    let country = '';
    let city = '';
    let zone = '';

    place.address_components?.forEach((comp: any) => {
      const types = comp.types;
      if (types.includes('country')) country = comp.long_name;
      if (types.includes('locality') || types.includes('administrative_area_level_1')) city = comp.long_name;
      if (types.includes('sublocality_level_1') || types.includes('administrative_area_level_2')) zone = comp.long_name;
    });

    setFormData(prev => ({
      ...prev,
      address: place.formatted_address || '',
      name: prev.name || place.name || '',
      latitude: lat,
      longitude: lng,
      city: city || prev.city,
      country: country || prev.country,
      zone: zone || prev.zone
    }));
    
    map?.panTo({ lat, lng });
    map?.setZoom(17);

    setTimeout(() => {
      detailAddressRef.current?.focus();
    }, 400);
  };

  const onPlaceChanged = () => {
    if (autocomplete !== null) {
      const place = autocomplete.getPlace();
      updateWithPlace(place);
    }
  };

  const handleManualSearch = () => {
    if (!formData.address) return;
    
    const service = new google.maps.places.AutocompleteService();
    const geocoder = new google.maps.Geocoder();

    service.getPlacePredictions({ input: formData.address }, (predictions, status) => {
      if (status === 'OK' && predictions && predictions.length > 0) {
        // Automatically pick the FIRST prediction if user hits Enter
        const firstPlaceId = predictions[0].place_id;
        const detailsService = new google.maps.places.PlacesService(document.createElement('div'));
        
        detailsService.getDetails({ placeId: firstPlaceId }, (place, status) => {
          if (status === 'OK' && place) {
            updateWithPlace(place);
          }
        });
      } else {
        // Fallback to basic geocoding if no predictions
        geocoder.geocode({ address: formData.address }, (results, status) => {
          if (status === 'OK' && results && results[0]) {
            updateWithPlace(results[0]);
          }
        });
      }
    });
  };

  const toggleCategory = (category: string) => {
    setFormData(prev => ({
      ...prev,
      categories: prev.categories.includes(category)
        ? prev.categories.filter(c => c !== category)
        : [...prev.categories, category]
    }));
  };

  const handleSubmit = async () => {
    if (!formData.name.trim()) {
      alert('Please enter a Place Name.');
      return;
    }
    if (formData.categories.length === 0) {
      alert('Please select at least one category.');
      return;
    }
    setSaving(true);
    try {
      const payload: any = {
        name: formData.name,
        nameKo: formData.nameKo,
        types: formData.categories,
        category: formData.categories[0], 
        address: formData.address,
        detailAddress: formData.detailAddress,
        city: (location.city || '').toUpperCase(),
        country: (formData.country || '').toUpperCase(),
        zone: formData.zone,
        coordinates: { latitude: Number(formData.latitude), longitude: Number(formData.longitude) },
        status: 'active',
      };

      if (initialData?.id) {
        await venueService.updateVenue(initialData.id, payload);
        alert('Venue updated successfully!');
      } else {
        payload.createdAt = serverTimestamp();
        await addDoc(collection(db, "venues"), payload);
        alert('Venue saved successfully!');
      }
      onClose();
    } catch (error: any) {
      console.error("Error saving venue:", error);
      alert(`Failed to save: ${error.message || 'Unknown error. check console.'}`);
    } finally {
      setSaving(false);
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[2000] bg-white flex flex-col overflow-hidden animate-in fade-in duration-300">
      
      {/* Header */}
      <header className="fixed top-0 left-0 right-0 z-[2001] bg-white flex justify-between items-center w-full px-6 h-16 border-b border-[#dde4e5]">
        <button onClick={onClose} className="p-2 hover:bg-[#e8eff0] transition-colors rounded-full"><span className="material-symbols-outlined text-[#161D1E]">close</span></button>
        <h1 className="font-headline text-[13px] font-black text-[#2D3435] uppercase tracking-widest">
          {mode === 'geo' ? 'Geo Tuning' : initialData ? 'Edit Venue' : 'Register Venue'}
        </h1>
        <button onClick={handleSubmit} disabled={saving} className="px-5 py-2 bg-[#005BC0] text-white font-black rounded-xl active:scale-95 transition-all text-[11px] uppercase tracking-widest disabled:opacity-50">
          {saving ? 'WAIT' : 'SAVE'}
        </button>
      </header>

      {/* Body */}
      <main className="flex-grow overflow-y-auto no-scrollbar pt-20 pb-32 max-w-2xl mx-auto w-full px-6">
        
        {/* Identity */}
        {mode === 'edit' && (
          <section className="mb-10">
            <h2 className="font-headline text-[13px] font-black text-[#2D3435] uppercase tracking-[0.15em] mb-6">Identity</h2>
            <div className="space-y-5">
              <div className="group">
                <label className="block text-[10px] font-bold text-[#596061] mb-2 tracking-widest uppercase">Place Name (Required)</label>
                <input type="text" value={formData.name} onChange={(e) => setFormData({...formData, name: e.target.value})} placeholder="e.g. Blue Horizon Studio" className="w-full bg-[#e8eff0] border-none rounded-xl px-5 py-4 text-[#2D3435] font-bold focus:bg-white focus:ring-2 focus:ring-[#005BC0]/20 transition-all placeholder:text-[#596061]/30 text-[15px]"/>
              </div>
              <div className="group">
                <label className="block text-[10px] font-bold text-[#596061] mb-2 tracking-widest uppercase">Korean Name (Optional)</label>
                <input type="text" value={formData.nameKo} onChange={(e) => setFormData({...formData, nameKo: e.target.value})} placeholder="예: 탱고라이프" className="w-full bg-[#e8eff0] border-none rounded-xl px-5 py-4 text-[#2D3435] font-bold focus:bg-white focus:ring-2 focus:ring-[#005BC0]/20 transition-all placeholder:text-[#596061]/30 text-[15px]"/>
              </div>
            </div>
          </section>
        )}

        {/* Category */}
        {mode === 'edit' && (
          <section className="mb-10">
            <div className="flex justify-between items-center mb-6">
              <h2 className="font-headline text-[13px] font-black text-[#2D3435] uppercase tracking-[0.15em]">Category</h2>
              <span className="text-[10px] font-bold text-[#005BC0] uppercase tracking-widest bg-[#005BC0]/5 px-3 py-1 rounded-full">Multi-selection Enabled</span>
            </div>
            <div className="grid grid-cols-3 gap-2.5">
              {categoriesList.map((cat) => (
                <button key={cat.id} type="button" onClick={() => toggleCategory(cat.id)} className={`flex flex-col items-center justify-center p-4 rounded-xl transition-all ${formData.categories.includes(cat.id) ? 'bg-[#005BC0] text-white shadow-lg scale-105 z-10' : 'bg-[#eef5f6] text-[#596061]'}`}>
                  <span className="material-symbols-outlined text-[20px] mb-2" style={{ fontVariationSettings: formData.categories.includes(cat.id) ? "'FILL' 1" : "'FILL' 0" }}>{cat.icon}</span>
                  <span className="text-[9px] font-black uppercase tracking-tight">{cat.label}</span>
                </button>
              ))}
            </div>
          </section>
        )}

        {/* Search */}
        <section className="mb-10">
          <h2 className="font-headline text-[13px] font-black text-[#2D3435] uppercase tracking-[0.15em] mb-6">Location Search</h2>
          <div className="relative mb-5 w-full">
            {isLoaded ? (
              <Autocomplete 
                onLoad={(auto) => setAutocomplete(auto)} 
                onPlaceChanged={onPlaceChanged}
                options={{
                  bounds: {
                    north: Number(formData.latitude) + 0.1,
                    south: Number(formData.latitude) - 0.1,
                    east: Number(formData.longitude) + 0.1,
                    west: Number(formData.longitude) - 0.1,
                  },
                  componentRestrictions: { country: "kr" }
                }}
              >
                <input 
                  type="text" 
                  value={formData.address}
                  onChange={(e) => setFormData({...formData, address: e.target.value})}
                  onKeyDown={(e) => { if (e.key === 'Enter') { e.preventDefault(); handleManualSearch(); } }}
                  placeholder="Type address or place name..."
                  className="w-full bg-[#e8eff0] border-none rounded-2xl pl-12 pr-4 py-4 text-[#2D3435] font-bold focus:bg-white focus:ring-2 focus:ring-[#005BC0]/20 shadow-sm transition-all text-[15px]"
                />
              </Autocomplete>
            ) : <div className="w-full bg-[#e8eff0] h-14 rounded-2xl animate-pulse"></div>}
            <span className="material-symbols-outlined absolute left-4 top-1/2 -translate-y-1/2 text-[#005BC0] text-[20px]">search</span>
          </div>
          
          <div className="h-60 w-full bg-[#f4fbfb] rounded-[2rem] overflow-hidden relative border border-[#dde4e5] mb-6">
            {isLoaded ? (
              <GoogleMap mapContainerStyle={mapContainerStyle} center={{ lat: formData.latitude, lng: formData.longitude }} zoom={17} onLoad={(m) => setMap(m)} options={{ disableDefaultUI: true, zoomControl: false, mapId: "425069951fef97d91810ab94", gestureHandling: 'greedy' }}>
                <Marker position={{ lat: formData.latitude, lng: formData.longitude }} draggable={true} onDragEnd={(e) => { if (e.latLng) { setFormData(prev => ({ ...prev, latitude: e.latLng!.lat(), longitude: e.latLng!.lng() })); } }} icon={{ path: CIRCLE_PATH, fillColor: "#005BC0", fillOpacity: 1, strokeWeight: 4, strokeColor: "#ffffff", scale: 10 }}/>
              </GoogleMap>
            ) : <div className="w-full h-full flex items-center justify-center"><div className="animate-spin rounded-full h-6 w-6 border-b-2 border-[#005BC0]"></div></div>}
          </div>

          <div className="bg-[#f4fbfb] rounded-3xl p-2.5 space-y-1.5 border border-[#e8eff0]">
            <div className="grid grid-cols-2 gap-1.5">
              <DetailItem label="LATITUDE" value={formData.latitude.toString()} readOnly={true} />
              <DetailItem label="LONGITUDE" value={formData.longitude.toString()} readOnly={true} />
            </div>
            <DetailItem label="COUNTRY" value={formData.country} readOnly={true} />
            <DetailItem label="CITY" value={formData.city} readOnly={true} />
            <DetailItem label="ZONE" value={formData.zone} readOnly={true} />
            <DetailItem label="STREET ADDR" value={formData.address} readOnly={true} />
            
            <div className="flex items-center px-5 py-4 bg-white rounded-2xl shadow-sm border-2 border-[#005BC0]/20">
              <label className="w-1/3 text-[9px] font-black text-[#005BC0] uppercase tracking-widest">UNIT / FLOOR</label>
              <input 
                ref={detailAddressRef}
                type="text" 
                value={formData.detailAddress}
                onChange={(e) => setFormData({...formData, detailAddress: e.target.value})}
                className="w-2/3 border-none bg-transparent focus:ring-0 text-[#2D3435] font-bold text-[14px] p-0" 
                placeholder="Required (e.g. 2F, 201)" 
              />
            </div>
          </div>
        </section>

        {/* Photos */}
        {mode === 'edit' && (
          <section className="mb-0">
            <div className="flex justify-between items-end mb-6">
              <h2 className="font-headline text-[13px] font-black text-[#2D3435] uppercase tracking-[0.15em]">Venue Photos</h2>
              <span className="text-[10px] font-black text-[#005BC0] bg-[#005BC0]/5 px-3 py-1 rounded-full uppercase tracking-widest">{formData.images.length} / 20</span>
            </div>
            <div className="flex gap-4 overflow-x-auto no-scrollbar pb-6 -mx-6 px-6">
              <label className="flex-shrink-0 w-48 h-48 border-2 border-dashed border-[#c2c6d5] rounded-[2rem] flex flex-col items-center justify-center bg-white hover:bg-[#eaf2ff] transition-all cursor-pointer group">
                <span className="material-symbols-outlined text-[#727784] text-[40px] mb-2 group-hover:scale-110 transition-all">add_a_photo</span>
                <input type="file" multiple accept="image/*" onChange={(e) => { if (e.target.files) { const filesArray = Array.from(e.target.files); if (filesArray.length + formData.images.length > 20) return; setFormData(prev => ({ ...prev, images: [...prev.images, ...filesArray] })); } }} className="hidden" />
              </label>
              {formData.images.map((img, idx) => (
                <div key={idx} className="relative flex-shrink-0 w-48 h-48 rounded-[2rem] bg-[#e2e9ea] overflow-hidden shadow-md">
                  <img src={URL.createObjectURL(img)} className="w-full h-full object-cover" alt="" />
                  <button type="button" onClick={() => setFormData(prev => ({ ...prev, images: prev.images.filter((_, i) => i !== idx) }))} className="absolute top-3 right-3 w-8 h-8 bg-black/40 text-white rounded-full flex items-center justify-center backdrop-blur-lg hover:bg-[#ba1a1a] transition-colors"><span className="material-symbols-outlined text-[18px]">close</span></button>
                </div>
              ))}
            </div>
          </section>
        )}
      </main>
    </div>
  );
}

function DetailItem({ label, value, readOnly }: { label: string, value: string, readOnly?: boolean }) {
  return (
    <div className={`flex items-center px-5 py-4 bg-white/60 rounded-2xl shadow-sm border border-transparent ${readOnly ? 'opacity-60' : ''}`}>
      <label className="w-1/3 text-[9px] font-black text-[#596061] uppercase tracking-widest">{label}</label>
      <input 
        type="text" 
        value={value}
        readOnly={readOnly}
        tabIndex={readOnly ? -1 : 0}
        className="w-2/3 border-none bg-transparent focus:ring-0 text-[#2D3435] font-bold text-[14px] p-0" 
      />
    </div>
  );
}

