source:
"use client";

import React, { useState, useEffect, useMemo } from 'react';
import { GoogleMap, Marker, Autocomplete } from '@react-google-maps/api';
import { motion, AnimatePresence } from 'framer-motion';
import { useLocation } from '@/components/providers/LocationProvider';
import { db } from '@/lib/firebase/clientApp';
import { collection, onSnapshot, query, where } from 'firebase/firestore';
import { CITY_COORDINATES, DEFAULT_COORDINATES } from '@/lib/constants/locations';
import { useRouter } from 'next/navigation';
import { OverlayView } from '@react-google-maps/api';
import useSupercluster from 'use-supercluster';

interface Venue {
  id: string;
  name: string;
  nameKo?: string;
  category: string;
  coordinates: { latitude: number; longitude: number; };
  address: string;
  city: string;
  status: string;
  imageUrl?: string;
}

const mapContainerStyle = { width: '100%', height: '100dvh' };
const CIRCLE_PATH = 0;

const getKakaoMapUrl = (v: Venue) => `https://map.kakao.com/link/map/${v.nameKo || v.name},${v.coordinates.latitude},${v.coordinates.longitude}`;
const getNaverMapUrl = (v: Venue) => `https://map.naver.com/v5/search/${v.nameKo || v.name}?c=${v.coordinates.longitude},${v.coordinates.latitude},15,0,0,0,dh`;
const getGoogleMapUrl = (v: Venue) => `https://www.google.com/maps/search/?api=1&query=${v.coordinates.latitude},${v.coordinates.longitude}`;

export default function MapComponent({ 
  onRegisterOpen, 
  onEdit, 
  onDelete, 
  isLoaded 
}: { 
  onRegisterOpen: () => void; 
  onEdit: (venue: Venue, mode?: 'edit' | 'geo') => void;
  onDelete: (id: string) => void;
  isLoaded: boolean; 
}) {
  const { location } = useLocation();
  const [map, setMap] = useState<google.maps.Map | null>(null);
  const [autocomplete, setAutocomplete] = useState<google.maps.places.Autocomplete | null>(null);
  const [bounds, setBounds] = useState<google.maps.LatLngBounds | null>(null);
  const [mapBounds, setMapBounds] = useState<[number, number, number, number] | null>(null);
  const [venues, setVenues] = useState<Venue[]>([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedCategories, setSelectedCategories] = useState<string[]>(['All']);
  const [isExpanded, setIsExpanded] = useState(false);
  const [selectedVenueId, setSelectedVenueId] = useState<string | null>(null);
  const [activeMenuId, setActiveMenuId] = useState<string | null>(null);
  const [userLocation, setUserLocation] = useState<{ lat: number; lng: number } | null>(null);
  const [zoom, setZoom] = useState(14);
  const [center, setCenter] = useState<{ lat: number; lng: number } | null>(null);
  const router = useRouter();

  const categories = ['All', 'Club', 'Stay', 'Shop', 'Studio', 'Academy', 'Beauty', 'Cafe', 'Eats', 'Other'];

  useEffect(() => {
    if (!map) return;
    // Sync map center/zoom when location from context changes via map instance
    const coords = (location?.city && location.city !== 'ALL' && CITY_COORDINATES[location.city.toUpperCase()])
      ? CITY_COORDINATES[location.city.toUpperCase()]
      : (CITY_COORDINATES[location.country.toUpperCase()] || DEFAULT_COORDINATES);
    
    map.panTo({ lat: coords.lat, lng: coords.lng });
    map.setZoom(coords.zoom);
    
    // Also update state for filtering
    setCenter({ lat: coords.lat, lng: coords.lng });
    setZoom(coords.zoom);
  }, [location, map]);

  useEffect(() => {
    // Fetch all active venues globally to allow seamless discovery across bounds
    const q = query(collection(db, "venues"), where("status", "==", "active"));
    return onSnapshot(q, (snapshot) => {
      const docs = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Venue));
      setVenues(docs.filter(v => v.coordinates?.latitude && v.coordinates?.longitude));
    });
  }, []);

  const calculateDistance = (lat1: number, lon1: number, lat2: number, lon2: number) => {
    if (isNaN(lat1) || isNaN(lon1) || isNaN(lat2) || isNaN(lon2)) return 999999;
    const R = 6371; // km
    const dLat = (lat2 - lat1) * Math.PI / 180;
    const dLon = (lon2 - lon1) * Math.PI / 180;
    const a = Math.sin(dLat / 2) * Math.sin(dLat / 2) +
              Math.cos(lat1 * Math.PI / 180) * Math.cos(lat2 * Math.PI / 180) *
              Math.sin(dLon / 2) * Math.sin(dLon / 2);
    const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
    const dist = R * c;
    return isNaN(dist) ? 999999 : dist;
  };

  const isWithinBounds = (lat: number, lng: number) => {
    if (!map) return true;
    const currentBounds = map.getBounds();
    if (!currentBounds) return true;
    return currentBounds.contains({ lat, lng });
  };

  const filteredVenues = useMemo(() => {
    let result = venues;

    // 1. Filter by categories
    if (!selectedCategories.includes('All')) {
      result = result.filter(v => selectedCategories.includes(v.category));
    }

    // 2. Conditional filter: Bounds (only when NO search term)
    if (!searchTerm && map) {
      result = result.filter(v => isWithinBounds(v.coordinates.latitude, v.coordinates.longitude));
    }

    // 3. Filter by search term (Global)
    if (searchTerm) {
      const lowerSearch = searchTerm.toLowerCase();
      result = result.filter(v => 
        v.name.toLowerCase().includes(lowerSearch) || 
        (v.nameKo && v.nameKo.toLowerCase().includes(lowerSearch)) ||
        v.address.toLowerCase().includes(lowerSearch)
      );
    }

    // 4. Sort by distance from current center state
    if (center) {
      result = [...result].sort((a, b) => {
        const distA = calculateDistance(center.lat, center.lng, a.coordinates.latitude, a.coordinates.longitude);
        const distB = calculateDistance(center.lat, center.lng, b.coordinates.latitude, b.coordinates.longitude);
        return distA - distB;
      });
    }

    return result;
  }, [venues, selectedCategories, searchTerm, center, bounds]); // bounds dependency for re-filtering on move

  const points = useMemo(() => {
    return filteredVenues.map(venue => ({
      type: "Feature" as const,
      properties: { cluster: false, venueId: venue.id, venue },
      geometry: {
        type: "Point" as const,
        coordinates: [
          venue.coordinates.longitude,
          venue.coordinates.latitude
        ]
      }
    }));
  }, [filteredVenues]);

  const { clusters, supercluster } = useSupercluster({
    points,
    bounds: mapBounds ? mapBounds : undefined,
    zoom,
    options: { radius: 60, maxZoom: 15 }
  });

  useEffect(() => {
    if (!isExpanded) {
      setSearchTerm('');
    }
  }, [isExpanded]);

  const toggleCategory = (cat: string) => {
    if (cat === 'All') {
      setSelectedCategories(['All']);
    } else {
      setSelectedCategories(prev => {
        const withoutAll = prev.filter(c => c !== 'All');
        if (withoutAll.includes(cat)) {
          const updated = withoutAll.filter(c => c !== cat);
          return updated.length === 0 ? ['All'] : updated;
        } else {
          return [...withoutAll, cat];
        }
      });
    }
  };

  const sortedFilteredVenues = useMemo(() => {
    if (!selectedVenueId) return filteredVenues;
    const selectedIdx = filteredVenues.findIndex(v => v.id === selectedVenueId);
    if (selectedIdx === -1) return filteredVenues;
    
    const result = [...filteredVenues];
    const [selected] = result.splice(selectedIdx, 1);
    return [selected, ...result];
  }, [filteredVenues, selectedVenueId]);

  const labelScale = useMemo(() => {
    if (zoom <= 14) return 1;
    return 1 + (zoom - 14) * 0.15;
  }, [zoom]);

  const handleEnterKey = () => {
    if (!searchTerm) return;
    const service = new google.maps.places.AutocompleteService();
    service.getPlacePredictions({ input: searchTerm }, (predictions) => {
      if (predictions && predictions.length > 0) {
        const ds = new google.maps.places.PlacesService(document.createElement('div'));
        ds.getDetails({ placeId: predictions[0].place_id }, (place) => {
          if (place?.geometry?.location) {
            map?.panTo(place.geometry.location);
            map?.setZoom(16);
            setSearchTerm(place.formatted_address || place.name || '');
          }
        });
      }
    });
  };

  const handleMarkerClick = (v: Venue) => {
    router.push(`/venues/${v.id}`);
  };

  const handleListItemClick = (v: Venue) => {
    router.push(`/venues/${v.id}`);
  };

  const findMyLocation = () => {
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (position) => {
          const pos = { lat: position.coords.latitude, lng: position.coords.longitude };
          setUserLocation(pos);
          map?.panTo(pos);
          map?.setZoom(15);
        },
        () => {
          alert("Could not find your location.");
        }
      );
    }
  };

  const initialMapConfig = useMemo(() => {
    const coords = (location?.city && location.city !== 'ALL' && CITY_COORDINATES[location.city.toUpperCase()])
      ? CITY_COORDINATES[location.city.toUpperCase()]
      : (CITY_COORDINATES[location.country.toUpperCase()] || DEFAULT_COORDINATES);
    return { lat: coords.lat, lng: coords.lng, zoom: coords.zoom };
  }, []); // Only once at mount

  const categoryIcons: Record<string, string> = {
    'All': 'apps',
    'Club': 'local_bar',
    'Stay': 'bed',
    'Shop': 'shopping_bag',
    'Studio': 'theater_comedy',
    'Academy': 'school',
    'Beauty': 'face_5',
    'Cafe': 'coffee',
    'Eats': 'restaurant',
    'Other': 'more_horiz'
  };

  return (
    <div className="relative w-full h-screen overflow-hidden bg-surface-container select-none font-body">
      {/* Layer 0: Map */}
      <div className="absolute inset-0 z-0">
        {isLoaded ? (
          <GoogleMap
            mapContainerStyle={mapContainerStyle}
            center={initialMapConfig}
            zoom={initialMapConfig.zoom}
            onLoad={(m) => {
              setMap(m);
              const c = m.getCenter();
              if (c) setCenter({ lat: c.lat(), lng: c.lng() });
              setZoom(m.getZoom() || 14);
              const b = m.getBounds();
              setBounds(b || null);
              if (b) {
                setMapBounds([
                  b.getSouthWest().lng(),
                  b.getSouthWest().lat(),
                  b.getNorthEast().lng(),
                  b.getNorthEast().lat()
                ]);
              }
            }}
            onBoundsChanged={() => {
              if (map) {
                const c = map.getCenter();
                const z = map.getZoom();
                if (c && (c.lat() !== center?.lat || c.lng() !== center?.lng)) {
                  setCenter({ lat: c.lat(), lng: c.lng() });
                }
                if (z !== undefined && z !== zoom) {
                  setZoom(z);
                }
                const b = map.getBounds();
                setBounds(b || null);
                if (b) {
                  setMapBounds([
                    b.getSouthWest().lng(),
                    b.getSouthWest().lat(),
                    b.getNorthEast().lng(),
                    b.getNorthEast().lat()
                  ]);
                }
              }
            }}
            onClick={() => {
              setSelectedVenueId(null);
              setIsExpanded(false);
            }}
            options={{ 
              disableDefaultUI: true, 
              mapId: "425069951fef97d91810ab94", 
              gestureHandling: 'greedy',
              styles: [
                {
                  featureType: "all",
                  elementType: "labels",
                  stylers: [{ visibility: "off" }]
                }
              ]
            }}
          >
            {clusters.map((cluster) => {
              const [longitude, latitude] = cluster.geometry.coordinates;
              const { cluster: isCluster, point_count: pointCount, venue } = cluster.properties as any;

              if (isCluster) {
                const size = Math.max(36, 24 + (pointCount / points.length) * 40);
                return (
                  <OverlayView
                    key={`cluster-${cluster.id}`}
                    position={{ lat: latitude, lng: longitude }}
                    mapPaneName={OverlayView.OVERLAY_MOUSE_TARGET}
                  >
                    <div
                      className="flex items-center justify-center bg-slate-800 text-white font-bold rounded-full shadow-[0_8px_16px_rgba(0,0,0,0.3)] cursor-pointer hover:scale-110 active:scale-95 transition-transform"
                      style={{
                        width: `${size}px`,
                        height: `${size}px`,
                        transform: 'translate(-50%, -50%)',
                        fontSize: `${Math.max(12, 10 + (pointCount / points.length) * 10)}px`
                      }}
                      onClick={(e) => {
                         e.stopPropagation();
                         const expansionZoom = Math.min(
                            supercluster?.getClusterExpansionZoom(cluster.id) || 16, 
                            20
                         );
                         map?.panTo({ lat: latitude, lng: longitude });
                         map?.setZoom(expansionZoom);
                      }}
                    >
                      {pointCount}
                    </div>
                  </OverlayView>
                );
              }

              const v = venue as Venue;
              return (
                <OverlayView
                  key={v.id}
                  position={{ lat: v.coordinates.latitude, lng: v.coordinates.longitude }}
                  mapPaneName={OverlayView.OVERLAY_MOUSE_TARGET}
                >
                  <div 
                    className="flex flex-col items-center cursor-pointer pointer-events-auto group"
                    onClick={(e) => {
                      e.stopPropagation();
                      handleMarkerClick(v);
                      setIsExpanded(true);
                    }}
                    style={{ 
                      transform: `translate(-50%, -50%) scale(${labelScale})`,
                      transition: 'transform 0.1s ease-out'
                    }}
                  >
                    {selectedVenueId === v.id ? (
                      <div className="flex flex-col items-center">
                        <div className="relative flex items-center justify-center mb-1">
                          <div className="absolute w-4 h-4 bg-primary/30 rounded-full animate-halo-pulse"></div>
                          <div className="w-5 h-5 bg-primary flex items-center justify-center rounded-full border-2 border-white shadow-xl">
                            <div className="w-1.5 h-1.5 bg-white rounded-full"></div>
                          </div>
                        </div>
                        <span className="text-[11px] font-black uppercase tracking-tight map-label text-primary bg-white/40 px-2 py-0.5 rounded-full backdrop-blur-sm whitespace-nowrap">
                          {v.nameKo || v.name}
                        </span>
                      </div>
                    ) : (
                      <div className="flex flex-col items-center">
                        <div className="w-3 h-3 bg-white border-[3px] border-primary rounded-full shadow-sm mb-1 group-hover:scale-125 transition-transform"></div>
                        {zoom >= 13 && (
                          <span className="text-[10px] font-extrabold uppercase tracking-tight map-label text-slate-800 whitespace-nowrap opacity-80 group-hover:opacity-100 transition-opacity">
                            {v.nameKo || v.name}
                          </span>
                        )}
                      </div>
                    )}
                  </div>
                </OverlayView>
              );
            })}

            {userLocation && (
              <OverlayView
                position={userLocation}
                mapPaneName={OverlayView.OVERLAY_MOUSE_TARGET}
              >
                <div className="user-pos-marker" style={{ transform: 'translate(-50%, -50%)' }} />
              </OverlayView>
            )}
          </GoogleMap>
        ) : (
          <div className="w-full h-full flex items-center justify-center bg-surface-container">
            <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary"></div>
          </div>
        )}
      </div>

      {/* Layer 1: Floating Filter Icons (Top) */}
      <div className="absolute top-36 left-0 right-0 z-20 flex gap-2.5 overflow-x-auto px-6 no-scrollbar pointer-events-auto py-2">
        {categories.map((cat) => (
          <button
            key={cat}
            onClick={() => toggleCategory(cat)}
            className={`flex items-center gap-1.5 px-3.5 py-1.5 backdrop-blur-md rounded-full text-[11px] font-black uppercase tracking-tight shadow-[0_4px_12px_rgba(0,0,0,0.12)] border-0 transition-all whitespace-nowrap active:scale-95 ${
              selectedCategories.includes(cat)
              ? 'bg-primary text-white shadow-primary/20 scale-105'
              : 'bg-white/90 text-on-surface hover:bg-white'
            }`}
          >
            <span className="material-symbols-outlined !text-[18px] leading-none" style={{ fontVariationSettings: "'FILL' 1" }}>
              {categoryIcons[cat]}
            </span>
            <span className="mt-[1px]">{cat}</span>
          </button>
        ))}
      </div>

      {/* Layer 3: Search & Venue Area (Kinetic Expansion) */}
      <div className="absolute bottom-6 left-1/2 -translate-x-1/2 w-[calc(100%-48px)] max-w-sm z-30 pointer-events-auto">
        
        {/* Floatable Buttons (Hide when expanded) */}
        <AnimatePresence>
          {!isExpanded && (
            <motion.div 
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, y: 10 }}
              className="absolute -top-16 left-0 right-0 flex justify-between pointer-events-none"
            >
              {/* Find Me (Left) */}
              <button 
                onClick={(e) => { e.stopPropagation(); findMyLocation(); }}
                className="pointer-events-auto w-12 h-12 bg-white shadow-2xl rounded-xl flex items-center justify-center text-primary hover:bg-slate-50 active:scale-95 transition-all border border-white/40"
              >
                <div className="flex flex-col items-center leading-none">
                  <span className="text-[8px] font-bold uppercase">Find</span>
                  <span className="text-[12px] font-black uppercase">ME</span>
                </div>
              </button>

              {/* Venue ADD (Right) */}
              <button 
                onClick={(e) => { e.stopPropagation(); onRegisterOpen(); }}
                className="pointer-events-auto w-12 h-12 bg-white backdrop-blur-md rounded-xl shadow-xl flex items-center justify-center text-primary hover:bg-slate-50 active:scale-95 transition-all border border-white/50"
              >
                <div className="flex flex-col items-center leading-none">
                  <span className="text-[8px] font-bold uppercase">venue</span>
                  <span className="text-[12px] font-black uppercase">ADD</span>
                </div>
              </button>
            </motion.div>
          )}
        </AnimatePresence>

        <motion.div 
          animate={{ height: isExpanded ? 'auto' : '56px' }}
          className="bg-white/95 backdrop-blur-3xl rounded-xl shadow-[0_24px_48px_rgba(0,0,0,0.12)] flex flex-col border border-white/60 overflow-hidden transition-all duration-300"
          onClick={() => !isExpanded && setIsExpanded(true)}
        >
          {/* Top Row / Summary Bar */}
          <div className={`px-6 flex items-center justify-between py-3 cursor-pointer ${isExpanded ? 'border-b border-slate-100' : ''}`}>
            <div className="flex items-center">
              <div 
                onClick={(e) => {
                  e.stopPropagation();
                  setIsExpanded(!isExpanded);
                }}
                className="w-8 h-8 rounded-full bg-slate-100 border border-slate-200 flex items-center justify-center transition-colors hover:bg-slate-200"
              >
                <span className="material-symbols-outlined text-primary text-xl">
                  {isExpanded ? 'expand_more' : 'expand_less'}
                </span>
              </div>
              
              {isExpanded ? (
                <div className="flex items-center ml-3 flex-grow">
                  <input 
                    type="text"
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    placeholder="Search venue.."
                    className="bg-transparent border-none p-0 focus:ring-0 text-sm font-medium text-slate-800 placeholder:text-slate-400 w-full outline-none"
                  />
                </div>
              ) : (
                <span className="text-sm text-slate-800 font-bold ml-3 tracking-wide">
                  {filteredVenues.length} IN VIEW
                </span>
              )}
            </div>
            
            <div className="flex items-center gap-4">
              <div className="h-5 w-[1px] bg-slate-200"></div>
              <button 
                onClick={(e) => {
                  e.stopPropagation();
                  setIsExpanded(true);
                }}
                className="flex items-center justify-center text-primary active:scale-90 transition-transform"
              >
                <span className="material-symbols-outlined text-[24px]">search</span>
              </button>
            </div>
          </div>

          {/* Expanded List area */}
          <AnimatePresence>
            {isExpanded && (
              <motion.div 
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                exit={{ opacity: 0 }}
                className="flex items-center overflow-x-auto px-6 gap-4 no-scrollbar snap-x snap-mandatory py-4 h-[130px]"
              >
                {sortedFilteredVenues.length > 0 ? (
                  sortedFilteredVenues.map((v) => (
                    <div 
                      key={v.id}
                      onClick={() => handleListItemClick(v)}
                      className={`flex-none w-[calc(100%-24px)] bg-white rounded-lg p-2 shadow-sm border flex gap-3 relative snap-center transition-all ${
                        selectedVenueId === v.id ? 'border-primary ring-1 ring-primary' : 'border-slate-50'
                      }`}
                    >
                      <div className="w-16 h-16 rounded bg-slate-100 flex-none overflow-hidden">
                        {v.imageUrl ? (
                          <img src={v.imageUrl} className="w-full h-full object-cover" alt={v.name} />
                        ) : (
                          <div className="w-full h-full flex items-center justify-center text-slate-300">
                            <span className="material-symbols-outlined text-xl">image</span>
                          </div>
                        )}
                      </div>
                      <div className="flex flex-col min-w-0 pr-8 justify-center">
                        <span className="text-[10px] font-bold text-primary bg-primary/10 w-fit px-1.5 py-0.5 rounded mb-1 uppercase">
                          {v.category}
                        </span>
                        <h3 className="text-[17px] font-bold text-on-background truncate leading-tight">
                          {v.nameKo || v.name}
                        </h3>
                        <p className="text-[11px] text-slate-400 truncate mt-0.5 font-medium">
                          no social today
                        </p>
                      </div>
                      
                      {/* More Vert Menu */}
                      <button 
                        onClick={(e) => {
                          e.stopPropagation();
                          setActiveMenuId(activeMenuId === v.id ? null : v.id);
                        }}
                        className="absolute top-2 right-2 text-slate-400 hover:text-slate-600"
                      >
                        <span className="material-symbols-outlined text-[18px]">more_vert</span>
                      </button>

                      <AnimatePresence>
                        {activeMenuId === v.id && (
                          <motion.div 
                            initial={{ opacity: 0, y: 10 }}
                            animate={{ opacity: 1, y: 0 }}
                            exit={{ opacity: 0, y: 10 }}
                            className="absolute right-2 bottom-full mb-2 bg-white rounded-xl shadow-[0_-10px_40px_-15px_rgba(0,0,0,0.3)] border border-slate-100 min-w-[140px] z-50 overflow-hidden origin-bottom-right"
                          >
                            <div className="flex items-center justify-between px-2 py-2 border-b border-slate-50 gap-1 bg-slate-50/50">
                              <a href={getKakaoMapUrl(v)} target="_blank" rel="noreferrer" className="flex-1 text-center bg-[#FEE500] text-black text-[9px] font-black py-1.5 rounded shadow-sm hover:brightness-95 transition-all" onClick={e => e.stopPropagation()}>
                                K
                              </a>
                              <a href={getNaverMapUrl(v)} target="_blank" rel="noreferrer" className="flex-1 text-center bg-[#03C75A] text-white text-[9px] font-black py-1.5 rounded shadow-sm hover:brightness-95 transition-all" onClick={e => e.stopPropagation()}>
                                N
                              </a>
                              <a href={getGoogleMapUrl(v)} target="_blank" rel="noreferrer" className="flex-1 text-center bg-white border border-slate-200 text-[#4285F4] text-[9px] font-black py-1.5 rounded shadow-sm hover:bg-slate-50 transition-all" onClick={e => e.stopPropagation()}>
                                G
                              </a>
                            </div>
                            <button 
                              onClick={(e) => {
                                e.stopPropagation();
                                onEdit(v, 'geo');
                                setActiveMenuId(null);
                              }}
                              className="w-full px-4 py-2.5 text-left text-xs font-bold text-primary hover:bg-primary/5 border-b border-slate-50 flex items-center justify-between transition-colors"
                            >
                              <span>Geo tuning</span>
                              <span className="material-symbols-outlined text-[14px]">my_location</span>
                            </button>
                            <button 
                              onClick={(e) => {
                                e.stopPropagation();
                                onEdit(v);
                                setActiveMenuId(null);
                              }}
                              className="w-full px-4 py-2 text-left text-xs font-bold text-slate-700 hover:bg-slate-50 border-b border-slate-50 transition-colors"
                            >
                              Edit
                            </button>
                            <button 
                              onClick={(e) => {
                                e.stopPropagation();
                                onDelete(v.id);
                                setActiveMenuId(null);
                              }}
                              className="w-full px-4 py-2 text-left text-xs font-bold text-error hover:bg-red-50 transition-colors"
                            >
                              Delete
                            </button>
                          </motion.div>
                        )}
                      </AnimatePresence>
                    </div>
                  ))
                ) : (
                  <div className="flex items-center justify-center w-full h-full text-slate-400 text-xs font-medium">
                    No venues in this area
                  </div>
                )}
                {/* Visual nudge for next card */}
                <div className="flex-none w-10 h-1" /> 
              </motion.div>
            )}
          </AnimatePresence>
        </motion.div>
      </div>
    </div>
  );
}

'use client';

import React, { useState, useEffect } from 'react';
import { venueService } from '@/lib/firebase/venueService';
import { Venue, VenueType } from '@/types/venue';

interface VenueFormProps {
  isOpen: boolean;
  onClose: () => void;
  initialData?: Venue | null;
}

const CATEGORY_OPTIONS = [
  { id: 'Shop', icon: 'shopping_bag', label: 'Shop' },
  { id: 'Studio', icon: 'palette', label: 'Studio' },
  { id: 'Stay', icon: 'bed', label: 'Stay' },
  { id: 'Academy', icon: 'school', label: 'Academy' },
  { id: 'Club', icon: 'groups', label: 'Club' },
  { id: 'Cafe', icon: 'coffee', label: 'Cafe' },
  { id: 'Eats', icon: 'restaurant', label: 'Eats' },
  { id: 'Beauty', icon: 'content_cut', label: 'Beauty' },
];

export default function VenueForm({ isOpen, onClose, initialData }: VenueFormProps) {
  const [formData, setFormData] = useState<Omit<Venue, 'id' | 'createdAt'>>({
    name: '',
    nameKo: '',
    types: ['Club'],
    category: 'Club',
    address: '',
    region: 'Seoul',
    city: 'Seoul',
    district: '',
    status: 'active',
    coordinates: { latitude: 37.5665, longitude: 126.9780 },
  });

  const [isSubmitting, setIsSubmitting] = useState(false);

  useEffect(() => {
    if (initialData) {
      setFormData({
        name: initialData.name,
        nameKo: initialData.nameKo || '',
        types: initialData.types || ['Club'],
        category: initialData.category,
        address: initialData.address,
        region: initialData.region,
        city: initialData.city,
        district: initialData.district,
        status: initialData.status,
        coordinates: initialData.coordinates,
      });
    }
  }, [initialData, isOpen]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);
    try {
      if (initialData?.id) {
        await venueService.updateVenue(initialData.id, formData);
      } else {
        await venueService.addVenue(formData);
      }
      onClose();
    } catch (error) {
      console.error('Failed to save venue:', error);
      alert('Failed to save venue. Please check your connection and permissions.');
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleDelete = async () => {
    if (!initialData?.id || !confirm('Are you sure you want to delete this venue?')) return;
    try {
      await venueService.deleteVenue(initialData.id);
      onClose();
    } catch (error) {
      console.error('Failed to delete venue:', error);
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[110] bg-background font-body text-on-background overflow-y-auto animate-slide-up no-scrollbar">
      {/* Header (TopAppBar) */}
      <header className="fixed top-0 left-0 w-full bg-surface border-b border-outline-variant/30 h-16 px-4 flex justify-between items-center z-[120]">
        <div className="flex items-center gap-4">
          <button 
            onClick={onClose}
            className="p-2 hover:bg-surface-container rounded-full transition-colors flex items-center justify-center"
          >
            <span className="material-symbols-outlined text-on-surface-variant">arrow_back</span>
          </button>
          <h1 className="font-headline text-base font-bold text-on-surface">
            {initialData ? 'Edit Entry' : 'Manage Entry'}
          </h1>
        </div>
        <div className="flex items-center gap-1">
          <div className="text-[10px] font-extrabold text-on-surface-variant tracking-tighter uppercase mr-2 hidden md:block">World of Group</div>
          {initialData && (
            <button 
              onClick={handleDelete}
              className="p-2 hover:bg-error-container/10 rounded-full transition-colors flex items-center justify-center group"
            >
              <span className="material-symbols-outlined text-on-surface-variant group-hover:text-error">delete</span>
            </button>
          )}
        </div>
      </header>

      <main className="max-w-3xl mx-auto px-6 pt-24 pb-12 md:pt-32 md:pb-20">
        <header className="mb-12">
          <h2 className="font-headline text-3xl md:text-4xl font-extrabold text-on-surface tracking-tight mb-3">
            {initialData ? 'Update your space.' : 'Configure your space.'}
          </h2>
          <p className="text-on-surface-variant text-base leading-relaxed">Keep your venue details up to date for the local group.</p>
        </header>

        <form onSubmit={handleSubmit} className="space-y-16">
          {/* 1. Venue Name */}
          <section>
            <div className="flex items-center gap-2 mb-6">
              <span className="material-symbols-outlined text-primary">edit_square</span>
              <h3 className="font-headline text-xl font-bold text-on-surface">Venue Name</h3>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-2">
                <label className="block text-xs font-bold text-on-surface-variant uppercase tracking-widest ml-1" htmlFor="venue-name-en">Venue Name (English) *</label>
                <input 
                  className="w-full px-4 py-4 bg-surface-container-lowest border-none ring-1 ring-outline-variant focus:ring-2 focus:ring-primary rounded-xl transition-all font-body text-on-surface" 
                  id="venue-name-en" 
                  placeholder="e.g. Blue Coffee Roasters" 
                  required 
                  type="text" 
                  value={formData.name}
                  onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                />
              </div>
              <div className="space-y-2">
                <label className="block text-xs font-bold text-on-surface-variant uppercase tracking-widest ml-1" htmlFor="venue-name-ko">Venue Name (Korean) <span className="normal-case opacity-70">(If applicable)</span></label>
                <input 
                  className="w-full px-4 py-4 bg-surface-container-lowest border-none ring-1 ring-outline-variant focus:ring-2 focus:ring-primary rounded-xl transition-all font-body text-on-surface" 
                  id="venue-name-ko" 
                  placeholder="e.g. 탱고라이프" 
                  type="text" 
                  value={formData.nameKo}
                  onChange={(e) => setFormData({ ...formData, nameKo: e.target.value })}
                />
              </div>
            </div>
          </section>

          {/* 2. Venue Category */}
          <section>
            <div className="flex items-center gap-2 mb-6">
              <span className="material-symbols-outlined text-primary">category</span>
              <h3 className="font-headline text-xl font-bold text-on-surface">Venue Category *</h3>
            </div>
            <div className="bento-grid">
              {CATEGORY_OPTIONS.map((cat) => (
                <label key={cat.id} className="group relative cursor-pointer">
                  <input 
                    className="peer sr-only" 
                    name="category" 
                    type="radio" 
                    checked={formData.category === cat.id}
                    onChange={() => setFormData({ ...formData, category: cat.id as VenueType })}
                  />
                  <div className="flex flex-col items-center justify-center p-4 aspect-square bg-surface-container-low rounded-xl border-2 border-transparent transition-all group-hover:bg-surface-container peer-checked:border-primary peer-checked:bg-primary-container/30">
                    <span className="material-symbols-outlined text-on-surface-variant peer-checked:text-primary mb-2">{cat.icon}</span>
                    <span className="font-label text-xs font-semibold text-on-surface-variant group-hover:text-on-surface">{cat.label}</span>
                  </div>
                </label>
              ))}
            </div>
          </section>

          {/* 3. Owner/Operator */}
          <section>
            <div className="flex items-center gap-2 mb-6">
              <span className="material-symbols-outlined text-primary">person_pin</span>
              <h3 className="font-headline text-xl font-bold text-on-surface">Owner / Operator *</h3>
            </div>
              <div className="flex items-center gap-3">
                <div className="w-8 h-8 rounded-full bg-primary-container flex items-center justify-center overflow-hidden">
                  <span className="material-symbols-outlined text-primary text-xl">person</span>
                </div>
                <span className="font-body text-sm font-semibold text-on-surface">Admin Mode</span>
              </div>
          </section>

          {/* 4. Global Details (Timezone Only) */}
          <section>
            <div className="flex items-center gap-2 mb-6">
              <span className="material-symbols-outlined text-primary">public</span>
              <h3 className="font-headline text-xl font-bold text-on-surface">Global Details</h3>
            </div>
            <div className="grid grid-cols-1 gap-6">
              <div className="space-y-2">
                <label className="block text-xs font-bold text-on-surface-variant uppercase tracking-widest ml-1" htmlFor="timezone">Venue Timezone</label>
                <div className="flex items-center gap-3 w-full px-4 py-4 bg-surface-container-low/50 border-none ring-1 ring-outline-variant/30 rounded-xl font-body text-on-surface-variant">
                  <span className="material-symbols-outlined text-primary/70 text-lg">auto_mode</span>
                  <span className="text-sm font-medium">Auto-detected: <span className="text-on-surface font-semibold">Singapore/Beijing (UTC+08:00)</span></span>
                </div>
                <p className="text-[10px] text-on-surface-variant italic px-1">Derived automatically from your pinned map location.</p>
              </div>
            </div>
          </section>

          {/* 5. Location Details */}
          <section>
            <div className="flex items-center justify-between mb-6">
              <div className="flex items-center gap-2">
                <span className="material-symbols-outlined text-primary">location_on</span>
                <h3 className="font-headline text-xl font-bold text-on-surface">Location Details *</h3>
              </div>
              <button className="text-primary text-xs font-bold uppercase tracking-wider flex items-center gap-1 hover:underline" type="button">
                <span className="material-symbols-outlined text-sm">push_pin</span>
                Pin on map
              </button>
            </div>
            <div className="space-y-6">
              <div className="relative">
                <span className="absolute left-4 top-1/2 -translate-y-1/2 material-symbols-outlined text-outline">search</span>
                <input 
                  className="w-full pl-12 pr-4 py-4 bg-surface-container-lowest border-none ring-1 ring-outline-variant focus:ring-2 focus:ring-primary rounded-xl transition-all font-body text-on-surface" 
                  placeholder="Address or phone number" 
                  type="text" 
                  value={formData.address}
                  onChange={(e) => setFormData({ ...formData, address: e.target.value })}
                />
              </div>
              <div className="relative overflow-hidden rounded-2xl border border-outline-variant/30 h-72 md:h-80 shadow-inner">
                <img 
                  className="w-full h-full object-cover" 
                  alt="map" 
